-- Poems batch 438
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-6','就道士問周易參同契','王昌齡','唐','御定全唐诗','yuding','','[]','仙人騎白鹿，發短耳何長。時餘采菖蒲，忽見嵩之陽。',60,'御定全唐詩/json/141.json','["仙人騎白鹿，發短耳何長。時餘采菖蒲，忽見嵩之陽。", "稽首求丹經，乃出懷中方。披讀了不悟，歸來問嵇康。", "嗟餘無道骨，發我入太行。"]'),
('yuding-7','諸官遊招隱寺','王昌齡','唐','御定全唐诗','yuding','','[]','山館人已空，青蘿換風雨。自從永明世，月向龍宮吐。',96,'御定全唐詩/json/141.json','["山館人已空，青蘿換風雨。自從永明世，月向龍宮吐。", "鑿井長幽泉，白雲今如古。應真坐松柏，錫杖掛窗戶。", "口雲七十餘，能救諸有苦。回指岩樹花，如聞道場鼓。", "金色身壞滅，真如性無主。僚友同一心，清光遣誰取。"]'),
('yuding-8','宴南亭','王昌齡','唐','御定全唐诗','yuding','','[]','寒江映村林，亭上納鮮潔。楚客共閑飲，靜坐金管闋。',72,'御定全唐詩/json/141.json','["寒江映村林，亭上納鮮潔。楚客共閑飲，靜坐金管闋。", "酣竟日入山，暝來雲歸穴。城樓空杳靄，猿鳥備清切。", "物狀如絲綸，上心為予決。訪君東溪事，早晚樵路絕。"]'),
('yuding-9','何九於客舍集','王昌齡','唐','御定全唐诗','yuding','','[]','客有住桂陽，亦如巢林鳥。罍觴且終宴，功業會未了。',60,'御定全唐詩/json/141.json','["客有住桂陽，亦如巢林鳥。罍觴且終宴，功業會未了。", "山月空霽時，江明高樓曉。門前泊舟楫，行次入松筱。", "此意投贈君，滄波風嫋嫋。"]'),
('yuding-10','洛陽尉劉晏與府掾諸公茶集天宮寺岸道上人房','王昌齡','唐','御定全唐诗','yuding','','[]','良友呼我宿，月明懸天宮。道安風塵外，灑掃青林中。',72,'御定全唐詩/json/141.json','["良友呼我宿，月明懸天宮。道安風塵外，灑掃青林中。", "削去府縣理，豁然神機空。自從三湘還，始得今夕同。", "舊居太行北，遠宦滄溟東。各有四方事，白雲處處通。"]'),
('yuding-11','觀江淮名勝圖','王昌齡','唐','御定全唐诗','yuding','','[]','刻意吟雲山，尤知隱淪妙。遠公何為者，再詣臨海嶠。',132,'御定全唐詩/json/141.json','["刻意吟雲山，尤知隱淪妙。遠公何為者，再詣臨海嶠。", "而我高其風，披圖得遺照。援毫無逃境，遂展千里眺。", "淡掃荊門煙，明標赤城燒。青蔥林間嶺，隱見淮海徼。", "但指香爐頂，無聞白猿嘯。沙門既雲滅，獨往豈殊調。", "感對懷拂衣，胡寧事漁釣。安期始遺舄，千古謝榮耀。", "投跡庶可齊，滄浪有孤棹。"]'),
('yuding-12','灞上閒居','王昌齡','唐','御定全唐诗','yuding','','[]','鴻都有歸客，偃臥滋陽村。軒冕無枉顧，清川照我門。',84,'御定全唐詩/json/141.json','["鴻都有歸客，偃臥滋陽村。軒冕無枉顧，清川照我門。", "空林網夕陽，寒鳥赴荒園。廓落時得意，懷哉莫與言。", "庭前有孤鶴，欲啄常翩翻。為我銜素書，吊彼顏與原。", "二君既不朽，所以慰其魂。"]'),
('yuding-13','風涼原上作','王昌齡','唐','御定全唐诗','yuding','','[]','陰岑宿雲歸，煙霧濕松柏。風淒日初曉，下嶺望川澤。',96,'御定全唐詩/json/141.json','["陰岑宿雲歸，煙霧濕松柏。風淒日初曉，下嶺望川澤。", "遠山無晦明，秋水千里白。佳氣盤未央，聖人在凝碧。", "關門阻天下，信是帝王宅。海內方晏然，廟堂有奇策。", "時貞守全運，罷去游說客。予忝蘭台人，幽尋免貽責。"]'),
('yuding-14','裴六書堂','王昌齡','唐','御定全唐诗','yuding','','[]','閑堂閉空陰，竹林但清響。窗下長嘯客，區中無遺想。',36,'御定全唐詩/json/141.json','["閑堂閉空陰，竹林但清響。窗下長嘯客，區中無遺想。", "經綸精微言，兼濟當獨往。"]'),
('yuding-15','江上聞笛','王昌齡','唐','御定全唐诗','yuding','','[]','橫笛怨江月，扁舟何處尋。聲長楚山外，曲繞胡關深。',96,'御定全唐詩/json/141.json','["橫笛怨江月，扁舟何處尋。聲長楚山外，曲繞胡關深。", "相去萬餘裏，遙傳此夜心。寥寥浦漵寒，響盡惟幽林。", "不知誰家子，複奏邯鄲音。水客皆擁棹，空霜遂盈襟。", "羸馬望北走，遷人悲越吟。何當邊草白，旌節隴城陰。"]'),
('yuding-16','太湖秋夕','王昌齡','唐','御定全唐诗','yuding','','[]','水宿煙雨寒，洞庭霜落微。月明移舟去，夜靜魂夢歸。',36,'御定全唐詩/json/141.json','["水宿煙雨寒，洞庭霜落微。月明移舟去，夜靜魂夢歸。", "暗覺海風度，蕭蕭聞雁飛。"]'),
('yuding-17','趙十四兄見訪','王昌齡','唐','御定全唐诗','yuding','','[]','客來舒長簟，開合延清風。但有無弦琴，共君盡尊中。',72,'御定全唐詩/json/141.json','["客來舒長簟，開合延清風。但有無弦琴，共君盡尊中。", "晚來常讀易，頃者欲還嵩。世事何須道，黃精且養蒙。", "嵇康殊寡識，張翰獨知終。忽憶鱸魚鱠，扁舟往江東。"]'),
('yuding-18','過華陰','王昌齡','唐','御定全唐诗','yuding','','[]','雲起太華山，雲山互明滅。東峰始含景，了了見松雪。',84,'御定全唐詩/json/141.json','["雲起太華山，雲山互明滅。東峰始含景，了了見松雪。", "羈人感幽棲，窅映轉奇絕。欣然忘所疲，永望吟不輟。", "信宿百餘裏，出關玩新月。何意昨來心，遇物遂遷別。", "人生屢如此，何以肆愉悅。"]'),
('yuding-19','九江口作','王昌齡','唐','御定全唐诗','yuding','','[]','漭漭江勢闊，雨開潯陽秋。驛門是高岸，望盡黃蘆洲。',72,'御定全唐詩/json/141.json','["漭漭江勢闊，雨開潯陽秋。驛門是高岸，望盡黃蘆洲。", "水與五溪合，心期萬里遊。明時無棄才，謫去隨孤舟。", "鷙鳥立寒木，丈夫佩吳鉤。何當報君恩，卻系單于頭。"]'),
('yuding-20','大樑途中作','王昌齡','唐','御定全唐诗','yuding','','[]','怏怏步長道，客行渺無端。郊原欲下雪，天地棱棱寒。',48,'御定全唐詩/json/141.json','["怏怏步長道，客行渺無端。郊原欲下雪，天地棱棱寒。", "當時每酣醉，不覺行路難。今日無酒錢，悽惶向誰歎。"]'),
('yuding-21','途中作','王昌齡','唐','御定全唐诗','yuding','','[]','遊人愁歲晏，早起遵王畿。墜葉吹未曉，疏林月微微。',96,'御定全唐詩/json/141.json','["遊人愁歲晏，早起遵王畿。墜葉吹未曉，疏林月微微。", "驚禽棲不定，寒獸相因依。歎此霜露下，複聞鴻雁飛。", "渺然江南意，惜與中途違。羈旅悲壯發，別離念征衣。", "永圖豈勞止，明節期所歸。甯厭楚山曲，無人長掩扉。"]'),
('yuding-22','山行入涇州','王昌齡','唐','御定全唐诗','yuding','','[]','倦此山路長，停驂問賓禦。林巒信回惑，白日落何處。',96,'御定全唐詩/json/141.json','["倦此山路長，停驂問賓禦。林巒信回惑，白日落何處。", "徙倚望長風，滔滔引歸慮。微雨隨雲收，濛濛傍山去。", "西臨有邊邑，北走盡亭戍。涇水橫白煙，州城隱寒樹。", "所嗟異風俗，已自少情趣。豈伊懷土多，觸目忻所遇。"]'),
('yuding-23','小敷谷龍潭祠作','王昌齡','唐','御定全唐诗','yuding','','[]','崖谷噴疾流，地中有雷集。百泉勢相蕩，巨石皆卻立。',144,'御定全唐詩/json/141.json','["崖谷噴疾流，地中有雷集。百泉勢相蕩，巨石皆卻立。", "跳波沸崢嶸，深處不可挹。昏為蛟龍怒，清見雲雨入。", "靈怪崇偏祠，廢興自茲邑。沉淫頃多昧，簷宇遂不葺。", "吾聞被明典，盛德惟世及。生人載山川，血食報原隰。", "豈伊駭微險，將以循甿揖。□飛振呂梁，忠信亦我習。", "波流浸已廣，悔吝在所汲。溪水有清源，褰裳靡沾濕。"]'),
('yuding-24','段宥廳孤桐','王昌齡','唐','御定全唐诗','yuding','','[]','鳳凰所宿處，月映孤桐寒。槁葉零落盡，空柯蒼翠殘。',48,'御定全唐詩/json/141.json','["鳳凰所宿處，月映孤桐寒。槁葉零落盡，空柯蒼翠殘。", "虛心誰能見，直影非無端。響發調尚苦，清商勞一彈。"]'),
('yuding-25','琴','王昌齡','唐','御定全唐诗','yuding','','[]','孤桐秘虛鳴，樸素傳幽真。仿佛弦指外，遂見初古人。',48,'御定全唐詩/json/141.json','["孤桐秘虛鳴，樸素傳幽真。仿佛弦指外，遂見初古人。", "意遠風雪苦，時來江山春。高宴未終曲，誰能辨經綸。"]'),
('yuding-26','初日','王昌齡','唐','御定全唐诗','yuding','','[]','初日淨金閨，先照床前暖。斜光入羅幕，稍稍親絲管。',36,'御定全唐詩/json/141.json','["初日淨金閨，先照床前暖。斜光入羅幕，稍稍親絲管。", "雲發不能梳，楊花更吹滿。"]'),
('yuding-27','失題','王昌齡','唐','御定全唐诗','yuding','','[]','奸雄乃得志，遂使群心搖。赤風蕩中原，烈火無遺巢。',36,'御定全唐詩/json/141.json','["奸雄乃得志，遂使群心搖。赤風蕩中原，烈火無遺巢。", "一人計不用，萬里空蕭條。"]'),
('yuding-28','贈宇文中丞','王昌齡','唐','御定全唐诗','yuding','','[]','僕本濩落人，辱當州郡使。量力頗及早，謝歸今即已。',96,'御定全唐詩/json/141.json','["僕本濩落人，辱當州郡使。量力頗及早，謝歸今即已。", "蕭蕭若淩虛，衿帶頃消靡。車服卒然來，涔陽作遊子。", "鬱鬱寡開顏，默默獨行李。忽逢平生友，一笑方在此。", "秋清寧風日，楚思浩雲水。為語弋林者，冥冥鴻遠矣。"]'),
('yuding-29','箜篌引','王昌齡','唐','御定全唐诗','yuding','','[]','盧溪郡南夜泊舟，夜聞兩岸羌戎謳，其時月黑猿啾啾。',360,'御定全唐詩/json/141.json','["盧溪郡南夜泊舟，夜聞兩岸羌戎謳，其時月黑猿啾啾。", "微雨沾衣令人愁，有一遷客登高樓，不言不寐彈箜篌。", "彈作薊門桑葉秋，風沙颯颯青塚頭，將軍鐵驄汗血流。", "深入匈奴戰未休，黃旗一點兵馬收，亂殺胡人積如丘。", "瘡病驅來配邊州，仍披漠北羔羊裘，顏色饑枯掩面羞。", "眼眶淚滴深兩眸，思還本鄉食犛牛，欲語不得指咽喉。", "或有強壯能咿嚘，意說被他邊將讎，五世屬藩漢主留。", "碧毛氈帳河曲遊，橐駝五萬部落稠，敕賜飛鳳金兜鍪。", "為君百戰如過籌，靜掃陰山無鳥投，家藏鐵券特承優。", "黃金千斤不稱求，九族分離作楚囚，深溪寂寞弦苦幽。", "草木悲感聲颼飀，僕本東山為國憂，明光殿前論九疇。", "簏讀兵書盡冥搜，為君掌上施權謀，洞曉山川無與儔。", "紫宸詔發遠懷柔，搖筆飛霜如奪鉤，鬼神不得知其由。", "憐愛蒼生比蚍蜉，朔河屯兵須漸抽，盡遣降來拜禦溝。", "便令海內休戈矛，何用班超定遠侯，史臣書之得已不。"]'),
('yuding-30','烏棲曲','王昌齡','唐','御定全唐诗','yuding','','[]','白馬逐朱車，黃昏入狹邪。柳樹烏爭宿，',18,'御定全唐詩/json/141.json','["白馬逐朱車，黃昏入狹邪。柳樹烏爭宿，"]'),
('yuding-31','城傍曲','王昌齡','唐','御定全唐诗','yuding','','[]','秋風鳴桑條，草白狐兔驕。邯鄲飲來酒未消，',20,'御定全唐詩/json/141.json','["秋風鳴桑條，草白狐兔驕。邯鄲飲來酒未消，"]'),
('yuding-32','行路難','王昌齡','唐','御定全唐诗','yuding','','[]','雙絲作綆系銀瓶，百尺寒泉轆轤上。懸絲一絕不可望，',88,'御定全唐詩/json/141.json','["雙絲作綆系銀瓶，百尺寒泉轆轤上。懸絲一絕不可望，", "宴罷調箏奏離鶴，回嬌轉盼泣君前。君不見，眼前事，", "但願莫忘前者言，銼骨黃塵亦無愧。行路難，勸君酒，", "一聞漢主思故劍，使妾長嗟萬古魂。"]'),
('yuding-33','奉贈張荊州','王昌齡','唐','御定全唐诗','yuding','','[]','祝融之峰紫雲銜，翠如何其雪嶄岩。邑西有路緣石壁，',40,'御定全唐詩/json/141.json','["祝融之峰紫雲銜，翠如何其雪嶄岩。邑西有路緣石壁，", "王君飛舄仍未去，蘇耽宅中意遙緘。"]'),
('yuding-0','駕出長安','王昌齡','唐','御定全唐诗','yuding','','[]','聖德超千古，皇風扇九圍。天回萬象出，駕動六龍飛。',48,'御定全唐詩/json/142.json','["聖德超千古，皇風扇九圍。天回萬象出，駕動六龍飛。", "淑氣來黃道，祥雲覆紫微。太平多扈從，文物有光輝。"]'),
('yuding-1','駕幸河東','王昌齡','唐','御定全唐诗','yuding','','[]','晉水千廬合，汾橋萬國從。開唐天業盛，入沛聖恩濃。',48,'御定全唐詩/json/142.json','["晉水千廬合，汾橋萬國從。開唐天業盛，入沛聖恩濃。", "下輦回三象，題碑任六龍。睿明懸日月，千歲此時逢。"]'),
('yuding-2','胡笳曲','王昌齡','唐','御定全唐诗','yuding','','[]','城南虜已合，一夜幾重圍。自有金笳引，能沾出塞衣。',48,'御定全唐詩/json/142.json','["城南虜已合，一夜幾重圍。自有金笳引，能沾出塞衣。", "聽臨關月苦，清入海風微。三奏高樓曉，胡人掩涕歸。"]'),
('yuding-3','潞府客亭寄崔鳳童','王昌齡','唐','御定全唐诗','yuding','','[]','蕭條郡城閉，旅館空寒煙。秋月對愁客，山鐘搖暮天。',48,'御定全唐詩/json/142.json','["蕭條郡城閉，旅館空寒煙。秋月對愁客，山鐘搖暮天。", "新知偶相訪，鬥酒情依然。一宿阻長會，清風徒滿川。"]'),
('yuding-4','和振上人秋夜懷士會','王昌齡','唐','御定全唐诗','yuding','','[]','白露傷草木，山風吹夜寒。遙林夢親友，高興發雲端。',48,'御定全唐詩/json/142.json','["白露傷草木，山風吹夜寒。遙林夢親友，高興發雲端。", "郭外秋聲急，城邊月色殘。瑤琴多遠思，更為客中彈。"]'),
('yuding-5','送李擢游江東','王昌齡','唐','御定全唐诗','yuding','','[]','清洛日夜漲，微風引孤舟。離腸便千里，遠夢生江樓。',48,'御定全唐詩/json/142.json','["清洛日夜漲，微風引孤舟。離腸便千里，遠夢生江樓。", "楚國橙橘暗，吳門煙雨愁。東南具今古，歸望山雲秋。"]'),
('yuding-6','沙苑南渡頭','王昌齡','唐','御定全唐诗','yuding','','[]','秋霧連雲白，歸心浦漵懸。津人空守纜，村館複臨川。',48,'御定全唐詩/json/142.json','["秋霧連雲白，歸心浦漵懸。津人空守纜，村館複臨川。", "篷隔蒼茫雨，波連演漾田。孤舟未得濟，入夢在何年。"]'),
('yuding-7','客廣陵','王昌齡','唐','御定全唐诗','yuding','','[]','樓頭廣陵近，九月在南徐。秋色明海縣，寒煙生裏閭。',48,'御定全唐詩/json/142.json','["樓頭廣陵近，九月在南徐。秋色明海縣，寒煙生裏閭。", "夜帆歸楚客，昨日度江書。為問易名叟，垂綸不見魚。"]'),
('yuding-8','靜法師東齋','王昌齡','唐','御定全唐诗','yuding','','[]','築室在人境，遂得真隱情。春盡草木變，雨來池館清。',48,'御定全唐詩/json/142.json','["築室在人境，遂得真隱情。春盡草木變，雨來池館清。", "琴書全雅道，視聽已無生。閉戶脫三界，白雲自虛盈。"]'),
('yuding-9','素上人影塔','王昌齡','唐','御定全唐诗','yuding','','[]','物化同枯木，希夷明月珠。本來生滅盡，何者是虛無。',48,'御定全唐詩/json/142.json','["物化同枯木，希夷明月珠。本來生滅盡，何者是虛無。", "一坐看如故，千齡獨向隅。至人非別有，方外不應殊。"]'),
('yuding-10','遇薛明府謁聰上人','王昌齡','唐','御定全唐诗','yuding','','[]','欣逢柏梁故，共謁聰公禪。石室無人到，繩床見虎眠。',48,'御定全唐詩/json/142.json','["欣逢柏梁故，共謁聰公禪。石室無人到，繩床見虎眠。", "陰崖常抱雪，枯澗為生泉。出處雖雲異，同歡在法筵。"]'),
('yuding-11','謁焦煉師','王昌齡','唐','御定全唐诗','yuding','','[]','中峰青苔壁，一點雲生時。豈意石堂裏，得逢焦煉師。',48,'御定全唐詩/json/142.json','["中峰青苔壁，一點雲生時。豈意石堂裏，得逢焦煉師。", "爐香淨琴案，松影閑瑤墀。拜受長年藥，翩翻西海期。"]'),
('yuding-12','宿京江口期劉昚虛不至','王昌齡','唐','御定全唐诗','yuding','','[]','霜天起長望，殘月生海門。風靜夜潮滿，城高寒氣昏。',48,'御定全唐詩/json/142.json','["霜天起長望，殘月生海門。風靜夜潮滿，城高寒氣昏。", "故人何寂寞，久已乖清言。明發不能寐，徒盈江上尊。"]'),
('yuding-13','寒食即事','王昌齡','唐','御定全唐诗','yuding','','[]','晉陽寒食地，風俗舊來傳。雨滅龍蛇火，春生鴻雁天。',48,'御定全唐詩/json/142.json','["晉陽寒食地，風俗舊來傳。雨滅龍蛇火，春生鴻雁天。", "泣多流水漲，歌發舞雲旋。西見之推廟，空為人所憐。"]'),
('yuding-14','九日登高','王昌齡','唐','御定全唐诗','yuding','','[]','青山遠近帶皇州，霽景重陽上北樓。雨歇亭皋仙菊潤，',40,'御定全唐詩/json/142.json','["青山遠近帶皇州，霽景重陽上北樓。雨歇亭皋仙菊潤，", "謾說陶潛籬下醉，何曾得見此風流。"]'),
('yuding-15','萬歲樓','王昌齡','唐','御定全唐诗','yuding','','[]','江上巍巍萬歲樓，不知經歷幾千秋。年年喜見山長在，',40,'御定全唐詩/json/142.json','["江上巍巍萬歲樓，不知經歷幾千秋。年年喜見山長在，", "誰堪登望雲煙裏，向晚茫茫發旅愁。"]'),
('yuding-16','夏月花萼樓酺宴應制','王昌齡','唐','御定全唐诗','yuding','','[]','土德三元正，堯心萬國同。汾陰備冬禮，長樂應和風。',96,'御定全唐詩/json/142.json','["土德三元正，堯心萬國同。汾陰備冬禮，長樂應和風。", "賜慶垂天澤，流歡舊渚宮。樓臺生海上，簫鼓出天中。", "霧曉筵初接，宵長曲未終。雨隨青幕合，月照舞羅空。", "玉陛分朝列，文章發聖聰。愚臣忝書賦，歌詠頌絲桐。"]'),
('yuding-17','送歐陽會稽之任','王昌齡','唐','御定全唐诗','yuding','','[]','懷祿貴心賞，東流山水長。官移會稽郡，地邇上虞鄉。',96,'御定全唐詩/json/142.json','["懷祿貴心賞，東流山水長。官移會稽郡，地邇上虞鄉。", "緩帶屏紛雜，漁舟臨訟堂。逶迤回溪趣，猿嘯飛鳥行。", "萬室霽朝雨，千峰迎夕陽。輝輝遠洲映，曖曖澄湖光。", "白髮有高士，青春期上皇。應須枉車歇，為我訪荷裳。"]'),
('yuding-18','同王維集青龍寺曇壁上人兄院五韻','王昌齡','唐','御定全唐诗','yuding','','[]','本來清淨所，竹樹引幽陰。簷外含山翠，人間出世心。',60,'御定全唐詩/json/142.json','["本來清淨所，竹樹引幽陰。簷外含山翠，人間出世心。", "圓通無有象，聖境不能侵。真是吾兄法，何妨友弟深。", "天香自然會，靈異識鐘音。"]'),
('yuding-19','東溪玩月','王昌齡','唐','御定全唐诗','yuding','','[]','月從斷山口，遙吐柴門端。萬木分空霽，流陰中夜攢。',72,'御定全唐詩/json/142.json','["月從斷山口，遙吐柴門端。萬木分空霽，流陰中夜攢。", "光連虛象白，氣與風露寒。穀靜秋泉響，岩深青靄殘。", "澄清入幽夢，破影抱空巒。恍惚琴窗裏，松溪曉思難。"]'),
('yuding-0','朝來曲','王昌齡','唐','御定全唐诗','yuding','','[]','月昃鳴珂動，花連繡戶春。盤龍玉台鏡，唯待畫眉人。',24,'御定全唐詩/json/143.json','["月昃鳴珂動，花連繡戶春。盤龍玉台鏡，唯待畫眉人。"]'),
('yuding-1','從軍行','王昌齡','唐','御定全唐诗','yuding','','[]','大將軍出戰，白日暗榆關。三面黃金甲，單于破膽還。',24,'御定全唐詩/json/143.json','["大將軍出戰，白日暗榆關。三面黃金甲，單于破膽還。"]'),
('yuding-2','答武陵田太守','王昌齡','唐','御定全唐诗','yuding','','[]','仗劍行千里，微軀感一言。曾為大樑客，不負信陵恩。',24,'御定全唐詩/json/143.json','["仗劍行千里，微軀感一言。曾為大樑客，不負信陵恩。"]'),
('yuding-3','題灞池二首','王昌齡','唐','御定全唐诗','yuding','','[]','腰鐮欲何之，東園刈秋韭。世事不復論，悲歌和樵叟。',48,'御定全唐詩/json/143.json','["腰鐮欲何之，東園刈秋韭。世事不復論，悲歌和樵叟。", "開門望長川，薄暮見漁者。借問白頭翁，垂綸幾年也。"]'),
('yuding-4','題僧房','王昌齡','唐','御定全唐诗','yuding','','[]','棕櫚花滿院，苔蘚入閒房。彼此名言絕，空中聞異香。',24,'御定全唐詩/json/143.json','["棕櫚花滿院，苔蘚入閒房。彼此名言絕，空中聞異香。"]'),
('yuding-5','擊磬老人','王昌齡','唐','御定全唐诗','yuding','','[]','雙峰褐衣久，一磬白眉長。誰識野人意，徒看春草芳。',24,'御定全唐詩/json/143.json','["雙峰褐衣久，一磬白眉長。誰識野人意，徒看春草芳。"]'),
('yuding-6','送胡大','王昌齡','唐','御定全唐诗','yuding','','[]','荊門不堪別，況乃瀟湘秋。何處遙望君，江邊明月樓。',24,'御定全唐詩/json/143.json','["荊門不堪別，況乃瀟湘秋。何處遙望君，江邊明月樓。"]'),
('yuding-7','送郭司倉','王昌齡','唐','御定全唐诗','yuding','','[]','映門淮水綠，留騎主人心。明月隨良掾，春潮夜夜深。',24,'御定全唐詩/json/143.json','["映門淮水綠，留騎主人心。明月隨良掾，春潮夜夜深。"]'),
('yuding-8','送李十五','王昌齡','唐','御定全唐诗','yuding','','[]','怨別秦楚深，江中秋雲起。天長杳無隔，月影在寒水。',24,'御定全唐詩/json/143.json','["怨別秦楚深，江中秋雲起。天長杳無隔，月影在寒水。"]'),
('yuding-9','送張四','王昌齡','唐','御定全唐诗','yuding','','[]','楓林已愁暮，楚水複堪悲。別後冷山月，清猿無斷時。',24,'御定全唐詩/json/143.json','["楓林已愁暮，楚水複堪悲。別後冷山月，清猿無斷時。"]'),
('yuding-10','武陵田太守席送司馬盧溪','王昌齡','唐','御定全唐诗','yuding','','[]','諸侯分楚郡，飲餞五溪春。山水清暉遠，俱憐一逐臣。',24,'御定全唐詩/json/143.json','["諸侯分楚郡，飲餞五溪春。山水清暉遠，俱憐一逐臣。"]'),
('yuding-11','送譚八之桂林','王昌齡','唐','御定全唐诗','yuding','','[]','客心仍在楚，江館複臨湘。別意猿鳥外，天寒桂水長。',24,'御定全唐詩/json/143.json','["客心仍在楚，江館複臨湘。別意猿鳥外，天寒桂水長。"]'),
('yuding-12','送劉十五之郡','王昌齡','唐','御定全唐诗','yuding','','[]','平明江霧寒，客馬江上發。扁舟事洛陽，窅窅含楚月。',24,'御定全唐詩/json/143.json','["平明江霧寒，客馬江上發。扁舟事洛陽，窅窅含楚月。"]'),
('yuding-13','從軍行七首','王昌齡','唐','御定全唐诗','yuding','','[]','烽火城西百尺樓，黃昏獨上海風秋。',224,'御定全唐詩/json/143.json','["烽火城西百尺樓，黃昏獨上海風秋。", "更吹羌笛關山月，無那金閨萬里愁。", "琵琶起舞換新聲，總是關山舊別情。", "撩亂邊愁聽不盡，高高秋月照長城。", "關城榆葉早疏黃，日暮雲沙古戰場。", "表請回軍掩塵骨，莫教兵士哭龍荒。", "青海長雲暗雪山，孤城遙望玉門關。", "黃沙百戰穿金甲，不破樓蘭終不還。", "大漠風塵日色昏，紅旗半卷出轅門。", "前軍夜戰洮河北，已報生擒吐谷渾。", "胡瓶落膊紫薄汗，碎葉城西秋月團。", "明敕星馳封寶劍，辭君一夜取樓蘭。", "玉門山嶂幾千重，山北山南總是烽。", "人依遠戍須看火，馬踏深山不見蹤。"]'),
('yuding-14','出塞二首','王昌齡','唐','御定全唐诗','yuding','','[]','秦時明月漢時關，萬里長征人未還。',64,'御定全唐詩/json/143.json','["秦時明月漢時關，萬里長征人未還。", "但使龍城飛將在，不教胡馬度陰山。", "騮馬新跨白玉鞍，戰罷沙場月色寒。", "城頭鐵鼓聲猶振，匣裏金刀血未幹。"]'),
('yuding-15','採蓮曲二首','王昌齡','唐','御定全唐诗','yuding','','[]','吳姬越豔楚王妃，爭弄蓮舟水濕衣。',64,'御定全唐詩/json/143.json','["吳姬越豔楚王妃，爭弄蓮舟水濕衣。", "來時浦口花迎入，采罷江頭月送歸。", "荷葉羅裙一色裁，芙蓉向臉兩邊開。", "亂入池中看不見，聞歌始覺有人來。"]'),
('yuding-16','殿前曲二首','王昌齡','唐','御定全唐诗','yuding','','[]','貴人妝梳殿前催，香風吹入殿后來。',64,'御定全唐詩/json/143.json','["貴人妝梳殿前催，香風吹入殿后來。", "仗引笙歌大宛馬，白蓮花發照池台。", "胡部笙歌西殿頭，梨園弟子和涼州。", "新聲一段高樓月，聖主千秋樂未休。"]'),
('yuding-17','春宮曲','王昌齡','唐','御定全唐诗','yuding','','[]','昨夜風開露井桃，未央前殿月輪高。',32,'御定全唐詩/json/143.json','["昨夜風開露井桃，未央前殿月輪高。", "平陽歌舞新承寵，簾外春寒賜錦袍。"]'),
('yuding-18','西宮春怨','王昌齡','唐','御定全唐诗','yuding','','[]','西宮夜靜百花香，欲卷珠簾春恨長。',32,'御定全唐詩/json/143.json','["西宮夜靜百花香，欲卷珠簾春恨長。", "斜抱雲和深見月，朦朧樹色隱昭陽。"]'),
('yuding-19','西宮秋怨','王昌齡','唐','御定全唐诗','yuding','','[]','芙蓉不及美人妝，水殿風來珠翠香。',32,'御定全唐詩/json/143.json','["芙蓉不及美人妝，水殿風來珠翠香。", "誰分含啼掩秋扇，空懸明月待君王。"]'),
('yuding-20','長信秋詞五首','王昌齡','唐','御定全唐诗','yuding','','[]','金井梧桐秋葉黃，珠簾不卷夜來霜。',160,'御定全唐詩/json/143.json','["金井梧桐秋葉黃，珠簾不卷夜來霜。", "熏籠玉枕無顏色，臥聽南宮清漏長。", "高殿秋砧響夜闌，霜深猶憶禦衣寒。", "銀燈青瑣裁縫歇，還向金城明主看。", "奉帚平明金殿開，且將團扇暫裴回。", "玉顏不及寒鴉色，猶帶昭陽日影來。", "真成薄命久尋思，夢見君王覺後疑。", "火照西宮知夜飲，分明複道奉恩時。", "長信宮中秋月明，昭陽殿下擣衣聲。", "白露堂中細草跡，紅羅帳裏不勝情。"]'),
('yuding-21','青樓曲二首','王昌齡','唐','御定全唐诗','yuding','','[]','白馬金鞍從武皇，旌旗十萬宿長楊。',64,'御定全唐詩/json/143.json','["白馬金鞍從武皇，旌旗十萬宿長楊。", "樓頭小婦鳴箏坐，遙見飛塵入建章。", "馳道楊花滿禦溝，紅妝縵綰上青樓。", "金章紫綬千餘騎，夫婿朝回初拜侯。"]'),
('yuding-22','青樓怨','王昌齡','唐','御定全唐诗','yuding','','[]','香幃風動花入樓，高調鳴箏緩夜愁。',32,'御定全唐詩/json/143.json','["香幃風動花入樓，高調鳴箏緩夜愁。", "腸斷關山不解說，依依殘月下簾鉤。"]'),
('yuding-23','浣紗女','王昌齡','唐','御定全唐诗','yuding','','[]','錢塘江畔是誰家，江上女兒全勝花。',32,'御定全唐詩/json/143.json','["錢塘江畔是誰家，江上女兒全勝花。", "吳王在時不得出，今日公然來浣紗。"]'),
