('yuding-63','送姚司法歸吳','王昌齡','唐','御定全唐诗','yuding','','[]','吳掾留觴楚郡心，洞庭秋雨海門陰。',32,'御定全唐詩/json/143.json','["吳掾留觴楚郡心，洞庭秋雨海門陰。", "但令意遠扁舟近，不道滄江百丈深。"]'),
('yuding-64','送高三之桂林','王昌齡','唐','御定全唐诗','yuding','','[]','留君夜飲對瀟湘，從此歸舟客夢長。',32,'御定全唐詩/json/143.json','["留君夜飲對瀟湘，從此歸舟客夢長。", "嶺上梅花侵雪暗，歸時還拂桂花香。"]'),
('yuding-65','旅望','王昌齡','唐','御定全唐诗','yuding','','[]','白花原頭望京師，黃河水流無盡時。',32,'御定全唐詩/json/143.json','["白花原頭望京師，黃河水流無盡時。", "窮秋曠野行人絕，馬首東來知是誰。"]'),
('yuding-66','題朱煉師山房','王昌齡','唐','御定全唐诗','yuding','','[]','叩齒焚香出世塵，齋壇鳴磬步虛人。',32,'御定全唐詩/json/143.json','["叩齒焚香出世塵，齋壇鳴磬步虛人。", "百花仙醞能留客，一飯胡麻度幾春。"]'),
('yuding-67','武陵開元觀黃煉師院三首','王昌齡','唐','御定全唐诗','yuding','','[]','松間白髮黃尊師，童子燒香禹步時。',96,'御定全唐詩/json/143.json','["松間白髮黃尊師，童子燒香禹步時。", "欲訪桃源入溪路，忽聞雞犬使人疑。", "先賢盛說桃花源，塵忝何堪武陵郡。", "聞道秦時避地人，至今不與人通問。", "山觀空虛清靜門，從官役吏擾塵喧。", "暫因問俗到真境，便欲投誠依道源。"]'),
('yuding-68','河上老人歌','王昌齡','唐','御定全唐诗','yuding','','[]','河上老人坐古槎，合丹只用青蓮花。',32,'御定全唐詩/json/143.json','["河上老人坐古槎，合丹只用青蓮花。", "至今八十如四十，口道滄溟是我家。"]'),
('yuding-69','春怨','王昌齡','唐','御定全唐诗','yuding','','[]','音書杜絕白狼西，桃李無顏黃鳥啼。',32,'御定全唐詩/json/143.json','["音書杜絕白狼西，桃李無顏黃鳥啼。", "寒雁春深歸去盡，出門腸斷草萋萋。"]'),
('yuding-70','句','王昌齡','唐','御定全唐诗','yuding','','[]','朝薦抱良策，獨倚江城樓。',83,'御定全唐詩/json/143.json','["朝薦抱良策，獨倚江城樓。", "昨從金陵邑，遠謫沅溪濱。", "娟魄已三孕。。", "駕幸溫泉日，嚴霜子月初。", "長亭酒未醒，千里風動地。", "蒼荻寒滄江，石頭岸邊飲。", "天仗森森練雪凝，身騎鐵驄自臂鷹。"]'),
('yuding-0','送陸擢','常建','唐','御定全唐诗','yuding','','[]','聖代多才俊，陸生何考盤。南山高松樹，不合空摧殘。',48,'御定全唐詩/json/144.json','["聖代多才俊，陸生何考盤。南山高松樹，不合空摧殘。", "九月湖上別，北風秋雨寒。殷勤歎孤鳳，早食金琅玕。"]'),
('yuding-1','送李十一尉臨溪','常建','唐','御定全唐诗','yuding','','[]','泠泠花下琴，君唱渡江吟。天際一帆影，預懸離別心。',48,'御定全唐詩/json/144.json','["泠泠花下琴，君唱渡江吟。天際一帆影，預懸離別心。", "以言神仙尉，因致瑤華音。回軫撫商調，越溪澄碧林。"]'),
('yuding-2','江上琴興','常建','唐','御定全唐诗','yuding','','[]','江上調玉琴，一弦清一心。泠泠七弦遍，萬木澄幽陰。',48,'御定全唐詩/json/144.json','["江上調玉琴，一弦清一心。泠泠七弦遍，萬木澄幽陰。", "能使江月白，又令江水深。始知梧桐枝，可以徽黃金。"]'),
('yuding-3','湖中晚霽','常建','唐','御定全唐诗','yuding','','[]','湖廣舟自輕，江天欲澄霽。是時清楚望，氣色猶霾曀。',120,'御定全唐詩/json/144.json','["湖廣舟自輕，江天欲澄霽。是時清楚望，氣色猶霾曀。", "踟躕金霞白，波上日初麗。煙虹落鏡中，樹木生天際。", "杳杳涯欲辨，濛濛雲複閉。言乘星漢明，又睹寰瀛勢。", "微興從此愜，悠然不知歲。試歌滄浪清，遂覺乾坤細。", "豈念客衣薄，將期永投袂。遲回漁父間，一雁聲嘹唳。"]'),
('yuding-4','宿王昌齡隱居','常建','唐','御定全唐诗','yuding','','[]','清溪深不測，隱處唯孤雲。松際露微月，清光猶為君。',48,'御定全唐詩/json/144.json','["清溪深不測，隱處唯孤雲。松際露微月，清光猶為君。", "茅亭宿花影，藥院滋苔紋。余亦謝時去，西山鸞鶴群。"]'),
('yuding-5','送楚十少府','常建','唐','御定全唐诗','yuding','','[]','微風吹霜氣，寒影明前除。落日未能別，蕭蕭林木虛。',72,'御定全唐詩/json/144.json','["微風吹霜氣，寒影明前除。落日未能別，蕭蕭林木虛。", "愁煙閉千里，仙尉其何如。因送別鶴操，贈之雙鯉魚。", "鯉魚在金盤，別鶴哀有餘。心事則如此，請君開素書。"]'),
('yuding-6','張山人彈琴','常建','唐','御定全唐诗','yuding','','[]','君去芳草綠，西峰彈玉琴。豈惟丘中賞，兼得清煩襟。',96,'御定全唐詩/json/144.json','["君去芳草綠，西峰彈玉琴。豈惟丘中賞，兼得清煩襟。", "朝從山口還，出嶺聞清音。了然雲霞氣，照見天地心。", "玄鶴下澄空，翩翩舞松林。改弦扣商聲，又聽飛龍吟。", "稍覺此身妄，漸知仙事深。其將煉金鼎，永矣投吾簪。"]'),
('yuding-7','白湖寺後溪宿雲門','常建','唐','御定全唐诗','yuding','','[]','落日山水清，亂流鳴淙淙。舊蒲雨抽節，新花水對窗。',156,'御定全唐詩/json/144.json','["落日山水清，亂流鳴淙淙。舊蒲雨抽節，新花水對窗。", "溪中日已沒，歸鳥多為雙。杉松引直路，出穀臨前湖。", "洲渚晚色靜，又觀花與蒲。入溪複登嶺，草淺寒流速。", "圓月明高峰，春山因獨宿。松陰澄初夜，曙色分遠目。", "日出城南隅，青青媚川陸。亂花覆東郭，碧氣銷長林。", "四郊一清影，千里歸寸心。前瞻王程促，卻戀雲門深。", "畢景有餘興，到家彈玉琴。"]'),
('yuding-8','閑齋臥病行藥至山館稍次湖亭二首','常建','唐','御定全唐诗','yuding','','[]','旬時結陰霖，簾外初白日。齋沐清病容，心魂畏虛室。',96,'御定全唐詩/json/144.json','["旬時結陰霖，簾外初白日。齋沐清病容，心魂畏虛室。", "閑梅照前戶，明鏡悲舊質。同袍四五人，何不來問疾。", "行藥至石壁，東風變萌芽。主人門外綠，小隱湖中花。", "時物堪獨往，春帆宜別家。辭君向滄海，爛熳從天涯。"]'),
('yuding-9','塞上曲','常建','唐','御定全唐诗','yuding','','[]','翩翩雲中使，來問太原卒。百戰苦不歸，刀頭怨明月。',48,'御定全唐詩/json/144.json','["翩翩雲中使，來問太原卒。百戰苦不歸，刀頭怨明月。", "塞雲隨陣落，寒日傍城沒。城下有寡妻，哀哀哭枯骨。"]'),
('yuding-10','仙谷遇毛女意知是秦宮人','常建','唐','御定全唐诗','yuding','','[]','溪口水石淺，泠泠明藥叢。入溪雙峰峻，松栝疏幽風。',144,'御定全唐詩/json/144.json','["溪口水石淺，泠泠明藥叢。入溪雙峰峻，松栝疏幽風。", "垂嶺枝嫋嫋，翳泉花濛濛。夤緣齋人目，路盡心彌通。", "磐石橫陽崖，前流殊未窮。回潭清雲影，彌漫長天空。", "水邊一神女，千歲為玉童。羽毛經漢代，珠翠逃秦宮。", "目覿神已寓，鶴飛言未終。祈君青雲秘，願謁黃仙翁。", "嘗以耕玉田，龍鳴西頂中。金梯與天接，幾日來相逢。"]'),
('yuding-11','夢太白西峰','常建','唐','御定全唐诗','yuding','','[]','夢寐升九崖，杳靄逢元君。遺我太白峰，寥寥辭垢氛。',96,'御定全唐詩/json/144.json','["夢寐升九崖，杳靄逢元君。遺我太白峰，寥寥辭垢氛。", "結宇在星漢，宴林閉氤氳。簷楹覆餘翠，巾舄生片雲。", "時往溪水間，孤亭晝仍曛。松峰引天影，石瀨清霞文。", "恬目緩舟趣，霽心投鳥群。春風又搖棹，潭島花紛紛。"]'),
('yuding-12','鄂渚招王昌齡張僨','常建','唐','御定全唐诗','yuding','','[]','刈蘆曠野中，沙土飛黃雲。天晦無精光，茫茫悲遠君。',144,'御定全唐詩/json/144.json','["刈蘆曠野中，沙土飛黃雲。天晦無精光，茫茫悲遠君。", "楚山隔湘水，湖畔落日曛。春雁又北飛，音書固難聞。", "謫居未為歎，讒枉何由分。午日逐蛟龍，宜為吊冤文。", "翻覆古共然，名宦安足雲。貧士任枯槁，捕魚清江濆。", "有時荷鋤犁，曠野自耕耘。不然春山隱，溪澗花氤氳。", "山鹿自有場，賢達亦顧群。二賢歸去來，世上徒紛紛。"]'),
('yuding-13','春詞二首','常建','唐','御定全唐诗','yuding','','[]','菀菀黃柳絲，濛濛雜花垂。日高紅妝臥，倚對春光遲。',72,'御定全唐詩/json/144.json','["菀菀黃柳絲，濛濛雜花垂。日高紅妝臥，倚對春光遲。", "甯知傍淇水，騕褭黃金羈。", "翳翳陌上桑，南枝交北堂。美人金梯出，素手自提筐。", "非但畏蠶饑，盈盈嬌路傍。"]'),
('yuding-14','晦日馬鐙曲稍次中流作','常建','唐','御定全唐诗','yuding','','[]','夜寒宿蘆葦，曉色明西林。初日在川上，便澄遊子心。',72,'御定全唐詩/json/144.json','["夜寒宿蘆葦，曉色明西林。初日在川上，便澄遊子心。", "秦天無纖翳，郊野浮春陰。波靜隨釣魚，舟小綠水深。", "出浦見千里，曠然諧遠尋。扣船應漁父，因唱滄浪吟。"]'),
('yuding-15','古意','常建','唐','御定全唐诗','yuding','','[]','牧馬古道傍，道傍多古墓。蕭條愁殺人，蟬鳴白楊樹。',48,'御定全唐詩/json/144.json','["牧馬古道傍，道傍多古墓。蕭條愁殺人，蟬鳴白楊樹。", "回頭望京邑，合遝生塵霧。富貴安可常，歸來保貞素。"]'),
('yuding-16','宿五度溪仙人得道處','常建','唐','御定全唐诗','yuding','','[]','五度溪上花，生根依兩崖。二月尋片雲，願宿秦人家。',72,'御定全唐詩/json/144.json','["五度溪上花，生根依兩崖。二月尋片雲，願宿秦人家。", "上見懸崖崩，下見白水湍。仙人彈棋處，石上青蘿盤。", "無處求玉童，翳翳唯林巒。前溪遇新月，聊取玉琴彈。"]'),
('yuding-17','西山','常建','唐','御定全唐诗','yuding','','[]','一身為輕舟，落日西山際。常隨去帆影，遠接長天勢。',120,'御定全唐詩/json/144.json','["一身為輕舟，落日西山際。常隨去帆影，遠接長天勢。", "物象歸餘清，林巒分夕麗。亭亭碧流暗，日入孤霞繼。", "渚日遠陰映，湖雲尚明霽。林昏楚色來，岸遠荊門閉。", "至夜轉清迥，蕭蕭北風厲。沙邊雁鷺泊，宿處蒹葭蔽。", "圓月逗前浦，孤琴又搖曳。泠然夜遂深，白露沾人袂。"]'),
('yuding-18','春詞','常建','唐','御定全唐诗','yuding','','[]','階下草猶短，牆頭梨花白。織女高樓上，停梭顧行客。',36,'御定全唐詩/json/144.json','["階下草猶短，牆頭梨花白。織女高樓上，停梭顧行客。", "問君在何所，青鳥舒錦翮。"]'),
('yuding-19','贈三侍禦','常建','唐','御定全唐诗','yuding','','[]','高山臨大澤，正月蘆花幹。陽色熏兩崖，不改青松寒。',192,'御定全唐詩/json/144.json','["高山臨大澤，正月蘆花幹。陽色熏兩崖，不改青松寒。", "士賢守孤貞，古來皆共難。明君錯甚才，臺上飛三鸞。", "操與霜雪明，量與江海寬。束身視天涯，安能窮波瀾。", "孤鶴在枳棘，一枝非所安。逸翮望絕霄，見欲淩雲端。", "層台何其高，山石流洪湍。固知非天池，鳴躍同所歡。", "誰念獨枯槁，四十長江幹。責躬貴知己，效拙從一官。", "折翮悲高風，苦饑候朝餐。湖月映大海，天空何漫漫。", "托身未知所，謀道庶不刊。吟彼喬木詩，一夕常三歎。"]'),
('yuding-20','第三峰','常建','唐','御定全唐诗','yuding','','[]','西山第三頂，茅宇依雙松。杳杳欲至天，雲梯升幾重。',120,'御定全唐詩/json/144.json','["西山第三頂，茅宇依雙松。杳杳欲至天，雲梯升幾重。", "瑩魄澄玉虛，以求鸞鶴蹤。逶迤非天人，執節乘赤龍。", "旁映白日光，縹緲輕霞容。孤輝上煙霧，餘影明心胸。", "願與黃麒麟，欲飛而莫從。因寂清萬象，輕雲自中峰。", "山暝學棲鳥，月來隨暗蛩。尋空靜餘響，嫋嫋雲溪鐘。"]'),
('yuding-21','古興','常建','唐','御定全唐诗','yuding','','[]','漢上逢老翁，江口為僵屍。白髮沾黃泥，遺骸集烏鴟。',144,'御定全唐詩/json/144.json','["漢上逢老翁，江口為僵屍。白髮沾黃泥，遺骸集烏鴟。", "機巧自此忘，精魄今何之。風吹釣竿折，魚躍安能施。", "白水明汀洲，菰蒲冒深陂。唯留扁舟影，系在長江湄。", "突兀枯松枝，悠揚女蘿絲。托身難憑依，生死焉相知。", "遍觀今時人，舉世皆爾為。將軍死重圍，漢卒猶爭馳。", "百馬同一銜，萬輪同一規。名與身孰親，君子宜固思。"]'),
('yuding-22','高樓夜彈箏','常建','唐','御定全唐诗','yuding','','[]','高樓百餘尺，直上江水準。明月照人苦，開簾彈玉箏。',48,'御定全唐詩/json/144.json','["高樓百餘尺，直上江水準。明月照人苦，開簾彈玉箏。", "山高猿狖急，天靜鴻雁鳴。曲度猶未終，東峰霞半生。"]'),
('yuding-23','客有自燕而歸哀其老而贈之','常建','唐','御定全唐诗','yuding','','[]','羸馬朝自燕，一身為二連。憶親拜孤塚，移葬雙陵前。',96,'御定全唐詩/json/144.json','["羸馬朝自燕，一身為二連。憶親拜孤塚，移葬雙陵前。", "幽願從此畢，劍心因獲全。孟冬寒氣盛，撫轡告言旋。", "碣石海北門，餘寇惟朝鮮。離離一寒騎，嫋嫋馳白天。", "生別皆自取，況為士卒先。寸心漁陽興，落日旌竿懸。"]'),
('yuding-24','白龍窟泛舟寄天臺學道者','常建','唐','御定全唐诗','yuding','','[]','夕映翠山深，餘暉在龍窟。扁舟滄浪意，澹澹花影沒。',120,'御定全唐詩/json/144.json','["夕映翠山深，餘暉在龍窟。扁舟滄浪意，澹澹花影沒。", "西浮入天色，南望對雲闕。因憶莓苔峰，初陽濯玄發。", "泉蘿兩幽映，松鶴間清越。碧海瑩子神，玉膏澤人骨。", "忽然為枯木，微興遂如兀。應寂中有天，明心外無物。", "環回從所泛，夜靜猶不歇。澹然意無限，身與波上月。"]'),
('yuding-25','張天師草堂','常建','唐','御定全唐诗','yuding','','[]','靈溪宴清宇，傍倚枯松根。花藥繞方丈，瀑泉飛至門。',120,'御定全唐詩/json/144.json','["靈溪宴清宇，傍倚枯松根。花藥繞方丈，瀑泉飛至門。", "四氣閉炎熱，兩崖改明昏。夜深月暫皎，亭午朝始暾。", "信是天人居，幽幽寂無喧。萬壑應鳴磬，諸峰接一魂。", "遂登仙子谷，因醉田生樽。時節開玉書，窅映飛天言。", "心化便無影，目精焉累煩。忽而與霄漢，寥落空南軒。"]'),
('yuding-26','古意三首','常建','唐','御定全唐诗','yuding','','[]','二妃方訪舜，萬里南方懸。遠道隔江漢，孤舟無歲年。',252,'御定全唐詩/json/144.json','["二妃方訪舜，萬里南方懸。遠道隔江漢，孤舟無歲年。", "不知蒼梧處，氣盡呼青天。愁淚變楚竹，蛾眉喪湘川。", "後人立為廟，累世稱其賢。過客設祠祭，狐狸來坐邊。", "懷古未忍還，猿吟徹空山。", "明月照高閣，彩女褰羅幕。歌舞臨碧雲，簫聲沸珠箔。", "青鸞臨南海，天上雙白鶴。萬里齊翼飛，意求君門樂。", "玉霄九重閉，金鎖夜不開。兩翅自無力，愁鳴雲外來。", "態深入空貴，世屈無良媒。俯仰顧中禁，東飛白玉台。", "楚王竟何去，獨自留巫山。偏使世人見，迢迢江漢間。", "駐舟春溪裏，皆願拜靈顏。寤寐見神女，金沙鳴佩環。", "閑豔絕世姿，令人氣力微。含笑竟不語，化作朝雲飛。"]'),
('yuding-27','漁浦','常建','唐','御定全唐诗','yuding','','[]','春至百草綠，陂澤聞鶬鶊。別家投釣翁，今世滄浪情。',72,'御定全唐詩/json/144.json','["春至百草綠，陂澤聞鶬鶊。別家投釣翁，今世滄浪情。", "漚紵為縕袍，折麻為長纓。榮譽失本真，怪人浮此生。", "碧水月自闊，安流淨而平。扁舟與天際，獨往誰能名。"]'),
('yuding-28','空靈山應田叟','常建','唐','御定全唐诗','yuding','','[]','湖南無村落，山舍多黃茆。淳樸如太古，其人居鳥巢。',144,'御定全唐詩/json/144.json','["湖南無村落，山舍多黃茆。淳樸如太古，其人居鳥巢。", "牧童唱巴歌，野老亦獻嘲。泊舟問溪口，言語皆啞咬。", "土俗不尚農，豈暇論肥磽。莫徭射禽獸，浮客烹魚鮫。", "餘亦罘罝人，獲麋今尚苞。敬君中國來，願以充其庖。", "日入聞虎鬥，空山滿咆哮。懷人雖共安，異域終難交。", "白水可洗心，采薇可為肴。曳策背落日，江風鳴梢梢。"]'),
('yuding-29','太公哀晚遇','常建','唐','御定全唐诗','yuding','','[]','日出渭流白，文王畋獵時。釣翁在蘆葦，川澤無熊羆。',144,'御定全唐詩/json/144.json','["日出渭流白，文王畋獵時。釣翁在蘆葦，川澤無熊羆。", "詔書起遺賢，匹馬令致辭。因稱江海人，臣老筋力衰。", "遲遲詣天車，快快悟靈龜。兵馬更不獵，君臣皆共怡。", "同車至咸陽，心影無磷緇。四牡玉墀下，一言為帝師。", "王侯擁朱門，軒蓋曜長逵。古來榮華人，遭遇誰知之。", "落日懸桑榆，光景有頓虧。倏忽天地人，雖貴將何為。"]'),
('yuding-30','昭君墓','常建','唐','御定全唐诗','yuding','','[]','漢宮豈不死，異域傷獨沒。萬里馱黃金，蛾眉為枯骨。',48,'御定全唐詩/json/144.json','["漢宮豈不死，異域傷獨沒。萬里馱黃金，蛾眉為枯骨。", "回車夜出塞，立馬皆不發。共恨丹青人，墳上哭明月。"]'),
('yuding-31','吊王將軍墓','常建','唐','御定全唐诗','yuding','','[]','嫖姚北伐時，深入強千里。戰餘落日黃，軍敗鼓聲死。',48,'御定全唐詩/json/144.json','["嫖姚北伐時，深入強千里。戰餘落日黃，軍敗鼓聲死。", "嘗聞漢飛將，可奪單于壘。今與山鬼鄰，殘兵哭遼水。"]'),
('yuding-32','古意','常建','唐','御定全唐诗','yuding','','[]','井底玉冰洞地明，琥珀轆轤青絲索。仙人騎鳳披彩霞，',40,'御定全唐詩/json/144.json','["井底玉冰洞地明，琥珀轆轤青絲索。仙人騎鳳披彩霞，", "一時渡海望不見，曉上青樓十二重。"]'),
('yuding-33','古興','常建','唐','御定全唐诗','yuding','','[]','轆轤井上雙梧桐，飛鳥銜花日將沒。深閨女兒莫愁年，',40,'御定全唐詩/json/144.json','["轆轤井上雙梧桐，飛鳥銜花日將沒。深閨女兒莫愁年，", "青絲素絲紅綠絲，織成錦衾當為誰。"]'),
('yuding-34','張公子行','常建','唐','御定全唐诗','yuding','','[]','日出乘釣舟，嫋嫋持釣竿。涉淇傍荷花，驄馬閑金鞍。',72,'御定全唐詩/json/144.json','["日出乘釣舟，嫋嫋持釣竿。涉淇傍荷花，驄馬閑金鞍。", "俠客白雲中，腰間懸轆轤。出門事嫖姚，為君西擊胡。", "胡兵漢騎相馳逐，轉戰孤軍西海北。百尺旌竿沉黑雲，"]'),
('yuding-35','題破山寺後禪院','常建','唐','御定全唐诗','yuding','','[]','清晨入古寺，初日照高林。竹徑通幽處，禪房花木深。',48,'御定全唐詩/json/144.json','["清晨入古寺，初日照高林。竹徑通幽處，禪房花木深。", "山光悅鳥性，潭影空人心。萬籟此都寂，但餘鐘磬音。"]'),
('yuding-36','送李大都護','常建','唐','御定全唐诗','yuding','','[]','單于雖不戰，都護事邊深。君執幕中秘，能為高士心。',48,'御定全唐詩/json/144.json','["單于雖不戰，都護事邊深。君執幕中秘，能為高士心。", "海頭近初月，磧裏多愁陰。西望郭猶子，將分淚滿襟。"]'),
('yuding-37','潭州留別','常建','唐','御定全唐诗','yuding','','[]','賢達不相識，偶然交已深。宿帆謁郡佐，悵別依禪林。',48,'御定全唐詩/json/144.json','["賢達不相識，偶然交已深。宿帆謁郡佐，悵別依禪林。", "湘水流入海，楚雲千里心。望君杉松夜，山月清猿吟。"]'),
('yuding-38','聽琴秋夜贈寇尊師','常建','唐','御定全唐诗','yuding','','[]','琴當秋夜聽，況是洞中人。一指指應法，一聲聲爽神。',48,'御定全唐詩/json/144.json','["琴當秋夜聽，況是洞中人。一指指應法，一聲聲爽神。", "寒蟲臨砌急，清吹嫋燈頻。何必鐘期耳，高閑自可親。"]'),
('yuding-39','泊舟盱眙','常建','唐','御定全唐诗','yuding','','[]','泊舟淮水次，霜降夕流清。夜久潮侵岸，天寒月近城。',48,'御定全唐詩/json/144.json','["泊舟淮水次，霜降夕流清。夜久潮侵岸，天寒月近城。", "平沙依雁宿，候館聽雞鳴。鄉國雲霄外，誰堪羈旅情。"]'),
('yuding-40','江行','常建','唐','御定全唐诗','yuding','','[]','平湖四無際，此夜泛孤舟。明月異方意，吳歌令客愁。',48,'御定全唐詩/json/144.json','["平湖四無際，此夜泛孤舟。明月異方意，吳歌令客愁。", "鄉園碧雲外，兄弟淥江頭。萬里無歸信，傷心看鬥牛。"]'),
('yuding-41','燕居','常建','唐','御定全唐诗','yuding','','[]','青苔常滿路，流水複入林。遠與市朝隔，日聞雞犬深。',48,'御定全唐詩/json/144.json','["青苔常滿路，流水複入林。遠與市朝隔，日聞雞犬深。", "寥寥丘中想，渺渺湖上心。嘯傲轉無欲，不知成陸沉。"]'),
('yuding-42','送宇文六','常建','唐','御定全唐诗','yuding','','[]','花映垂楊漢水清，微風林裏一枝輕。',32,'御定全唐詩/json/144.json','["花映垂楊漢水清，微風林裏一枝輕。", "即今江北還如此，愁殺江南離別情。"]'),
('yuding-43','落第長安','常建','唐','御定全唐诗','yuding','','[]','家園好在尚留秦，恥作明時失路人。',32,'御定全唐詩/json/144.json','["家園好在尚留秦，恥作明時失路人。", "恐逢故里鶯花笑，且向長安度一春。"]'),
('yuding-44','塞下','常建','唐','御定全唐诗','yuding','','[]','鐵馬胡裘出漢營，分麾百道救龍城。',32,'御定全唐詩/json/144.json','["鐵馬胡裘出漢營，分麾百道救龍城。", "左賢未遁旌竿折，過在將軍不在兵。"]'),
('yuding-45','題法院','常建','唐','御定全唐诗','yuding','','[]','勝景門閑對遠山，竹深松老半含煙。',32,'御定全唐詩/json/144.json','["勝景門閑對遠山，竹深松老半含煙。", "皓月殿中三度磬，水晶宮裏一僧禪。"]'),
('yuding-46','嶺猿','常建','唐','御定全唐诗','yuding','','[]','杳杳嫋嫋清且切，鷓鴣飛處又斜陽。',32,'御定全唐詩/json/144.json','["杳杳嫋嫋清且切，鷓鴣飛處又斜陽。", "相思嶺上相思淚，不到三聲合斷腸。"]'),
('yuding-47','三日尋李九莊','常建','唐','御定全唐诗','yuding','','[]','雨歇楊林東渡頭，永和三日蕩輕舟。',32,'御定全唐詩/json/144.json','["雨歇楊林東渡頭，永和三日蕩輕舟。", "故人家在桃花岸，直到門前溪水流。"]'),
('yuding-48','塞下曲四首','常建','唐','御定全唐诗','yuding','','[]','玉帛朝回望帝鄉，烏孫歸去不稱王。',128,'御定全唐詩/json/144.json','["玉帛朝回望帝鄉，烏孫歸去不稱王。", "天涯靜處無征戰，兵氣銷為日月光。", "北海陰風動地來，明君祠上望龍堆。", "髑髏皆是長城卒，日暮沙場飛作灰。", "龍鬥雌雄勢已分，山崩鬼哭恨將軍。", "黃河直北千餘裏，冤氣蒼茫成黑雲。", "因嫁單于怨在邊，蛾眉萬古葬胡天。", "漢家此去三千里，青塚常無草木煙。"]'),
('yuding-49','戲題湖上','常建','唐','御定全唐诗','yuding','','[]','湖上老人坐磯頭，湖裏桃花水卻流。',32,'御定全唐詩/json/144.json','["湖上老人坐磯頭，湖裏桃花水卻流。", "竹竿嫋嫋波無際，不知何者吞吾鉤。"]'),
('yuding-50','吳故宮','常建','唐','御定全唐诗','yuding','','[]','越女歌長君且聽，芙蓉香滿水邊城。',32,'御定全唐詩/json/144.json','["越女歌長君且聽，芙蓉香滿水邊城。", "豈知一日終非主，猶自如今有怨聲。"]'),
('yuding-0','從軍行','杜頠','唐','御定全唐诗','yuding','','[]','秋草馬蹄輕，角弓持弦急。去為龍城候，正值胡兵襲。',96,'御定全唐詩/json/145.json','["秋草馬蹄輕，角弓持弦急。去為龍城候，正值胡兵襲。", "軍氣橫大荒，戰酣日將入。長風金鼓動，白露鐵衣濕。", "四起愁邊聲，南轅時佇立。斷蓬孤自轉，寒雁飛相及。", "萬里雲沙漲，平川冰霰溢。夜聞漢使歸，獨向刀環泣。"]'),
('yuding-1','故絳行','杜頠','唐','御定全唐诗','yuding','','[]','君不見銅鞮觀，數裏城池已蕪漫。君不見h6祁宮，',39,'御定全唐詩/json/145.json','["君不見銅鞮觀，數裏城池已蕪漫。君不見h6祁宮，", "一代繁華皆共絕，九原唯望塚累累。"]'),
('yuding-2','少年行三首','李嶷','唐','御定全唐诗','yuding','','[]','十八羽林郎，戎衣侍漢王。臂鷹金殿側，挾彈玉輿傍。',108,'御定全唐詩/json/145.json','["十八羽林郎，戎衣侍漢王。臂鷹金殿側，挾彈玉輿傍。", "馳道春風起，陪游出建章。", "侍獵長楊下，承恩更射飛。塵生馬影滅，箭落雁行稀。", "薄暮隨天仗，聯翩入瑣闈。", "玉劍膝邊橫，金杯馬上傾。朝遊茂陵道，夜宿鳳凰城。", "豪吏多猜忌，無勞問姓名。"]'),
('yuding-3','淮南秋夜呈周侃','李嶷','唐','御定全唐诗','yuding','','[]','天淨河漢高，夜閑砧杵發。清秋忽如此，離恨應難歇。',48,'御定全唐詩/json/145.json','["天淨河漢高，夜閑砧杵發。清秋忽如此，離恨應難歇。", "風亂池上萍，露光竹間月。與君共遊處，勿作他鄉別。"]'),
('yuding-4','林園秋夜作','李嶷','唐','御定全唐诗','yuding','','[]','林臥避殘暑，白雲長在天。賞心既如此，對酒非徒然。',48,'御定全唐詩/json/145.json','["林臥避殘暑，白雲長在天。賞心既如此，對酒非徒然。", "月色遍秋露，竹聲兼夜泉。涼風懷袖裏，茲意與誰傳。"]'),
('yuding-5','讀前漢外戚傳','李嶷','唐','御定全唐诗','yuding','','[]','人錄尚書事，家臨禦路傍。鑿池通渭水，避暑借明光。',48,'御定全唐詩/json/145.json','["人錄尚書事，家臨禦路傍。鑿池通渭水，避暑借明光。", "印綬妻封邑，軒車子拜郎。寵因宮掖裏，勢極必先亡。"]'),
('yuding-6','春怨','崔亙','唐','御定全唐诗','yuding','','[]','夜盡夢初驚，紗窗早霧明。曉妝脂粉薄，春服綺羅輕。',48,'御定全唐詩/json/145.json','["夜盡夢初驚，紗窗早霧明。曉妝脂粉薄，春服綺羅輕。", "妾有今朝恨，君無舊日情。愁來理弦管，皆是斷腸聲。"]'),
('yuding-7','古歌二首','蔣維翰','唐','御定全唐诗','yuding','','[]','美人怨何深，含情倚金閣。不嚬複不語，紅淚雙雙落。',48,'御定全唐詩/json/145.json','["美人怨何深，含情倚金閣。不嚬複不語，紅淚雙雙落。", "美人閉紅燭，獨坐裁新錦。頻放剪刀聲，夜寒知未寢。"]'),
('yuding-8','春夜裁縫','蔣維翰','唐','御定全唐诗','yuding','','[]','珠箔因風起，飛蛾入最能。不教人夜作，方便殺明燈。',24,'御定全唐詩/json/145.json','["珠箔因風起，飛蛾入最能。不教人夜作，方便殺明燈。"]'),
('yuding-9','春女怨','蔣維翰','唐','御定全唐诗','yuding','','[]','白玉堂前一樹梅，今朝忽見數花開。',32,'御定全唐詩/json/145.json','["白玉堂前一樹梅，今朝忽見數花開。", "兒家門戶尋常閉，春色因何入得來。"]'),
('yuding-10','怨歌','蔣維翰','唐','御定全唐诗','yuding','','[]','百尺珠樓臨狹斜，新妝能唱美人車。',32,'御定全唐詩/json/145.json','["百尺珠樓臨狹斜，新妝能唱美人車。", "皆言賤妾紅顏好，要自狂夫不憶家。"]'),
('yuding-11','小山歌','萬楚','唐','御定全唐诗','yuding','','[]','人說淮南有小山，淮王昔日此登仙。城中雞犬皆飛去，',72,'御定全唐詩/json/145.json','["人說淮南有小山，淮王昔日此登仙。城中雞犬皆飛去，", "不知金石變長年，謾在人間戀攜手。君能舉帆至淮南，", "憶記來時魂悄悄，想見仙山眾峰小。今日長歌思不堪，"]'),
('yuding-12','題江潮莊壁','萬楚','唐','御定全唐诗','yuding','','[]','田家喜秋熟，歲晏林葉稀。禾黍積場圃，楂梨垂戶扉。',48,'御定全唐詩/json/145.json','["田家喜秋熟，歲晏林葉稀。禾黍積場圃，楂梨垂戶扉。", "野閑犬時吠，日暮牛自歸。時複落花酒，茅齋堪解衣。"]'),
('yuding-13','詠簾','萬楚','唐','御定全唐诗','yuding','','[]','玳瑁昔稱華，玲瓏薄絳紗。鉤銜門勢曲，節亂水紋斜。',48,'御定全唐詩/json/145.json','["玳瑁昔稱華，玲瓏薄絳紗。鉤銜門勢曲，節亂水紋斜。", "日弄長飛鳥，風搖不卷花。自當分內外，非是為驕奢。"]'),
('yuding-14','茱萸女','萬楚','唐','御定全唐诗','yuding','','[]','山陰柳家女，九日采茱萸。複得東鄰伴，雙為陌上姝。',84,'御定全唐詩/json/145.json','["山陰柳家女，九日采茱萸。複得東鄰伴，雙為陌上姝。", "插枝著高髻，結子置長裾。作性常遲緩，非關詫丈夫。", "平明折林樾，日入返城隅。俠客要羅袖，行人挑短書。", "蛾眉自有主，年少莫踟躕。"]'),
('yuding-15','五日觀妓','萬楚','唐','御定全唐诗','yuding','','[]','西施謾道浣春紗，碧玉今時鬥麗華。眉黛奪將萱草色，',40,'御定全唐詩/json/145.json','["西施謾道浣春紗，碧玉今時鬥麗華。眉黛奪將萱草色，", "誰道五絲能續命，卻令今日死君家。"]'),
('yuding-16','驄馬','萬楚','唐','御定全唐诗','yuding','','[]','金絡青驄白玉鞍，長鞭紫陌野遊盤。朝驅東道塵恒滅，',40,'御定全唐詩/json/145.json','["金絡青驄白玉鞍，長鞭紫陌野遊盤。朝驅東道塵恒滅，", "君能一飲長城窟，為報天山行路難。"]'),
('yuding-17','題情人藥欄','萬楚','唐','御定全唐诗','yuding','','[]','斂眉語芳草，何許太無情。正見離人別，春心相向生。',24,'御定全唐詩/json/145.json','["斂眉語芳草，何許太無情。正見離人別，春心相向生。"]'),
('yuding-18','河上逢落花','萬楚','唐','御定全唐诗','yuding','','[]','河水浮落花，花流東不息。應見浣紗人，為道長相憶。',24,'御定全唐詩/json/145.json','["河水浮落花，花流東不息。應見浣紗人，為道長相憶。"]'),
('yuding-19','甯王山池','範朝','唐','御定全唐诗','yuding','','[]','水勢臨階轉，峰形對路開。槎從天上得，石是海邊來。',48,'御定全唐詩/json/145.json','["水勢臨階轉，峰形對路開。槎從天上得，石是海邊來。", "瑞草分叢種，祥花間色栽。舊傳詞賦客，唯見有鄒枚。"]'),
('yuding-20','題石甕寺','範朝','唐','御定全唐诗','yuding','','[]','勝境宜長望，遲春好散愁。關連四塞起，河帶八川流。',48,'御定全唐詩/json/145.json','["勝境宜長望，遲春好散愁。關連四塞起，河帶八川流。", "複磴承香閣，重岩映彩樓。為臨溫液近，偏美聖君遊。"]'),
('yuding-21','田家','楊顏','唐','御定全唐诗','yuding','','[]','小園足生事，尋勝日傾壺。蒔蔬利於鬻，才青摘已無。',48,'御定全唐詩/json/145.json','["小園足生事，尋勝日傾壺。蒔蔬利於鬻，才青摘已無。", "四鄰依野竹，日夕采其枯。田家心適時，春色遍桑榆。"]'),
('yuding-22','後庭怨','王諲','唐','御定全唐诗','yuding','','[]','君不見紅閨少女端正時，夭夭桃李仙容姿。',115,'御定全唐詩/json/145.json','["君不見紅閨少女端正時，夭夭桃李仙容姿。", "幸得君王憐巧笑，披香殿裏薦蛾眉。蛾眉雙雙人共進，", "長信宮門閉不開，昭陽歌吹風送來。夢中魂魄猶言是，", "獨立每看斜日盡，孤眠直至殘燈死。秋日聞蟲翡翠簾，", "傳聞紈扇恩未歇，預想蛾眉上初月。如君貴偽不貴真，"]'),
('yuding-23','夜坐看搊箏','王諲','唐','御定全唐诗','yuding','','[]','調箏夜坐燈光裏，卻掛羅帷露纖指。朱弦一一聲不同，',40,'御定全唐詩/json/145.json','["調箏夜坐燈光裏，卻掛羅帷露纖指。朱弦一一聲不同，", "應是石家金穀裏，流傳未滿洛陽城。"]'),
('yuding-24','長信怨','王諲','唐','御定全唐诗','yuding','','[]','飛燕倚身輕，爭人巧笑名。生君棄妾意，增妾怨君情。',48,'御定全唐詩/json/145.json','["飛燕倚身輕，爭人巧笑名。生君棄妾意，增妾怨君情。", "日落昭陽壁，秋來長信城。寥寥金殿裏，歌吹夜無聲。"]'),
('yuding-25','閨情','王諲','唐','御定全唐诗','yuding','','[]','日暮裁縫歇，深嫌氣力微。才能收篋笥，懶起下簾帷。',48,'御定全唐詩/json/145.json','["日暮裁縫歇，深嫌氣力微。才能收篋笥，懶起下簾帷。", "怨坐空然燭，愁眠不解衣。昨來頻夢見，夫婿莫應知。"]'),
('yuding-26','十五夜觀燈','王諲','唐','御定全唐诗','yuding','','[]','暫得金吾夜，通看火樹春。停車傍明月，走馬入紅塵。',48,'御定全唐詩/json/145.json','["暫得金吾夜，通看火樹春。停車傍明月，走馬入紅塵。", "妓雜歌偏勝，場移舞更新。應須盡記取，說向不來人。"]'),
('yuding-27','除夜','王諲','唐','御定全唐诗','yuding','','[]','今歲今宵盡，明年明日催。寒隨一夜去，春逐五更來。',48,'御定全唐詩/json/145.json','["今歲今宵盡，明年明日催。寒隨一夜去，春逐五更來。", "氣色空中改，容顏暗裏回。風光人不覺，已著後園梅。"]'),
('yuding-28','聞漏','王嶽靈','唐','御定全唐诗','yuding','','[]','建禮含香處，重城待漏臣。徐聞傳鳳詔，曉唱辨雞人。',72,'御定全唐詩/json/145.json','["建禮含香處，重城待漏臣。徐聞傳鳳詔，曉唱辨雞人。", "銀箭殘將盡，銅壺漏更新。催籌當午夜，移刻及三辰。", "杳杳從天遠，泠泠出禁頻。直疑殘漏曙，肅肅對鉤陳。"]'),
('yuding-29','送沈芳謁李觀察求仕進','周萬','唐','御定全唐诗','yuding','','[]','往日長安路，歡遊不惜年。為貪盧女曲，用盡沈郎錢。',48,'御定全唐詩/json/145.json','["往日長安路，歡遊不惜年。為貪盧女曲，用盡沈郎錢。", "身老方投刺，途窮始著鞭。猶聞有知己，此去不徒然。"]'),
('yuding-0','古塞下曲','陶翰','唐','御定全唐诗','yuding','','[]','進軍飛狐北，窮寇勢將變。日落沙塵昏，背河更一戰。',72,'御定全唐詩/json/146.json','["進軍飛狐北，窮寇勢將變。日落沙塵昏，背河更一戰。", "騂馬黃金勒，雕弓白羽箭。射殺左賢王，歸奏未央殿。", "欲言塞下事，天子不召見。東出咸陽門，哀哀淚如霰。"]'),
('yuding-1','燕歌行','陶翰','唐','御定全唐诗','yuding','','[]','請君留楚調，聽我吟燕歌。家在遼水頭，邊風意氣多。',108,'御定全唐詩/json/146.json','["請君留楚調，聽我吟燕歌。家在遼水頭，邊風意氣多。", "出身為漢將，正值戎未和。雪中淩天山，冰上渡交河。", "大小百餘戰，封侯竟蹉跎。歸來灞陵下，故舊無相過。", "雄劍委塵匣，空門垂雀羅。玉簪還趙女，寶瑟付齊娥。", "昔日不為樂，時哉今奈何。"]'),
('yuding-2','望太華贈盧司倉','陶翰','唐','御定全唐诗','yuding','','[]','行吏到西華，乃觀三峰壯。削成元氣中，傑出天河上。',96,'御定全唐詩/json/146.json','["行吏到西華，乃觀三峰壯。削成元氣中，傑出天河上。", "如有飛動色，不知青冥狀。巨靈安在哉，厥跡猶可望。", "方此顧行旅，末由飭仙裝。蔥蘢記星壇，明滅數雲嶂。", "良友垂真契，宿心所微尚。敢投歸山吟，霞徑一相訪。"]'),
('yuding-3','贈鄭員外','陶翰','唐','御定全唐诗','yuding','','[]','驄馬拂繡裳，按兵遼水陽。西分雁門騎，北逐樓煩王。',120,'御定全唐詩/json/146.json','["驄馬拂繡裳，按兵遼水陽。西分雁門騎，北逐樓煩王。", "聞道五軍集，相邀百戰場。風沙暗天起，虜騎森已行。", "儒服揖諸將，雄謀吞大荒。金門來見謁，朱紱生輝光。", "數年侍御史，稍遷尚書郎。人生志氣立，所貴功業昌。", "何必守章句，終年事鉛黃。同時獻賦客，尚在東陵傍。"]'),
('yuding-4','贈房侍禦','陶翰','唐','御定全唐诗','yuding','','[]','志士固不羈，與道常周旋。進則天下仰，已之能晏然。',180,'御定全唐詩/json/146.json','["志士固不羈，與道常周旋。進則天下仰，已之能晏然。", "褐衣東府召，執簡南台先。雄義每特立，犯顏豈圖全。", "謫居東南遠，逸氣吟芳荃。適會寥廓趣，清波更夤緣。", "扁舟入五湖，發纜洞庭前。浩蕩臨海曲，迢遙濟江壖。", "征奇忽忘返，遇興將彌年。乃悟范生智，足明漁父賢。", "郡臨新安渚，佳賞此城偏。日夕對層岫，雲霞映晴川。", "閒居戀秋色，偃臥含貞堅。倚伏聊自化，行藏互推遷。", "君其振羽翮，歲晏將沖天。"]'),
('yuding-5','晚出伊闕寄河南裴中丞','陶翰','唐','御定全唐诗','yuding','','[]','退無偃息資，進無當代策。冉冉時將暮，坐為周南客。',108,'御定全唐詩/json/146.json','["退無偃息資，進無當代策。冉冉時將暮，坐為周南客。", "前登闕塞門，永眺伊城陌。長川黯已空，千里寒氣白。", "家本渭水西，異日同所適。秉志師禽尚，微言祖莊易。", "一辭林壑間，共系風塵役。交朋忽先進，天道何紛劇。", "豈念嘉遁時，依依偶沮溺。"]'),
('yuding-6','送朱大出關','陶翰','唐','御定全唐诗','yuding','','[]','楚客西上書，十年不得意。平生相知者，晚節心各異。',84,'御定全唐詩/json/146.json','["楚客西上書，十年不得意。平生相知者，晚節心各異。", "長揖五侯門，拂衣謝中貴。丈夫多別離，各有四方事。", "拔劍因高歌，蕭蕭北風至。故人有鬥酒，是夜共君醉。", "努力強加餐，當年莫相棄。"]'),
('yuding-7','宿天竺寺','陶翰','唐','御定全唐诗','yuding','','[]','松柏亂岩口，山西微徑通。天開一峰見，宮闕生虛空。',120,'御定全唐詩/json/146.json','["松柏亂岩口，山西微徑通。天開一峰見，宮闕生虛空。", "正殿倚霞壁，千樓標石叢。夜來猿鳥靜，鐘梵響雲中。", "岑翠映湖月，泉聲亂溪風。心超諸境外，了與懸解同。", "明發唯改視，朝日長崖東。湖色濃蕩漾，海光漸曈朦。", "葛仙跡尚在，許氏道猶崇。獨往古來事，幽懷期二公。"]'),
('yuding-8','出蕭關懷古','陶翰','唐','御定全唐诗','yuding','','[]','驅馬擊長劍，行役至蕭關。悠悠五原上，永眺關河前。',120,'御定全唐詩/json/146.json','["驅馬擊長劍，行役至蕭關。悠悠五原上，永眺關河前。", "北虜三十萬，此中常控弦。秦城亙宇宙，漢帝理旌旃。", "刁鬥鳴不息，羽書日夜傳。五軍計莫就，三策議空全。", "大漠橫萬里，蕭條絕人煙。孤城當瀚海，落日照祁連。", "愴矣苦寒奏，懷哉式微篇。更悲秦樓月，夜夜出胡天。"]'),
('yuding-9','南楚懷古','陶翰','唐','御定全唐诗','yuding','','[]','南國久蕪漫，我來空郁陶。君看章華宮，處處生黃蒿。',96,'御定全唐詩/json/146.json','["南國久蕪漫，我來空郁陶。君看章華宮，處處生黃蒿。", "但見陵與穀，豈知賢與豪。精魂托古木，寶玉捐江皋。", "倚棹下晴景，回舟隨晚濤。碧雲暮寥落，湖上秋天高。", "往事那堪問，此心徒自勞。獨餘湘水上，千載聞離騷。"]'),
('yuding-10','經殺子谷','陶翰','唐','御定全唐诗','yuding','','[]','扶蘇秦帝子，舉代稱其賢。百萬猶在握，可爭天下權。',72,'御定全唐詩/json/146.json','["扶蘇秦帝子，舉代稱其賢。百萬猶在握，可爭天下權。", "束身就一劍，壯志皆棄捐。塞下有遺跡，千齡人共傳。", "疏蕪盡荒草，寂曆空寒煙。到此盡垂淚，非我獨潸然。"]'),
('yuding-11','早過臨淮','陶翰','唐','御定全唐诗','yuding','','[]','夜來三渚風，晨過臨淮島。湖中海氣白，城上楚雲早。',84,'御定全唐詩/json/146.json','["夜來三渚風，晨過臨淮島。湖中海氣白，城上楚雲早。", "鱗鱗魚浦帆，漭漭蘆洲草。川路日浩蕩，惄焉心如搗。", "且言任倚伏，何暇念枯槁。範子名屢移，蘧公志常保。", "古人去已久，此理今難道。"]'),
('yuding-12','乘潮至漁浦作','陶翰','唐','御定全唐诗','yuding','','[]','艤棹乘早潮，潮來如風雨。樟台忽已隱，界峰莫及睹。',97,'御定全唐詩/json/146.json','["艤棹乘早潮，潮來如風雨。樟台忽已隱，界峰莫及睹。", "崩騰心為失，浩蕩目無主。豗cI浪始聞，漾漾入魚浦。", "雲景共澄霽，江山相吞吐。偉哉造化工，此事從終古。", "流沫誠足誡，商歌調易若。頗因忠信全，客心猶栩栩。"]'),
('yuding-13','秋山夕興','陶翰','唐','御定全唐诗','yuding','','[]','山月松筱下，月明山景鮮。聊為高秋酌，複此清夜弦。',48,'御定全唐詩/json/146.json','["山月松筱下，月明山景鮮。聊為高秋酌，複此清夜弦。", "晤語方獲志，棲心亦彌年。尚言興未逸，更理逍遙篇。"]'),
('yuding-14','送集賢學士伊闕史少府敕放歸江東覲省','陶翰','唐','御定全唐诗','yuding','','[]','墨客鐘張侶，材高吳越珍。千門來謁帝，駟馬去榮親。',48,'御定全唐詩/json/146.json','["墨客鐘張侶，材高吳越珍。千門來謁帝，駟馬去榮親。", "吏邑沿清洛，鄉山指白蘋。歸期應不遠，當及未央春。"]'),
('yuding-15','送金卿歸新羅','陶翰','唐','御定全唐诗','yuding','','[]','奉義朝中國，殊恩及遠臣。鄉心遙渡海，客路再經春。',72,'御定全唐詩/json/146.json','["奉義朝中國，殊恩及遠臣。鄉心遙渡海，客路再經春。", "落日誰同望，孤舟獨可親。拂波銜木鳥，偶宿泣珠人。", "禮樂夷風變，衣冠漢制新。青雲已幹呂，知汝重來賓。"]'),
('yuding-16','柳陌聽早鶯','陶翰','唐','御定全唐诗','yuding','','[]','忽來枝上囀，還似穀中聲。乍使香閨靜，偏傷遠客情。',72,'御定全唐詩/json/146.json','["忽來枝上囀，還似穀中聲。乍使香閨靜，偏傷遠客情。", "間關難辨處，斷續若頻驚。玉勒留將久，青樓夢不成。", "千門候曉發，萬井報春生。徒有知音賞，慚非皋鶴鳴。"]'),
('yuding-0','逢雪宿芙蓉山主人','劉長卿','唐','御定全唐诗','yuding','','[]','日暮蒼山遠，天寒白屋貧。柴門聞犬吠，風雪夜歸人。',24,'御定全唐詩/json/147.json','["日暮蒼山遠，天寒白屋貧。柴門聞犬吠，風雪夜歸人。"]'),
('yuding-1','送張起、崔載華之閩中','劉長卿','唐','御定全唐诗','yuding','','[]','朝無寒士達，家在舊山貧。相送天涯裏，憐君更遠人。',24,'御定全唐詩/json/147.json','["朝無寒士達，家在舊山貧。相送天涯裏，憐君更遠人。"]'),
('yuding-2','贈秦系征君','劉長卿','唐','御定全唐诗','yuding','','[]','群公誰讓位，五柳獨知貧。惆悵青山路，煙霞老此人。',24,'御定全唐詩/json/147.json','["群公誰讓位，五柳獨知貧。惆悵青山路，煙霞老此人。"]'),
('yuding-3','秦系頃以家事獲謗因出舊山每荷觀察崔公見知欲歸未遂感其流寓詩以贈之','劉長卿','唐','御定全唐诗','yuding','','[]','初迷武陵路，複出孟嘗門。回首江南岸，青山與舊恩。',24,'御定全唐詩/json/147.json','["初迷武陵路，複出孟嘗門。回首江南岸，青山與舊恩。"]'),
('yuding-4','夜中對雪贈秦系，時秦初與謝氏離婚，謝氏在越','劉長卿','唐','御定全唐诗','yuding','','[]','月明花滿地，君自憶山陰。誰遣因風起，紛紛亂此心。',24,'御定全唐詩/json/147.json','["月明花滿地，君自憶山陰。誰遣因風起，紛紛亂此心。"]'),
('yuding-5','湘妃','劉長卿','唐','御定全唐诗','yuding','','[]','帝子不可見，秋風來暮思。嬋娟湘江月，千載空蛾眉。',24,'御定全唐詩/json/147.json','["帝子不可見，秋風來暮思。嬋娟湘江月，千載空蛾眉。"]'),
('yuding-6','斑竹','劉長卿','唐','御定全唐诗','yuding','','[]','蒼梧千載後，斑竹對湘沅。欲識湘妃怨，枝枝滿淚痕。',24,'御定全唐詩/json/147.json','["蒼梧千載後，斑竹對湘沅。欲識湘妃怨，枝枝滿淚痕。"]'),
('yuding-7','春草宮懷古','劉長卿','唐','御定全唐诗','yuding','','[]','君王不可見，芳草舊宮春。猶帶羅裙色，青青向楚人。',24,'御定全唐詩/json/147.json','["君王不可見，芳草舊宮春。猶帶羅裙色，青青向楚人。"]'),
('yuding-8','正朝覽鏡作','劉長卿','唐','御定全唐诗','yuding','','[]','憔悴逢新歲，茅扉見舊春。朝來明鏡裏，不忍白頭人。',24,'御定全唐詩/json/147.json','["憔悴逢新歲，茅扉見舊春。朝來明鏡裏，不忍白頭人。"]'),
('yuding-9','瓜洲道中送李端公南渡後，歸揚州道中寄','劉長卿','唐','御定全唐诗','yuding','','[]','片帆何處去，匹馬獨歸遲。惆悵江南北，青山欲暮時。',24,'御定全唐詩/json/147.json','["片帆何處去，匹馬獨歸遲。惆悵江南北，青山欲暮時。"]'),
('yuding-10','送張十八歸桐廬','劉長卿','唐','御定全唐诗','yuding','','[]','歸人乘野艇，帶月過江村。正落寒潮水，相隨夜到門。',24,'御定全唐詩/json/147.json','["歸人乘野艇，帶月過江村。正落寒潮水，相隨夜到門。"]'),
('yuding-11','過白鶴觀尋岑秀才不遇','劉長卿','唐','御定全唐诗','yuding','','[]','不知方外客，何事鎖空房。應向桃源裏，教他喚阮郎。',24,'御定全唐詩/json/147.json','["不知方外客，何事鎖空房。應向桃源裏，教他喚阮郎。"]'),
('yuding-12','聽彈琴','劉長卿','唐','御定全唐诗','yuding','','[]','泠泠七絲上，靜聽松風寒。古調雖自愛，今人多不彈。',24,'御定全唐詩/json/147.json','["泠泠七絲上，靜聽松風寒。古調雖自愛，今人多不彈。"]'),
('yuding-13','游南園，偶見在陰牆下葵，因以成詠','劉長卿','唐','御定全唐诗','yuding','','[]','此地常無日，青青獨在陰。太陽偏不及，非是未傾心。',24,'御定全唐詩/json/147.json','["此地常無日，青青獨在陰。太陽偏不及，非是未傾心。"]'),
('yuding-14','入百丈澗見桃花晚開','劉長卿','唐','御定全唐诗','yuding','','[]','百丈深澗裏，過時花欲妍。應緣地勢下，遂使春風偏。',24,'御定全唐詩/json/147.json','["百丈深澗裏，過時花欲妍。應緣地勢下，遂使春風偏。"]'),
('yuding-15','送子婿崔真甫、李穆往揚州四首','劉長卿','唐','御定全唐诗','yuding','','[]','渡口發梅花，山中動泉脈。蕪城春草生，君作揚州客。',96,'御定全唐詩/json/147.json','["渡口發梅花，山中動泉脈。蕪城春草生，君作揚州客。", "半邏鶯滿樹，新年人獨遠。落花逐流水，共到茱萸灣。", "雁還空渚在，人去落潮翻。臨水獨揮手，殘陽歸掩門。", "狎鳥攜稚子，釣魚終老身。殷勤囑歸客，莫話桃源人。"]'),
('yuding-16','寄龍山道士許法棱','劉長卿','唐','御定全唐诗','yuding','','[]','悠悠白雲裏，獨住青山客。林下晝焚香，桂花同寂寂。',24,'御定全唐詩/json/147.json','["悠悠白雲裏，獨住青山客。林下晝焚香，桂花同寂寂。"]'),
('yuding-17','送方外上人','劉長卿','唐','御定全唐诗','yuding','','[]','孤雲將野鶴，豈向人間住。莫買沃洲山，時人已知處。',24,'御定全唐詩/json/147.json','["孤雲將野鶴，豈向人間住。莫買沃洲山，時人已知處。"]'),
('yuding-18','送靈澈上人','劉長卿','唐','御定全唐诗','yuding','','[]','蒼蒼竹林寺，杳杳鐘聲晚。荷笠帶夕陽，青山獨歸遠。',24,'御定全唐詩/json/147.json','["蒼蒼竹林寺，杳杳鐘聲晚。荷笠帶夕陽，青山獨歸遠。"]'),
('yuding-19','茱萸灣北答崔載華問','劉長卿','唐','御定全唐诗','yuding','','[]','荒涼野店絕，迢遞人煙遠。蒼蒼古木中，多是隋家苑。',24,'御定全唐詩/json/147.json','["荒涼野店絕，迢遞人煙遠。蒼蒼古木中，多是隋家苑。"]'),
('yuding-20','赴楚州次自田途中阻淺，問張南史','劉長卿','唐','御定全唐诗','yuding','','[]','楚城今近遠，積靄寒塘暮。水淺舟且遲，淮潮至何處。',24,'御定全唐詩/json/147.json','["楚城今近遠，積靄寒塘暮。水淺舟且遲，淮潮至何處。"]'),
('yuding-21','江中對月','劉長卿','唐','御定全唐诗','yuding','','[]','空洲夕煙斂，望月秋江裏。歷歷沙上人，月中孤渡水。',24,'御定全唐詩/json/147.json','["空洲夕煙斂，望月秋江裏。歷歷沙上人，月中孤渡水。"]'),
('yuding-22','碧澗別墅喜皇甫侍禦相訪','劉長卿','唐','御定全唐诗','yuding','','[]','荒村帶返照，落葉亂紛紛。古路無行客，寒山獨見君。',48,'御定全唐詩/json/147.json','["荒村帶返照，落葉亂紛紛。古路無行客，寒山獨見君。", "野橋經雨斷，澗水向田分。不為憐同病，何人到白雲。"]'),
('yuding-23','初到碧澗招明契上人','劉長卿','唐','御定全唐诗','yuding','','[]','漸老知身累，初寒曝背眠。白雲留永日，黃葉減餘年。',48,'御定全唐詩/json/147.json','["漸老知身累，初寒曝背眠。白雲留永日，黃葉減餘年。", "猿護窗前樹，泉澆谷後田。沃洲能共隱，不用道林錢。"]'),
('yuding-24','送少微上人游天臺','劉長卿','唐','御定全唐诗','yuding','','[]','石橋人不到，獨往更迢迢。乞食山家少，尋鐘野路遙。',48,'御定全唐詩/json/147.json','["石橋人不到，獨往更迢迢。乞食山家少，尋鐘野路遙。", "松門風自掃，瀑布雪難消。秋夜聞清梵，餘音逐海潮。"]'),
('yuding-25','卻歸睦州至七裏灘下作','劉長卿','唐','御定全唐诗','yuding','','[]','南歸猶謫宦，獨上子陵灘。江樹臨洲晚，沙禽對水寒。',48,'御定全唐詩/json/147.json','["南歸猶謫宦，獨上子陵灘。江樹臨洲晚，沙禽對水寒。", "山開斜照在，石淺亂流難。惆悵梅花發，年年此地看。"]'),
('yuding-26','對酒寄嚴維','劉長卿','唐','御定全唐诗','yuding','','[]','陋巷喜陽和，衰顏對酒歌。懶從華髮亂，閑任白雲多。',48,'御定全唐詩/json/147.json','["陋巷喜陽和，衰顏對酒歌。懶從華髮亂，閑任白雲多。", "郡簡容垂釣，家貧學弄梭。門前七裏瀨，早晚子陵過。"]'),
('yuding-27','新年作','劉長卿','唐','御定全唐诗','yuding','','[]','鄉心新歲切，天畔獨潸然。老至居人下，春歸在客先。',48,'御定全唐詩/json/147.json','["鄉心新歲切，天畔獨潸然。老至居人下，春歸在客先。", "嶺猿同旦暮，江柳共風煙。已似長沙傅，從今又幾年。"]'),
('yuding-28','朱放自杭州與故里相使君立碑回因以奉簡吏部楊侍郎制文','劉長卿','唐','御定全唐诗','yuding','','[]','片石羊公後，淒涼江水濱。好辭千古事，墮淚萬家人。',48,'御定全唐詩/json/147.json','["片石羊公後，淒涼江水濱。好辭千古事，墮淚萬家人。", "鵩集占書久，鸞回刻篆新。不堪相顧恨，文字日生塵。"]'),
('yuding-29','送宣尊師醮畢歸越','劉長卿','唐','御定全唐诗','yuding','','[]','吹簫江上晚，惆悵別茅君。踏火能飛雪，登刀入白雲。',48,'御定全唐詩/json/147.json','["吹簫江上晚，惆悵別茅君。踏火能飛雪，登刀入白雲。", "晨香長日在，夜磬滿山聞。揮手桐溪路，無情水亦分。"]'),
('yuding-30','送裴使君赴荊南充行軍司馬','劉長卿','唐','御定全唐诗','yuding','','[]','盛府南門寄，前程積水中。月明臨夏口，山晚望巴東。',48,'御定全唐詩/json/147.json','["盛府南門寄，前程積水中。月明臨夏口，山晚望巴東。", "故節辭江郡，寒笳發渚宮。漢川風景好，遙羨逐羊公。"]'),
('yuding-31','送裴郎中貶吉州','劉長卿','唐','御定全唐诗','yuding','','[]','亂軍交白刃，一騎出黃塵。漢節同歸闕，江帆共逐臣。',48,'御定全唐詩/json/147.json','["亂軍交白刃，一騎出黃塵。漢節同歸闕，江帆共逐臣。", "猿愁歧路晚，梅作異方春。知己酂侯在，應憐脫粟人。"]'),
('yuding-32','酬皇甫侍禦見寄，時前相國姑臧公初臨郡','劉長卿','唐','御定全唐诗','yuding','','[]','離別江南北，汀洲葉再黃。路遙雲共水，砧迥月如霜。',48,'御定全唐詩/json/147.json','["離別江南北，汀洲葉再黃。路遙雲共水，砧迥月如霜。", "歲儉依仁政，年衰憶故鄉。佇看宣室召，漢法倚張綱。"]'),
('yuding-33','月下呈章秀才','劉長卿','唐','御定全唐诗','yuding','','[]','自古悲搖落，誰人奈此何。夜蛩偏傍枕，寒鳥數移柯。',48,'御定全唐詩/json/147.json','["自古悲搖落，誰人奈此何。夜蛩偏傍枕，寒鳥數移柯。", "向老三年謫，當秋百感多。家貧惟好月，空愧子猷過。"]'),
('yuding-34','酬張夏','劉長卿','唐','御定全唐诗','yuding','','[]','幾歲依窮海，頹年惜故陰。劍寒空有氣，松老欲無心。',48,'御定全唐詩/json/147.json','["幾歲依窮海，頹年惜故陰。劍寒空有氣，松老欲無心。", "玩雪勞相訪，看山正獨吟。孤舟且莫去，前路水雲深。"]'),
('yuding-35','送李使君貶連州','劉長卿','唐','御定全唐诗','yuding','','[]','獨過長沙去，誰堪此路愁。秋風散千騎，寒雨泊孤舟。',48,'御定全唐詩/json/147.json','["獨過長沙去，誰堪此路愁。秋風散千騎，寒雨泊孤舟。", "賈誼辭明主，蕭何識故侯。漢廷當自召，湘水但空流。"]'),
('yuding-36','秋夜北山精舍觀體如師梵','劉長卿','唐','御定全唐诗','yuding','','[]','焚香奏仙唄，向夕遍空山。清切兼秋遠，威儀對月閑。',48,'御定全唐詩/json/147.json','["焚香奏仙唄，向夕遍空山。清切兼秋遠，威儀對月閑。", "靜分岩響答，散逐海潮還。幸得風吹去，隨人到世間。"]'),
('yuding-37','酬張夏雪夜赴州訪別途中苦寒作','劉長卿','唐','御定全唐诗','yuding','','[]','扁舟乘興客，不憚苦寒行。晚暮相依分，江潮欲別情。',48,'御定全唐詩/json/147.json','["扁舟乘興客，不憚苦寒行。晚暮相依分，江潮欲別情。", "水聲冰下嚥，砂路雪中平。舊劍鋒芒盡，應嫌贈脫輕。"]'),
('yuding-38','尋洪尊師不遇','劉長卿','唐','御定全唐诗','yuding','','[]','古木無人地，來尋羽客家。道書堆玉案，仙帔疊青霞。',48,'御定全唐詩/json/147.json','["古木無人地，來尋羽客家。道書堆玉案，仙帔疊青霞。", "鶴老難知歲，梅寒未作花。山中不相見，何處化丹砂。"]'),
('yuding-39','喜鮑禪師自龍山至','劉長卿','唐','御定全唐诗','yuding','','[]','故居何日下，春草欲芊芊。猶對山中月，誰聽石上泉。',48,'御定全唐詩/json/147.json','["故居何日下，春草欲芊芊。猶對山中月，誰聽石上泉。", "猿聲知後夜，花發見流年。杖錫閑來往，無心到處禪。"]'),
('yuding-40','送方外上人之常州依蕭使君','劉長卿','唐','御定全唐诗','yuding','','[]','宰臣思得度，鷗鳥戀為群。遠客回飛錫，空山臥白雲。',48,'御定全唐詩/json/147.json','["宰臣思得度，鷗鳥戀為群。遠客回飛錫，空山臥白雲。", "夕陽孤艇去，秋水兩溪分。歸共臨川史，同翻貝葉文。"]'),
('yuding-41','宿北山禪寺蘭若','劉長卿','唐','御定全唐诗','yuding','','[]','上方鳴夕磬，林下一僧還。密行傳人少，禪心對虎閑。',48,'御定全唐詩/json/147.json','["上方鳴夕磬，林下一僧還。密行傳人少，禪心對虎閑。", "青松臨古路，白月滿寒山。舊識窗前桂，經霜更待攀。"]'),
('yuding-42','赴新安別梁侍郎','劉長卿','唐','御定全唐诗','yuding','','[]','新安君莫問，此路水雲深。江海無行跡，孤舟何處尋。',48,'御定全唐詩/json/147.json','["新安君莫問，此路水雲深。江海無行跡，孤舟何處尋。", "青山空向淚，白月豈知心。縱有餘生在，終傷老病侵。"]'),
('yuding-43','江州留別薛六、柳八二員外','劉長卿','唐','御定全唐诗','yuding','','[]','江海相逢少，東南別處長。獨行風嫋嫋，相去水茫茫。',48,'御定全唐詩/json/147.json','["江海相逢少，東南別處長。獨行風嫋嫋，相去水茫茫。", "白首辭同舍，青山背故鄉。離心與潮信，每日到潯陽。"]'),
('yuding-44','和州留別穆郎中','劉長卿','唐','御定全唐诗','yuding','','[]','播遷悲遠道，搖落感衰容。今日猶多難，何年更此逢。',48,'御定全唐詩/json/147.json','["播遷悲遠道，搖落感衰容。今日猶多難，何年更此逢。", "世交黃葉散，鄉路白雲重。明發看煙樹，唯聞江北鐘。"]'),
('yuding-45','和州送人歸複郢','劉長卿','唐','御定全唐诗','yuding','','[]','因家漢水曲，相送掩柴扉。故郢生秋草，寒江澹落暉。',48,'御定全唐詩/json/147.json','["因家漢水曲，相送掩柴扉。故郢生秋草，寒江澹落暉。", "綠林行客少，赤壁住人稀。獨過潯陽去，潮歸人不歸。"]'),
('yuding-46','送金昌宗歸錢塘','劉長卿','唐','御定全唐诗','yuding','','[]','新家浙江上，獨泛落潮歸。秋水照華髮，涼風生褐衣。',48,'御定全唐詩/json/147.json','["新家浙江上，獨泛落潮歸。秋水照華髮，涼風生褐衣。", "柴門嘶馬少，藜杖拜人稀。惟有陶潛柳，蕭條對掩扉。"]'),
('yuding-47','酬張夏別後道中見寄','劉長卿','唐','御定全唐诗','yuding','','[]','離群方歲晏，謫宦在天涯。暮雪同行少，寒潮欲上遲。',48,'御定全唐詩/json/147.json','["離群方歲晏，謫宦在天涯。暮雪同行少，寒潮欲上遲。", "海鷗知吏傲，砂鶴見人衰。只畏生秋草，西歸亦未期。"]'),
('yuding-48','新安奉送穆諭德歸朝，賦得行字','劉長卿','唐','御定全唐诗','yuding','','[]','九重宣室召，萬里建溪行。事直皇天在，歸遲白髮生。',48,'御定全唐詩/json/147.json','["九重宣室召，萬里建溪行。事直皇天在，歸遲白髮生。", "用材身複起，睹聖眼猶明。離別寒江上，潺湲若有情。"]'),
('yuding-49','偶然作','劉長卿','唐','御定全唐诗','yuding','','[]','野寺長依止，田家或往還。老農開古地，夕鳥入寒山。',48,'御定全唐詩/json/147.json','["野寺長依止，田家或往還。老農開古地，夕鳥入寒山。", "書劍身同廢，煙霞吏共閑。豈能將白髮，扶杖出人間。"]'),
('yuding-50','送州人孫沅自本州卻歸句章新營所居','劉長卿','唐','御定全唐诗','yuding','','[]','故里歸成客，新家去未安。詩書滿蝸舍，徵稅及漁竿。',48,'御定全唐詩/json/147.json','["故里歸成客，新家去未安。詩書滿蝸舍，徵稅及漁竿。", "火種山田薄，星居海島寒。憐君不得已，步步別離難。"]'),
('yuding-51','送李員外使還蘇州兼呈前袁州李使君賦得長字袁州即員外之從兄','劉長卿','唐','御定全唐诗','yuding','','[]','別離共成怨，衰老更難忘。夜月留同舍，秋風在遠鄉。',48,'御定全唐詩/json/147.json','["別離共成怨，衰老更難忘。夜月留同舍，秋風在遠鄉。", "朱弦徐向燭，白髮強臨觴。歸獻西陵作，誰知此路長。"]'),
('yuding-52','酬李員外從崔錄事載華宿三河戍先見寄','劉長卿','唐','御定全唐诗','yuding','','[]','寒江鳴石瀨，歸客夜初分。人語空山答，猿聲獨戍聞。',48,'御定全唐詩/json/147.json','["寒江鳴石瀨，歸客夜初分。人語空山答，猿聲獨戍聞。", "遲來朝及暮，愁去水連雲。歲晚心誰在，青山見此君。"]'),
('yuding-53','見秦系離婚後出山居作','劉長卿','唐','御定全唐诗','yuding','','[]','豈知偕老重，垂老絕良姻。郗氏誠難負，朱家自愧貧。',48,'御定全唐詩/json/147.json','["豈知偕老重，垂老絕良姻。郗氏誠難負，朱家自愧貧。", "綻衣留欲故，織錦罷經春。何況蘼蕪綠，空山不見人。"]'),
('yuding-54','酬秦系','劉長卿','唐','御定全唐诗','yuding','','[]','鶴書猶未至，那出白雲來。舊路經年別，寒潮每日回。',48,'御定全唐詩/json/147.json','["鶴書猶未至，那出白雲來。舊路經年別，寒潮每日回。", "家空歸海燕，人老發江梅。最憶門前柳，閒居手自栽。"]'),
('yuding-55','歲日作','劉長卿','唐','御定全唐诗','yuding','','[]','建寅回北斗，看曆占春風。律變滄江外，年加白髮中。',48,'御定全唐詩/json/147.json','["建寅回北斗，看曆占春風。律變滄江外，年加白髮中。", "春衣試稚子，壽酒勸衰翁。今日陽和發，榮枯豈不同。"]'),
('yuding-56','題元錄事開元所居','劉長卿','唐','御定全唐诗','yuding','','[]','幽居蘿薜情，高臥紀綱行。鳥散秋鷹下，人閑春草生。',48,'御定全唐詩/json/147.json','["幽居蘿薜情，高臥紀綱行。鳥散秋鷹下，人閑春草生。", "冒風歸野寺，收印出山城。今日新安郡，因君水更清。"]'),
('yuding-57','送崔載華、張起之閩中','劉長卿','唐','御定全唐诗','yuding','','[]','不識閩中路，遙知別後心。猿聲入嶺切，鳥道問人深。',48,'御定全唐詩/json/147.json','["不識閩中路，遙知別後心。猿聲入嶺切，鳥道問人深。", "旅食過夷落，方言會越音。西征開幕府，早晚用陳琳。"]'),
('yuding-58','送張司直赴嶺南謁張尚書','劉長卿','唐','御定全唐诗','yuding','','[]','番禺萬里路，遠客片帆過。盛府依橫海，荒祠拜伏波。',48,'御定全唐詩/json/147.json','["番禺萬里路，遠客片帆過。盛府依橫海，荒祠拜伏波。", "人經秋瘴變，鳥墜火雲多。誠憚炎洲裏，無如一顧何。"]'),
('yuding-59','寄會稽公徐侍郎','劉長卿','唐','御定全唐诗','yuding','','[]','搖落淮南葉，秋風想越吟。鄒枚入梁苑，逸少在山陰。',48,'御定全唐詩/json/147.json','["搖落淮南葉，秋風想越吟。鄒枚入梁苑，逸少在山陰。", "老鶴無衰貌，寒松有本心。聖朝難稅駕，惆悵白雲深。"]'),
('yuding-60','送朱山人放越州，賊退後歸山陰別業','劉長卿','唐','御定全唐诗','yuding','','[]','越州初罷戰，江上送歸橈。南渡無來客，西陵自落潮。',48,'御定全唐詩/json/147.json','["越州初罷戰，江上送歸橈。南渡無來客，西陵自落潮。", "空城垂故柳，舊業廢春苗。閭裏相逢少，鶯花共寂寥。"]'),
('yuding-61','秋夜肅公房喜普門上人自陽羨山至','劉長卿','唐','御定全唐诗','yuding','','[]','山棲久不見，林下偶同遊。早晚來香積，何人住沃洲。',48,'御定全唐詩/json/147.json','["山棲久不見，林下偶同遊。早晚來香積，何人住沃洲。", "寒禽驚後夜，古木帶高秋。卻入千峰去，孤雲不可留。"]'),
('yuding-62','送李秘書卻赴南中','劉長卿','唐','御定全唐诗','yuding','','[]','卻到番禺日，應傷昔所依。炎洲百口住，故國幾人歸。',48,'御定全唐詩/json/147.json','["卻到番禺日，應傷昔所依。炎洲百口住，故國幾人歸。", "路識梅花在，家存棣萼稀。獨逢回雁去，猶作舊行飛。"]'),
('yuding-63','過前安宜張明府郊居','劉長卿','唐','御定全唐诗','yuding','','[]','寂寥東郭外，白首一先生。解印孤琴在，移家五柳成。',48,'御定全唐詩/json/147.json','["寂寥東郭外，白首一先生。解印孤琴在，移家五柳成。", "夕陽臨水釣，春雨向田耕。終日空林下，何人識此情。"]'),
('yuding-64','使回次楊柳過元八所居','劉長卿','唐','御定全唐诗','yuding','','[]','君家楊柳渡，來往落帆過。綠竹經寒在，青山欲暮多。',48,'御定全唐詩/json/147.json','["君家楊柳渡，來往落帆過。綠竹經寒在，青山欲暮多。", "薜蘿誠可戀，婚嫁複如何。無奈閑門外，漁翁夜夜歌。"]'),
('yuding-65','送李侍禦貶郴州','劉長卿','唐','御定全唐诗','yuding','','[]','洞庭波渺渺，君去吊靈均。幾路三湘水，全家萬里人。',48,'御定全唐詩/json/147.json','["洞庭波渺渺，君去吊靈均。幾路三湘水，全家萬里人。", "聽猿明月夜，看柳故年春。憶想汀洲畔，傷心向白蘋。"]'),
('yuding-66','寄普門上人','劉長卿','唐','御定全唐诗','yuding','','[]','白雲幽臥處，不向世人傳。聞在千峰裏，心知獨夜禪。',48,'御定全唐詩/json/147.json','["白雲幽臥處，不向世人傳。聞在千峰裏，心知獨夜禪。", "辛勤羞薄祿，依止愛閒田。惆悵王孫草，青青又一年。"]'),
('yuding-67','逢郴州使，因寄鄭協律','劉長卿','唐','御定全唐诗','yuding','','[]','相思楚天外，夢寐楚猿吟。更落淮南葉，難為江上心。',48,'御定全唐詩/json/147.json','["相思楚天外，夢寐楚猿吟。更落淮南葉，難為江上心。", "衡陽問人遠，湘水向君深。欲逐孤帆去，茫茫何處尋。"]'),
('yuding-68','岳陽館中望洞庭湖','劉長卿','唐','御定全唐诗','yuding','','[]','萬古巴丘戍，平湖此望長。問人何淼淼，愁暮更蒼蒼。',48,'御定全唐詩/json/147.json','["萬古巴丘戍，平湖此望長。問人何淼淼，愁暮更蒼蒼。", "疊浪浮元氣，中流沒太陽。孤舟有歸客，早晚達瀟湘。"]'),
('yuding-69','巡去岳陽卻歸鄂州使院留別鄭洵侍禦侍禦先曾謫居此州','劉長卿','唐','御定全唐诗','yuding','','[]','何事長沙謫，相逢楚水秋。暮帆歸夏口，寒雨對巴丘。',48,'御定全唐詩/json/147.json','["何事長沙謫，相逢楚水秋。暮帆歸夏口，寒雨對巴丘。", "帝子椒漿奠，騷人木葉愁。惟憐萬里外，離別洞庭頭。"]'),
('yuding-70','夏口送屈突司直使湖南','劉長卿','唐','御定全唐诗','yuding','','[]','共悲來夏口，何事更南征。霧露行人少，瀟湘春草生。',48,'御定全唐詩/json/147.json','["共悲來夏口，何事更南征。霧露行人少，瀟湘春草生。", "鶯啼何處夢，猿嘯若為聲。風月新年好，悠悠遠客情。"]'),
('yuding-71','代邊將有懷','劉長卿','唐','御定全唐诗','yuding','','[]','少年辭魏闕，白首向沙場。瘦馬戀秋草，征人思故鄉。',48,'御定全唐詩/json/147.json','["少年辭魏闕，白首向沙場。瘦馬戀秋草，征人思故鄉。", "暮笳吹塞月，曉甲帶胡霜。自到雲中郡，於今百戰強。"]'),
('yuding-72','雨中過員稷巴陵山居贈別','劉長卿','唐','御定全唐诗','yuding','','[]','憐君洞庭上，白髮向人垂。積雨悲幽獨，長江對別離。',48,'御定全唐詩/json/147.json','["憐君洞庭上，白髮向人垂。積雨悲幽獨，長江對別離。", "牛羊歸故道，猿鳥聚寒枝。明發遙相望，雲山不可知。"]'),
('yuding-73','送李中丞之襄州','劉長卿','唐','御定全唐诗','yuding','','[]','流落征南將，曾驅十萬師。罷歸無舊業，老去戀明時。',48,'御定全唐詩/json/147.json','["流落征南將，曾驅十萬師。罷歸無舊業，老去戀明時。", "獨立三朝識，輕生一劍知。茫茫漢江上，日暮複何之。"]'),
('yuding-74','奉使至申州，傷經陷沒','劉長卿','唐','御定全唐诗','yuding','','[]','舉目傷蕪沒，何年此戰爭。歸人失舊裏，老將守孤城。',48,'御定全唐詩/json/147.json','["舉目傷蕪沒，何年此戰爭。歸人失舊裏，老將守孤城。", "廢戍山煙出，荒田野火行。獨憐溮水上，時亂亦能清。"]'),
('yuding-75','穆陵關北逢人歸漁陽','劉長卿','唐','御定全唐诗','yuding','','[]','逢君穆陵路，匹馬向桑幹。楚國蒼山古，幽州白日寒。',48,'御定全唐詩/json/147.json','["逢君穆陵路，匹馬向桑幹。楚國蒼山古，幽州白日寒。", "城池百戰後，耆舊幾家殘。處處蓬蒿遍，歸人掩淚看。"]'),
('yuding-76','安州道中經滻水有懷','劉長卿','唐','御定全唐诗','yuding','','[]','征途逢滻水，忽似到秦川。借問朝天處，猶看落日邊。',48,'御定全唐詩/json/147.json','["征途逢滻水，忽似到秦川。借問朝天處，猶看落日邊。", "映沙晴漾漾，出澗夜濺濺。欲寄西歸恨，微波不可傳。"]'),
('yuding-77','步登夏口古城作','劉長卿','唐','御定全唐诗','yuding','','[]','平蕪連古堞，遠客此沾衣。高樹朝光上，空城秋氣歸。',48,'御定全唐詩/json/147.json','["平蕪連古堞，遠客此沾衣。高樹朝光上，空城秋氣歸。", "微明漢水極，搖落楚人稀。但見荒郊外，寒鴉暮暮飛。"]'),
('yuding-78','贈別盧司直之閩中','劉長卿','唐','御定全唐诗','yuding','','[]','爾來多不見，此去又何之。華髮同今日，流芳似舊時。',48,'御定全唐詩/json/147.json','["爾來多不見，此去又何之。華髮同今日，流芳似舊時。", "洲長春色遍，漢廣夕陽遲。歲歲王孫草，空憐無處期。"]'),
('yuding-79','酬郭夏人日長沙感懷見贈','劉長卿','唐','御定全唐诗','yuding','','[]','舊俗歡猶在，憐君恨獨深。新年向國淚，今日倚門心。',48,'御定全唐詩/json/147.json','["舊俗歡猶在，憐君恨獨深。新年向國淚，今日倚門心。", "歲去隨湘水，春生近桂林。流鶯且莫弄，江畔正行吟。"]'),
('yuding-80','赴巴南書情寄故人','劉長卿','唐','御定全唐诗','yuding','','[]','南過三湘去，巴人此路偏。謫居秋瘴裏，歸處夕陽邊。',48,'御定全唐詩/json/147.json','["南過三湘去，巴人此路偏。謫居秋瘴裏，歸處夕陽邊。", "直道天何在，愁容鏡亦憐。裁書欲誰訴，無淚可潸然。"]'),
('yuding-81','餘幹旅舍','劉長卿','唐','御定全唐诗','yuding','','[]','搖落暮天迥，青楓霜葉稀。孤城向水閉，獨鳥背人飛。',48,'御定全唐詩/json/147.json','["搖落暮天迥，青楓霜葉稀。孤城向水閉，獨鳥背人飛。", "渡口月初上，鄰家漁未歸。鄉心正欲絕，何處搗寒衣。"]'),
('yuding-82','登思禪寺上方題修竹茂松','劉長卿','唐','御定全唐诗','yuding','','[]','上方幽且暮，台殿隱蒙籠。遠磬秋山裏，清猿古木中。',48,'御定全唐詩/json/147.json','["上方幽且暮，台殿隱蒙籠。遠磬秋山裏，清猿古木中。", "眾溪連竹路，諸嶺共松風。儻許棲林下，甘成白首翁。"]'),
('yuding-83','恩敕重推使牒追赴蘇州，次前溪館作','劉長卿','唐','御定全唐诗','yuding','','[]','漸入雲峰裏，愁看驛路閑。亂鴉投落日，疲馬向空山。',48,'御定全唐詩/json/147.json','["漸入雲峰裏，愁看驛路閑。亂鴉投落日，疲馬向空山。", "且喜憐非罪，何心戀末班。天南一萬里，誰料得生還。"]'),
('yuding-84','北歸次秋浦界清溪館','劉長卿','唐','御定全唐诗','yuding','','[]','萬里猿啼斷，孤村客暫依。雁過彭蠡暮，人向宛陵稀。',48,'御定全唐詩/json/147.json','["萬里猿啼斷，孤村客暫依。雁過彭蠡暮，人向宛陵稀。", "舊路青山在，餘生白首歸。漸知行近北，不見鷓鴣飛。"]'),
('yuding-85','謫官後卻歸故村，將過虎丘，悵然有作','劉長卿','唐','御定全唐诗','yuding','','[]','萬事依然在，無如歲月何。邑人憐白髮，庭樹長新柯。',48,'御定全唐詩/json/147.json','["萬事依然在，無如歲月何。邑人憐白髮，庭樹長新柯。", "故老相逢少，同官不見多。唯餘舊山路，惆悵枉帆過。"]'),
('yuding-86','重推後卻赴嶺外待進止，寄元侍郎','劉長卿','唐','御定全唐诗','yuding','','[]','卻訪巴人路，難期國士恩。白雲從出岫，黃葉已辭根。',48,'御定全唐詩/json/147.json','["卻訪巴人路，難期國士恩。白雲從出岫，黃葉已辭根。", "大造功何薄，長年氣尚冤。空令數行淚，來往落湘沅。"]'),
('yuding-87','秋杪江亭有作','劉長卿','唐','御定全唐诗','yuding','','[]','寂寞江亭下，江楓秋氣斑。世情何處澹，湘水向人閑。',48,'御定全唐詩/json/147.json','["寂寞江亭下，江楓秋氣斑。世情何處澹，湘水向人閑。", "寒渚一孤雁，夕陽千萬山。扁舟如落葉，此去未知還。"]'),
('yuding-88','送鄭司直歸上都','劉長卿','唐','御定全唐诗','yuding','','[]','歲歲逢離別，蹉跎江海濱。宦游成楚老，鄉思逐秦人。',48,'御定全唐詩/json/147.json','["歲歲逢離別，蹉跎江海濱。宦游成楚老，鄉思逐秦人。", "馬首歸何日，鶯啼又一春。因君報情舊，閑慢欲垂綸。"]'),
('yuding-89','送靈澈上人歸嵩陽蘭若','劉長卿','唐','御定全唐诗','yuding','','[]','南地隨緣久，東林幾歲空。暮山門獨掩，春草路難通。',48,'御定全唐詩/json/147.json','["南地隨緣久，東林幾歲空。暮山門獨掩，春草路難通。", "作梵連松韻，焚香入桂叢。唯將舊瓶缽，卻寄白雲中。"]'),
('yuding-90','卻赴南邑留別蘇台知己','劉長卿','唐','御定全唐诗','yuding','','[]','又過梅嶺上，歲歲此枝寒。落日孤舟去，青山萬里看。',48,'御定全唐詩/json/147.json','["又過梅嶺上，歲歲此枝寒。落日孤舟去，青山萬里看。", "猿聲湘水靜，草色洞庭寬。已料生涯事，唯應把釣竿。"]'),
('yuding-91','和靈一上人新泉','劉長卿','唐','御定全唐诗','yuding','','[]','東林一泉出，複與遠公期。石淺寒流處，山空夜落時。',48,'御定全唐詩/json/147.json','["東林一泉出，複與遠公期。石淺寒流處，山空夜落時。", "夢閑聞細響，慮澹對清漪。動靜皆無意，唯應達者知。"]'),
('yuding-92','送李摯赴延陵令','劉長卿','唐','御定全唐诗','yuding','','[]','清風季子邑，想見下車時。向水彈琴靜，看山采菊遲。',48,'御定全唐詩/json/147.json','["清風季子邑，想見下車時。向水彈琴靜，看山采菊遲。", "明君加印綬，廉使托煢嫠。旦暮華陽洞，雲峰若有期。"]'),
('yuding-93','奉送裴員外赴上都','劉長卿','唐','御定全唐诗','yuding','','[]','彤襜江上遠，萬里詔書催。獨過潯陽去，空憐潮信回。',48,'御定全唐詩/json/147.json','["彤襜江上遠，萬里詔書催。獨過潯陽去，空憐潮信回。", "離心秋草綠，揮手暮帆開。想見秦城路，人看五馬來。"]'),
('yuding-94','長沙桓王墓下別李紓、張南史','劉長卿','唐','御定全唐诗','yuding','','[]','長沙千載後，春草獨萋萋。流水朝將暮，行人東複西。',48,'御定全唐詩/json/147.json','["長沙千載後，春草獨萋萋。流水朝將暮，行人東複西。", "碑苔幾字滅，山木萬株齊。佇立傷今古，相看惜解攜。"]'),
('yuding-95','送侯禦赴黔中充判官','劉長卿','唐','御定全唐诗','yuding','','[]','不識黔中路，今看遣使臣。猿啼萬里客，鳥似五湖人。',48,'御定全唐詩/json/147.json','["不識黔中路，今看遣使臣。猿啼萬里客，鳥似五湖人。", "地遠官無法，山深俗豈淳。須令荒徼外，亦解懼埋輪。"]'),
('yuding-96','秋日登吳公臺上寺遠眺，寺即陳將吳明徹戰場','劉長卿','唐','御定全唐诗','yuding','','[]','古台搖落後，秋日望鄉心。野寺人來少，雲峰水隔深。',48,'御定全唐詩/json/147.json','["古台搖落後，秋日望鄉心。野寺人來少，雲峰水隔深。", "夕陽依舊壘，寒磬滿空林。惆悵南朝事，長江獨至今。"]'),
('yuding-97','淮上送梁二，恩命追赴上都','劉長卿','唐','御定全唐诗','yuding','','[]','賈生年最少，儒行漢庭聞。拜手卷黃紙，回身謝白雲。',48,'御定全唐詩/json/147.json','["賈生年最少，儒行漢庭聞。拜手卷黃紙，回身謝白雲。", "故關無去客，春草獨隨君。淼淼長淮水，東西自此分。"]'),
('yuding-98','送崔升歸上都','劉長卿','唐','御定全唐诗','yuding','','[]','舊寺尋遺緒，歸心逐去塵。早鶯何處客，古木幾家人。',48,'御定全唐詩/json/147.json','["舊寺尋遺緒，歸心逐去塵。早鶯何處客，古木幾家人。", "白髮經多難，滄洲欲暮春。臨期數行淚，為爾一沾巾。"]'),
('yuding-99','過李將軍南鄭林園觀妓','劉長卿','唐','御定全唐诗','yuding','','[]','郊原風日好，百舌弄何頻。小婦秦家女，將軍天上人。',48,'御定全唐詩/json/147.json','["郊原風日好，百舌弄何頻。小婦秦家女，將軍天上人。", "鴉歸長郭暮，草映大堤春。客散垂楊下，通橋車馬塵。"]'),
('yuding-100','送嚴侍禦充東畿觀察判官','劉長卿','唐','御定全唐诗','yuding','','[]','洛陽征戰後，君去問凋殘。雲月臨南至，風霜向北寒。',48,'御定全唐詩/json/147.json','["洛陽征戰後，君去問凋殘。雲月臨南至，風霜向北寒。", "故園經亂久，古木隔林看。誰訪江城客，年年守一官。"]'),
('yuding-101','送王端公入奏上都','劉長卿','唐','御定全唐诗','yuding','','[]','舊國無家訪，臨歧亦羨歸。途經百戰後，客過二陵稀。',48,'御定全唐詩/json/147.json','["舊國無家訪，臨歧亦羨歸。途經百戰後，客過二陵稀。", "秋草通征騎，寒城背落暉。行當蒙顧問，吳楚歲頻饑。"]'),
('yuding-102','送營田判官鄭侍禦赴上都','劉長卿','唐','御定全唐诗','yuding','','[]','上國三千里，西還及歲芳。故山經亂在，春日送歸長。',48,'御定全唐詩/json/147.json','["上國三千里，西還及歲芳。故山經亂在，春日送歸長。", "曉奏趨雙闕，秋成報萬箱。幸論開濟力，已實海陵倉。"]'),
('yuding-103','送李校書赴東浙幕府','劉長卿','唐','御定全唐诗','yuding','','[]','方從大夫後，南去會稽行。淼淼滄江外，青青春草生。',48,'御定全唐詩/json/147.json','["方從大夫後，南去會稽行。淼淼滄江外，青青春草生。", "芸香辭亂事，梅吹聽軍聲。應訪王家宅，空憐江水準。"]'),
('yuding-104','清明後登城眺望','劉長卿','唐','御定全唐诗','yuding','','[]','風景清明後，雲山睥睨前。百花如舊日，萬井出新煙。',48,'御定全唐詩/json/147.json','["風景清明後，雲山睥睨前。百花如舊日，萬井出新煙。", "草色無空地，江流合遠天。長安在何處，遙指夕陽邊。"]'),
('yuding-105','陪王明府泛舟','劉長卿','唐','御定全唐诗','yuding','','[]','花縣彈琴暇，樵風載酒時。山含秋色近，鳥度夕陽遲。',48,'御定全唐詩/json/147.json','["花縣彈琴暇，樵風載酒時。山含秋色近，鳥度夕陽遲。", "出沒鳧成浪，蒙籠竹亞枝。雲峰逐人意，來去解相隨。"]'),
('yuding-106','送度支留後若侍禦之歙州，便赴信州省覲','劉長卿','唐','御定全唐诗','yuding','','[]','國用憂錢谷，朝推此任難。即山榆莢變，降雨稻花殘。',48,'御定全唐詩/json/147.json','["國用憂錢谷，朝推此任難。即山榆莢變，降雨稻花殘。", "林響朝登嶺，江喧夜過灘。遙知驄馬色，應待倚門看。"]'),
('yuding-107','餘幹夜宴奉餞前蘇州韋使君新除婺州作','劉長卿','唐','御定全唐诗','yuding','','[]','複拜東陽郡，遙馳北闕心。行春五馬急，向夜一猿深。',48,'御定全唐詩/json/147.json','["複拜東陽郡，遙馳北闕心。行春五馬急，向夜一猿深。", "山過康郎近，星看婺女臨。幸容棲托分，猶戀舊棠陰。"]'),
('yuding-108','晚次苦竹館，卻憶幹越舊游','劉長卿','唐','御定全唐诗','yuding','','[]','匹馬風塵色，千峰旦暮時。遙看落日盡，獨向遠山遲。',48,'御定全唐詩/json/147.json','["匹馬風塵色，千峰旦暮時。遙看落日盡，獨向遠山遲。", "故驛花臨道，荒村竹映籬。誰憐卻回首，步步戀南枝。"]'),
('yuding-109','送李二十四移家之江州','劉長卿','唐','御定全唐诗','yuding','','[]','煙塵猶滿目，歧路易沾衣。逋客多南渡，征鴻自北飛。',48,'御定全唐詩/json/147.json','["煙塵猶滿目，歧路易沾衣。逋客多南渡，征鴻自北飛。", "九江春草綠，千里暮潮歸。別後難相訪，全家隱釣磯。"]'),
('yuding-110','送盧判官南湖','劉長卿','唐','御定全唐诗','yuding','','[]','漾舟仍載酒，愧爾意相寬。草色南湖綠，松聲小署寒。',48,'御定全唐詩/json/147.json','["漾舟仍載酒，愧爾意相寬。草色南湖綠，松聲小署寒。", "水禽前後起，花嶼往來看。已作滄洲調，無心戀一官。"]'),
('yuding-111','送張栩扶侍之睦州','劉長卿','唐','御定全唐诗','yuding','','[]','遙憶新安舊，扁舟複卻還。淺深看水石，來往逐雲山。',48,'御定全唐詩/json/147.json','["遙憶新安舊，扁舟複卻還。淺深看水石，來往逐雲山。", "入縣餘花在，過門故柳閑。東征隨子去，皆隱薜蘿間。"]'),
('yuding-112','集梁耿開元寺所居院','劉長卿','唐','御定全唐诗','yuding','','[]','到君幽臥處，為我掃莓苔。花雨晴天落，松風終日來。',48,'御定全唐詩/json/147.json','["到君幽臥處，為我掃莓苔。花雨晴天落，松風終日來。", "路經深竹過，門向遠山開。豈得長高枕，中朝正用才。"]'),
('yuding-113','贈西鄰盧少府','劉長卿','唐','御定全唐诗','yuding','','[]','籬落能相近，漁樵偶複同。苔封三徑絕，溪向數家通。',48,'御定全唐詩/json/147.json','["籬落能相近，漁樵偶複同。苔封三徑絕，溪向數家通。", "犬吠寒煙裏，鴉鳴夕照中。時因杖藜次，相訪竹林東。"]'),
('yuding-114','游休禪師雙峰寺','劉長卿','唐','御定全唐诗','yuding','','[]','雙扉碧峰際，遙向夕陽開。飛錫方獨往，孤雲何事來。',48,'御定全唐詩/json/147.json','["雙扉碧峰際，遙向夕陽開。飛錫方獨往，孤雲何事來。", "寒潭映白月，秋雨上青苔。相送東郊外，羞看驄馬回。"]'),
('yuding-115','廨中見桃花南枝已開，北枝未發，因寄杜副端','劉長卿','唐','御定全唐诗','yuding','','[]','何意同根本，開花每後時。應緣去日遠，獨自發春遲。',48,'御定全唐詩/json/147.json','["何意同根本，開花每後時。應緣去日遠，獨自發春遲。", "結實恩難忘，無言恨豈知。年光不可待，空羨向南枝。"]'),
('yuding-116','奉送盧員外之饒州','劉長卿','唐','御定全唐诗','yuding','','[]','天書萬里至，旌旆上江飛。日向鄱陽近，應看吳岫微。',48,'御定全唐詩/json/147.json','["天書萬里至，旌旆上江飛。日向鄱陽近，應看吳岫微。", "暮帆何處落，潮水背人歸。風土無勞問，南枝黃葉稀。"]'),
('yuding-117','送處士歸州，因寄林山人','劉長卿','唐','御定全唐诗','yuding','','[]','陵陽不可見，獨往復如何。舊邑雲山裏，扁舟來去過。',48,'御定全唐詩/json/147.json','["陵陽不可見，獨往復如何。舊邑雲山裏，扁舟來去過。", "鳥聲春穀靜，草色太湖多。儻宿荊溪夜，相思漁者歌。"]'),
('yuding-118','移使鄂州，次峴陽館懷舊居','劉長卿','唐','御定全唐诗','yuding','','[]','多慚恩未報，敢問路何長。萬里通秋雁，千峰共夕陽。',48,'御定全唐詩/json/147.json','["多慚恩未報，敢問路何長。萬里通秋雁，千峰共夕陽。", "舊游成遠道，此去更違鄉。草露深山裏，朝朝落客裳。"]'),
('yuding-119','送齊郎中赴海州','劉長卿','唐','御定全唐诗','yuding','','[]','華省占星動，孤城望日遙。直廬收舊草，行縣及新苗。',48,'御定全唐詩/json/147.json','["華省占星動，孤城望日遙。直廬收舊草，行縣及新苗。", "滄海天連水，青山暮與朝。閭閻幾家散，應待下車招。"]'),
('yuding-120','重陽日鄂城樓送屈突司直','劉長卿','唐','御定全唐诗','yuding','','[]','登高複送遠，惆悵洞庭秋。風景同前古，雲山滿上游。',48,'御定全唐詩/json/147.json','["登高複送遠，惆悵洞庭秋。風景同前古，雲山滿上游。", "蒼蒼來暮雨，淼淼逐寒流。今日關中事，蕭何共爾憂。"]'),
('yuding-121','更被奏留淮南，送從弟罷使江東','劉長卿','唐','御定全唐诗','yuding','','[]','又作淮南客，還悲木葉聲。寒潮落瓜步，秋色上蕪城。',48,'御定全唐詩/json/147.json','["又作淮南客，還悲木葉聲。寒潮落瓜步，秋色上蕪城。", "王事何時盡，滄洲羨爾行。青山將綠水，惆悵不勝情。"]'),
('yuding-122','經漂母墓','劉長卿','唐','御定全唐诗','yuding','','[]','昔賢懷一飯，茲事已千秋。古墓樵人識，前朝楚水流。',48,'御定全唐詩/json/147.json','["昔賢懷一飯，茲事已千秋。古墓樵人識，前朝楚水流。", "渚蘋行客薦，山木杜鵑愁。春草茫茫綠，王孫舊此游。"]'),
('yuding-123','送李端公赴東都','劉長卿','唐','御定全唐诗','yuding','','[]','軒轅征戰後，江海別離長。遠客歸何處，平蕪滿故鄉。',48,'御定全唐詩/json/147.json','["軒轅征戰後，江海別離長。遠客歸何處，平蕪滿故鄉。", "夕陽帆杳杳，舊裏樹蒼蒼。惆悵蓬山下，瓊枝不可忘。"]'),
('yuding-124','送王員外歸朝','劉長卿','唐','御定全唐诗','yuding','','[]','往來無盡目，離別要逢春。海內罹多事，天涯見近臣。',48,'御定全唐詩/json/147.json','["往來無盡目，離別要逢春。海內罹多事，天涯見近臣。", "芳時萬里客，鄉路獨歸人。魏闕心常在，隨君亦向秦。"]'),
('yuding-125','送蔣侍禦入秦','劉長卿','唐','御定全唐诗','yuding','','[]','朝見及芳菲，恩榮出紫微。晚光臨仗奏，春色共西歸。',48,'御定全唐詩/json/147.json','["朝見及芳菲，恩榮出紫微。晚光臨仗奏，春色共西歸。", "楚客移家老，秦人訪舊稀。因君鄉里去，為掃故園扉。"]'),
('yuding-126','洞庭驛逢郴州使還，寄李湯司馬','劉長卿','唐','御定全唐诗','yuding','','[]','洞庭秋水闊，南望過衡峰。遠客瀟湘裏，歸人何處逢。',48,'御定全唐詩/json/147.json','["洞庭秋水闊，南望過衡峰。遠客瀟湘裏，歸人何處逢。", "孤雲飛不定，落葉去無蹤。莫使滄浪叟，長歌笑爾容。"]'),
('yuding-127','送舍弟之鄱陽居','劉長卿','唐','御定全唐诗','yuding','','[]','鄱陽寄家處，自別掩柴扉。故里人何在，滄波孤客稀。',48,'御定全唐詩/json/147.json','["鄱陽寄家處，自別掩柴扉。故里人何在，滄波孤客稀。", "湖山春草遍，雲木夕陽微。南去逢回雁，應憐相背飛。"]'),
('yuding-128','送裴二十端公使嶺南','劉長卿','唐','御定全唐诗','yuding','','[]','蒼梧萬里路，空見白雲來。遠國知何在，憐君去未回。',48,'御定全唐詩/json/147.json','["蒼梧萬里路，空見白雲來。遠國知何在，憐君去未回。", "桂林無葉落，梅嶺自花開。陸賈千年後，誰看朝漢台。"]'),
('yuding-129','過桃花夫人廟','劉長卿','唐','御定全唐诗','yuding','','[]','寂寞應千歲，桃花想一枝。路人看古木，江月向空祠。',48,'御定全唐詩/json/147.json','["寂寞應千歲，桃花想一枝。路人看古木，江月向空祠。", "雲雨飛何處，山川是舊時。獨憐春草色，猶似憶佳期。"]'),
('yuding-130','鄂渚送池州程使君','劉長卿','唐','御定全唐诗','yuding','','[]','蕭蕭五馬動，欲別謝臨川。落日蕪湖色，空山梅冶煙。',48,'御定全唐詩/json/147.json','["蕭蕭五馬動，欲別謝臨川。落日蕪湖色，空山梅冶煙。", "江湖通廨舍，楚老拜戈船。風化東南滿，行舟來去傳。"]'),
('yuding-131','送友人西上','劉長卿','唐','御定全唐诗','yuding','','[]','羈心不自解，有別會沾衣。春草連天積，五陵遠客歸。',48,'御定全唐詩/json/147.json','["羈心不自解，有別會沾衣。春草連天積，五陵遠客歸。", "十年經轉戰，幾處便芳菲。想見函關路，行人去亦稀。"]'),
('yuding-132','送梁郎中赴吉州','劉長卿','唐','御定全唐诗','yuding','','[]','遙想廬陵郡，還聽叔度歌。舊官移上象，新令布中和。',48,'御定全唐詩/json/147.json','["遙想廬陵郡，還聽叔度歌。舊官移上象，新令布中和。", "看竹經霜少，聞猿帶雨多。但愁征拜日，無奈借留何。"]'),
('yuding-133','過湖南羊處士別業','劉長卿','唐','御定全唐诗','yuding','','[]','杜門成白首，湖上寄生涯。秋草蕪三徑，寒塘獨一家。',48,'御定全唐詩/json/147.json','["杜門成白首，湖上寄生涯。秋草蕪三徑，寒塘獨一家。", "鳥歸村落盡，水向縣城斜。自有東籬菊，年年解作花。"]'),
('yuding-134','送河南元判官赴河南勾當苗稅充百官俸錢','劉長卿','唐','御定全唐诗','yuding','','[]','春草長河曲，離心共渺然。方收漢家俸，獨向汶陽田。',48,'御定全唐詩/json/147.json','["春草長河曲，離心共渺然。方收漢家俸，獨向汶陽田。", "鳥雀空城在，榛蕪舊路遷。山東征戰苦，幾處有人煙。"]'),
('yuding-135','夏中崔中丞宅見海紅搖落一花獨開','劉長卿','唐','御定全唐诗','yuding','','[]','何事一花殘，閒庭百草闌。綠滋經雨發，紅豔隔林看。',48,'御定全唐詩/json/147.json','["何事一花殘，閒庭百草闌。綠滋經雨發，紅豔隔林看。", "竟日餘香在，過時獨秀難。共憐芳意晚，秋露未須團。"]'),
('yuding-136','使還至菱陂驛渡溮水作','劉長卿','唐','御定全唐诗','yuding','','[]','清川已再涉，疲馬共西還。何事行人倦，終年流水閑。',48,'御定全唐詩/json/147.json','["清川已再涉，疲馬共西還。何事行人倦，終年流水閑。", "孤煙飛廣澤，一鳥向空山。愁入雲峰裏，蒼蒼閉古關。"]'),
('yuding-137','送齊郎中典括州','劉長卿','唐','御定全唐诗','yuding','','[]','星象移何處，旌麾獨向東。勸耕滄海畔，聽訟白雲中。',48,'御定全唐詩/json/147.json','["星象移何處，旌麾獨向東。勸耕滄海畔，聽訟白雲中。", "樹色雙溪合，猿聲萬嶺同。石門康樂住，幾裏枉帆通。"]'),
('yuding-138','過隱空和尚故居','劉長卿','唐','御定全唐诗','yuding','','[]','自從飛錫去，人到沃洲稀。林下期何在，山中春獨歸。',48,'御定全唐詩/json/147.json','["自從飛錫去，人到沃洲稀。林下期何在，山中春獨歸。", "踏花尋舊徑，映竹掩空扉。寥落東峰上，猶堪靜者依。"]'),
('yuding-139','過蕭尚書故居見李花，感而成詠','劉長卿','唐','御定全唐诗','yuding','','[]','手植已芳菲，心傷故徑微。往年啼鳥至，今日主人非。',48,'御定全唐詩/json/147.json','["手植已芳菲，心傷故徑微。往年啼鳥至，今日主人非。", "滿地誰當掃，隨風豈複歸。空憐舊陰在，門客共沾衣。"]'),
('yuding-140','送袁處士','劉長卿','唐','御定全唐诗','yuding','','[]','閒田北川下，靜者去躬耕。萬里空江菼，孤舟過郢城。',48,'御定全唐詩/json/147.json','["閒田北川下，靜者去躬耕。萬里空江菼，孤舟過郢城。", "種荷依野水，移柳待山鶯。出處安能問，浮雲豈有情。"]'),
('yuding-141','酬李侍禦登岳陽見寄','劉長卿','唐','御定全唐诗','yuding','','[]','想見孤舟去，無由此路尋。暮帆遙在眼，春色獨何心。',48,'御定全唐詩/json/147.json','["想見孤舟去，無由此路尋。暮帆遙在眼，春色獨何心。", "綠水瀟湘闊，青山鄠杜深。誰當北風至，為爾一開襟。"]'),
('yuding-142','喜晴','劉長卿','唐','御定全唐诗','yuding','','[]','曉日西風轉，秋天萬里明。湖天一種色，林鳥百般聲。',48,'御定全唐詩/json/147.json','["曉日西風轉，秋天萬里明。湖天一種色，林鳥百般聲。", "霽景浮雲滿，遊絲映水輕。今朝江上客，凡慰幾人情。"]'),
('yuding-0','夏口送徐郎中歸朝','劉長卿','唐','御定全唐诗','yuding','','[]','星象南宮遠，風流上客稀。九重思曉奏，萬里見春歸。',48,'御定全唐詩/json/148.json','["星象南宮遠，風流上客稀。九重思曉奏，萬里見春歸。", "棹發空江響，城孤落日暉。離心與楊柳，臨水更依依。"]'),
('yuding-1','鄂渚聽杜別駕彈胡琴','劉長卿','唐','御定全唐诗','yuding','','[]','文姬留此曲，千載一知音。不解胡人語，空留楚客心。',48,'御定全唐詩/json/148.json','["文姬留此曲，千載一知音。不解胡人語，空留楚客心。", "聲隨邊草動，意入隴雲深。何事長江上，蕭蕭出塞吟。"]'),
('yuding-2','過鸚鵡洲王處士別業','劉長卿','唐','御定全唐诗','yuding','','[]','白首此為漁，青山對結廬。問人尋野筍，留客饋家蔬。',48,'御定全唐詩/json/148.json','["白首此為漁，青山對結廬。問人尋野筍，留客饋家蔬。", "古柳依沙發，春苗帶雨鋤。共憐芳杜色，終日伴閒居。"]'),
('yuding-3','寄萬州崔使君','劉長卿','唐','御定全唐诗','yuding','','[]','時艱方用武，儒者任浮沈。搖落秋江暮，憐君巴峽深。',48,'御定全唐詩/json/148.json','["時艱方用武，儒者任浮沈。搖落秋江暮，憐君巴峽深。", "丘門多白首，蜀郡滿青襟。自解書生詠，愁猿莫夜吟。"]'),
('yuding-4','送馬秀才移家京洛便赴舉','劉長卿','唐','御定全唐诗','yuding','','[]','自從為楚客，不復掃荊扉。劍共丹誠在，書隨白髮歸。',48,'御定全唐詩/json/148.json','["自從為楚客，不復掃荊扉。劍共丹誠在，書隨白髮歸。", "舊遊經亂靜，後進識君稀。空把相如賦，何人薦禮闈。"]'),
('yuding-5','送南特進赴歸行營','劉長卿','唐','御定全唐诗','yuding','','[]','聞道軍書至，揚鞭不問家。虜雲連白草，漢月到黃沙。',48,'御定全唐詩/json/148.json','["聞道軍書至，揚鞭不問家。虜雲連白草，漢月到黃沙。", "汗馬河源飲，燒羌隴坻遮。翩翩新結束，去逐李輕車。"]'),
('yuding-6','送道標上人歸南嶽','劉長卿','唐','御定全唐诗','yuding','','[]','悠然倚孤棹，卻憶臥中林。江草將歸遠，湘山獨往深。',48,'御定全唐詩/json/148.json','["悠然倚孤棹，卻憶臥中林。江草將歸遠，湘山獨往深。", "白雲留不住，淥水去無心。衡嶽千峰亂，禪房何處尋。"]'),
('yuding-7','送梁侍禦巡永州','劉長卿','唐','御定全唐诗','yuding','','[]','蕭蕭江雨暮，客散野亭空。憂國天涯去，思鄉歲暮同。',48,'御定全唐詩/json/148.json','["蕭蕭江雨暮，客散野亭空。憂國天涯去，思鄉歲暮同。", "到時猿未斷，回處水應窮。莫望零陵路，千峰萬木中。"]'),
('yuding-8','歲夜喜魏萬成、郭夏雪中相尋','劉長卿','唐','御定全唐诗','yuding','','[]','新年欲變柳，舊客共沾衣。歲夜猶難盡，鄉春又獨歸。',48,'御定全唐詩/json/148.json','["新年欲變柳，舊客共沾衣。歲夜猶難盡，鄉春又獨歸。", "寒燈映虛牖，暮雪掩閑扉。且莫乘船去，平生相訪稀。"]'),
('yuding-9','送蔡侍禦赴上都','劉長卿','唐','御定全唐诗','yuding','','[]','遲遲立駟馬，久客戀瀟湘。明日誰同路，新年獨到鄉。',48,'御定全唐詩/json/148.json','["遲遲立駟馬，久客戀瀟湘。明日誰同路，新年獨到鄉。", "孤煙向驛遠，積雪去關長。秦地看春色，南枝不可忘。"]'),
('yuding-10','晦日陪辛大夫宴南亭','劉長卿','唐','御定全唐诗','yuding','','[]','月晦逢休浣，年光逐宴移。早鶯留客醉，春日為人遲。',48,'御定全唐詩/json/148.json','["月晦逢休浣，年光逐宴移。早鶯留客醉，春日為人遲。", "蓂草全無葉，梅花遍壓枝。政閑風景好，莫比峴山時。"]'),
('yuding-11','送獨孤判官赴嶺','劉長卿','唐','御定全唐诗','yuding','','[]','伏波初樹羽，待爾靜川鱗。嶺海看飛鳥，天涯問遠人。',48,'御定全唐詩/json/148.json','["伏波初樹羽，待爾靜川鱗。嶺海看飛鳥，天涯問遠人。", "蒼梧雲裏夕，青草嶂中春。遙想文身國，迎舟拜使臣。"]'),
('yuding-12','長沙館中與郭夏對雨','劉長卿','唐','御定全唐诗','yuding','','[]','長沙積雨晦，深巷絕人幽。潤上春衣冷，聲連暮角愁。',48,'御定全唐詩/json/148.json','["長沙積雨晦，深巷絕人幽。潤上春衣冷，聲連暮角愁。", "雲橫全楚地，樹暗古湘洲。杳藹江天外，空堂生百憂。"]'),
('yuding-13','陪辛大夫西亭宴觀妓','劉長卿','唐','御定全唐诗','yuding','','[]','歌舞憐遲日，旄麾映早春。鶯窺隴西將，花對洛陽人。',48,'御定全唐詩/json/148.json','["歌舞憐遲日，旄麾映早春。鶯窺隴西將，花對洛陽人。", "醉罷知何事，恩深忘此身。任他行雨去，歸路裛香塵。"]'),
('yuding-14','題魏萬成江亭','劉長卿','唐','御定全唐诗','yuding','','[]','蕭條方歲晏，牢落對空洲。才出時人右，家貧湘水頭。',48,'御定全唐詩/json/148.json','["蕭條方歲晏，牢落對空洲。才出時人右，家貧湘水頭。", "蒼山隱暮雪，白鳥沒寒流。不是蓮花府，冥冥不可求。"]'),
('yuding-15','春過裴虯郊園','劉長卿','唐','御定全唐诗','yuding','','[]','郊原春欲暮，桃杏落紛紛。何處隨芳草，留家寄白雲。',48,'御定全唐詩/json/148.json','["郊原春欲暮，桃杏落紛紛。何處隨芳草，留家寄白雲。", "聽鶯情念友，看竹恨無君。長嘯高臺上，南風冀爾聞。"]'),
('yuding-16','送韋贊善使嶺南','劉長卿','唐','御定全唐诗','yuding','','[]','欲逐樓船將，方安卉服夷。炎洲經瘴遠，春水上瀧遲。',48,'御定全唐詩/json/148.json','["欲逐樓船將，方安卉服夷。炎洲經瘴遠，春水上瀧遲。", "歲貢隨重譯，年芳遍四時。番禺靜無事，空詠飲泉詩。"]'),
('yuding-17','送喬判官赴福州','劉長卿','唐','御定全唐诗','yuding','','[]','揚帆向何處，插羽逐征東。夷落人煙迥，王程鳥路通。',48,'御定全唐詩/json/148.json','["揚帆向何處，插羽逐征東。夷落人煙迥，王程鳥路通。", "江流回澗底，山色聚閩中。君去凋殘後，應憐百越空。"]'),
('yuding-18','送李補闕之上都','劉長卿','唐','御定全唐诗','yuding','','[]','獨歸西掖去，難接後塵遊。向日三千里，朝天十二樓。',48,'御定全唐詩/json/148.json','["獨歸西掖去，難接後塵遊。向日三千里，朝天十二樓。", "路看新柳夕，家對舊山秋。惆悵離心遠，滄江空自流。"]'),
('yuding-19','送袁明府之任','劉長卿','唐','御定全唐诗','yuding','','[]','既有親人術，還逢試吏年。蓬蒿千里閉，村樹幾家全。',48,'御定全唐詩/json/148.json','["既有親人術，還逢試吏年。蓬蒿千里閉，村樹幾家全。", "雪覆淮南道，春生潁穀煙。何時當蒞政，相府待聞天。"]'),
('yuding-20','海鹽官舍早春','劉長卿','唐','御定全唐诗','yuding','','[]','小邑滄洲吏，新年白首翁。一官如遠客，萬事極飄蓬。',48,'御定全唐詩/json/148.json','["小邑滄洲吏，新年白首翁。一官如遠客，萬事極飄蓬。", "柳色孤城裏，鶯聲細雨中。羈心早已亂，何事更春風。"]'),
('yuding-21','南湖送徐二十七西上','劉長卿','唐','御定全唐诗','yuding','','[]','家在橫塘曲，那能萬里違。門臨秋水掩，帆帶夕陽飛。',48,'御定全唐詩/json/148.json','["家在橫塘曲，那能萬里違。門臨秋水掩，帆帶夕陽飛。", "傲俗宜紗帽，幹時倚布衣。獨將湖上月，相逐去還歸。"]'),
('yuding-22','曲阿對月別岑況、徐說','劉長卿','唐','御定全唐诗','yuding','','[]','金陵已蕪沒，函穀複煙塵。猶見南朝月，還隨上國人。',48,'御定全唐詩/json/148.json','["金陵已蕪沒，函穀複煙塵。猶見南朝月，還隨上國人。", "白雲心自遠，滄海意相親。何事須成別，汀洲欲暮春。"]'),
('yuding-23','送李侍禦貶鄱陽','劉長卿','唐','御定全唐诗','yuding','','[]','回車仍昨日，謫去已秋風。幹越知何處，雲山只向東。',48,'御定全唐詩/json/148.json','["回車仍昨日，謫去已秋風。幹越知何處，雲山只向東。", "暮天江色裏，田鶴稻花中。卻見鄱陽吏，猶應舊馬驄。"]'),
('yuding-24','送路少府使東京便應制舉','劉長卿','唐','御定全唐诗','yuding','','[]','故人西奉使，胡騎正紛紛。舊國無來信，春江獨送君。',48,'御定全唐詩/json/148.json','["故人西奉使，胡騎正紛紛。舊國無來信，春江獨送君。", "五言淩白雪，六翮向青雲。誰念滄洲吏，忘機鷗鳥群。"]'),
('yuding-25','松江獨宿','劉長卿','唐','御定全唐诗','yuding','','[]','洞庭初下葉，孤客不勝愁。明月天涯夜，青山江上秋。',48,'御定全唐詩/json/148.json','["洞庭初下葉，孤客不勝愁。明月天涯夜，青山江上秋。", "一官成白首，萬里寄滄洲。久被浮名系，能無愧海鷗。"]'),
('yuding-26','尋白石山真禪師舊草堂','劉長卿','唐','御定全唐诗','yuding','','[]','惆悵雲山暮，閑門獨不開。何時飛杖錫，終日閉蒼苔。',48,'御定全唐詩/json/148.json','["惆悵雲山暮，閑門獨不開。何時飛杖錫，終日閉蒼苔。", "隔嶺春猶在，無人燕亦來。誰堪暝投處，空複一猿哀。"]'),
('yuding-27','送行軍張司馬罷使回','劉長卿','唐','御定全唐诗','yuding','','[]','時危身赴敵，事往任浮沈。末路三江去，當時百戰心。',48,'御定全唐詩/json/148.json','["時危身赴敵，事往任浮沈。末路三江去，當時百戰心。", "春風吳苑綠，古木剡山深。千里滄波上，孤舟不可尋。"]'),
('yuding-28','喜李翰自越至','劉長卿','唐','御定全唐诗','yuding','','[]','南浮滄海上，萬里到吳台。久別長相憶，孤舟何處來。',48,'御定全唐詩/json/148.json','["南浮滄海上，萬里到吳台。久別長相憶，孤舟何處來。", "春風催客醉，江月向人開。羨爾無羈束，沙鷗獨不猜。"]'),
('yuding-29','罪所留系寄張十四','劉長卿','唐','御定全唐诗','yuding','','[]','不見君來久，冤深意未傳。冶長空得罪，夷甫豈言錢。',48,'御定全唐詩/json/148.json','["不見君來久，冤深意未傳。冶長空得罪，夷甫豈言錢。", "直道天何在，愁容鏡亦憐。因書欲自訴，無淚可潸然。"]'),
('yuding-30','送勤照和尚往睢陽赴太守請','劉長卿','唐','御定全唐诗','yuding','','[]','燃燈傳七祖，杖錫為諸侯。來去雲無意，東西水自流。',48,'御定全唐詩/json/148.json','["燃燈傳七祖，杖錫為諸侯。來去雲無意，東西水自流。", "青山春滿目，白日夜隨舟。知到梁園下，蒼生賴此遊。"]'),
('yuding-31','長門怨','劉長卿','唐','御定全唐诗','yuding','','[]','何事長門閉，珠簾只自垂。月移深殿早，春向後宮遲。',48,'御定全唐詩/json/148.json','["何事長門閉，珠簾只自垂。月移深殿早，春向後宮遲。", "蕙草生閑地，梨花發舊枝。芳菲自恩幸，看著被風吹。"]'),
('yuding-32','過橫山顧山人草堂','劉長卿','唐','御定全唐诗','yuding','','[]','只見山相掩，誰言路尚通。人來千嶂外，犬吠百花中。',48,'御定全唐詩/json/148.json','["只見山相掩，誰言路尚通。人來千嶂外，犬吠百花中。", "細草香飄雨，垂楊閑臥風。卻尋樵徑去，惆悵綠溪東。"]'),
('yuding-33','送李校書適越謁杜中丞','劉長卿','唐','御定全唐诗','yuding','','[]','江風處處盡，旦暮水空波。搖落行人去，雲山向越多。',48,'御定全唐詩/json/148.json','["江風處處盡，旦暮水空波。搖落行人去，雲山向越多。", "陳蕃懸榻待，謝客枉帆過。相見耶溪路，逶迤入薜蘿。"]'),
('yuding-34','秋夜雨中，諸公過靈光寺所居','劉長卿','唐','御定全唐诗','yuding','','[]','晤語青蓮舍，重門閉夕陰。向人寒燭靜，帶雨夜鐘沈。',48,'御定全唐詩/json/148.json','["晤語青蓮舍，重門閉夕陰。向人寒燭靜，帶雨夜鐘沈。", "流水從他事，孤雲任此心。不能捐鬥粟，終日愧瑤琴。"]'),
('yuding-35','西庭夜燕，喜評事兄拜會','劉長卿','唐','御定全唐诗','yuding','','[]','猶是南州吏，江城又一春。隔簾湖上月，對酒眼中人。',48,'御定全唐詩/json/148.json','["猶是南州吏，江城又一春。隔簾湖上月，對酒眼中人。", "棘寺初銜命，梅仙已誤身。無心羨榮祿，唯待卻垂綸。"]'),
('yuding-36','尋南溪常山道人隱居','劉長卿','唐','御定全唐诗','yuding','','[]','一路經行處，莓苔見履痕。白雲依靜渚，春草閉閑門。',48,'御定全唐詩/json/148.json','["一路經行處，莓苔見履痕。白雲依靜渚，春草閉閑門。", "過雨看松色，隨山到水源。溪花與禪意，相對亦忘言。"]'),
('yuding-37','揚州雨中張十宅觀妓','劉長卿','唐','御定全唐诗','yuding','','[]','夜色帶春煙，燈花拂更燃。殘妝添石黛，豔舞落金鈿。',48,'御定全唐詩/json/148.json','["夜色帶春煙，燈花拂更燃。殘妝添石黛，豔舞落金鈿。", "掩笑頻欹扇，迎歌乍動弦。不知巫峽雨，何事海西邊。"]'),
('yuding-38','赴宣州使院，夜宴寂上人房，留辭前蘇州韋使君','劉長卿','唐','御定全唐诗','yuding','','[]','白雲乖始願，滄海有微波。戀舊爭趨府，臨危欲負戈。',48,'御定全唐詩/json/148.json','["白雲乖始願，滄海有微波。戀舊爭趨府，臨危欲負戈。", "春歸花殿暗，秋傍竹房多。耐可機心息，其如羽檄何。"]'),
('yuding-39','送薛承矩秩滿北游','劉長卿','唐','御定全唐诗','yuding','','[]','匹馬向何處，北遊殊未還。寒雲帶飛雪，日暮雁門關。',48,'御定全唐詩/json/148.json','["匹馬向何處，北遊殊未還。寒雲帶飛雪，日暮雁門關。", "一路傍汾水，數州看晉山。知君喜初服，只愛此身閑。"]'),
('yuding-40','餞別王十一南游','劉長卿','唐','御定全唐诗','yuding','','[]','望君煙水闊，揮手淚沾巾。飛鳥沒何處，青山空向人。',48,'御定全唐詩/json/148.json','["望君煙水闊，揮手淚沾巾。飛鳥沒何處，青山空向人。", "長江一帆遠，落日五湖春。誰見汀洲上，相思愁白蘋。"]'),
('yuding-41','送嚴維尉諸暨','劉長卿','唐','御定全唐诗','yuding','','[]','愛爾文章遠，還家印綬榮。退公兼色養，臨下帶鄉情。',48,'御定全唐詩/json/148.json','["愛爾文章遠，還家印綬榮。退公兼色養，臨下帶鄉情。", "喬木映官舍，春山宜縣城。應憐釣台石，閑卻為浮名。"]'),
('yuding-42','送李七之笮水謁張相公','劉長卿','唐','御定全唐诗','yuding','','[]','惆悵青春晚，殷勤濁酒壚。後時長劍澀，斜日片帆孤。',48,'御定全唐詩/json/148.json','["惆悵青春晚，殷勤濁酒壚。後時長劍澀，斜日片帆孤。", "東閣邀才子，南昌老腐儒。梁園舊相識，誰憶臥江湖。"]'),
('yuding-43','送崔處士先適越','劉長卿','唐','御定全唐诗','yuding','','[]','山陰好雲物，此去又春風。越鳥聞花裏，曹娥想鏡中。',48,'御定全唐詩/json/148.json','["山陰好雲物，此去又春風。越鳥聞花裏，曹娥想鏡中。", "小江潮易滿，萬井水皆通。徒羨扁舟客，微官事不同。"]'),
('yuding-44','奉陪使君西庭送淮西魏判官','劉長卿','唐','御定全唐诗','yuding','','[]','羽檄催歸恨，春風醉別顏。能邀五馬送，自逐一星還。',48,'御定全唐詩/json/148.json','["羽檄催歸恨，春風醉別顏。能邀五馬送，自逐一星還。", "破竹從軍樂，看花聽訟閑。遙知用兵處，多在八公山。"]'),
('yuding-45','獄中見壁畫佛','劉長卿','唐','御定全唐诗','yuding','','[]','不謂銜冤處，而能窺大悲。獨棲叢棘下，還見雨花時。',48,'御定全唐詩/json/148.json','["不謂銜冤處，而能窺大悲。獨棲叢棘下，還見雨花時。", "地狹青蓮小，城高白日遲。幸親方便力，猶畏毒龍欺。"]'),
('yuding-46','送許拾遺還京','劉長卿','唐','御定全唐诗','yuding','','[]','萬里辭三殿，金陵到舊居。文星出西掖，卿月在南徐。',48,'御定全唐詩/json/148.json','["萬里辭三殿，金陵到舊居。文星出西掖，卿月在南徐。", "故里驚朝服，高堂捧詔書。暫容乘駟馬，誰許戀鱸魚。"]'),
('yuding-47','送張七判官還京覲省','劉長卿','唐','御定全唐诗','yuding','','[]','春蘭方可采，此去葉初齊。函谷鶯聲裏，秦山馬首西。',48,'御定全唐詩/json/148.json','["春蘭方可采，此去葉初齊。函谷鶯聲裏，秦山馬首西。", "庭闈新柏署，門館舊桃蹊。春色長安道，相隨入禁閨。"]'),
('yuding-48','送孫瑩京監擢第歸蜀覲省','劉長卿','唐','御定全唐诗','yuding','','[]','適賀一枝新，旋驚萬里分。禮闈稱獨步，太學許能文。',48,'御定全唐詩/json/148.json','["適賀一枝新，旋驚萬里分。禮闈稱獨步，太學許能文。", "征馬望春草，行人看暮雲。遙知倚門處，江樹正氛氳。"]'),
('yuding-49','送史九赴任寧陵，兼呈單父史八時監察五兄初入台','劉長卿','唐','御定全唐诗','yuding','','[]','趨府弟聯兄，看君此去榮。春隨千里道，河帶萬家城。',48,'御定全唐詩/json/148.json','["趨府弟聯兄，看君此去榮。春隨千里道，河帶萬家城。", "繡服棠花映，青袍草色迎。梁園修竹在，持贈結交情。"]'),
('yuding-50','臥病喜田九見寄','劉長卿','唐','御定全唐诗','yuding','','[]','臥來能幾日，春事已依然。不解謝公意，翻令靜者便。',48,'御定全唐詩/json/148.json','["臥來能幾日，春事已依然。不解謝公意，翻令靜者便。", "庭陰殘舊雪，柳色帶新年。寂寞深村裏，唯君相訪偏。"]'),
('yuding-51','重過宣峰寺山房，寄靈一上人','劉長卿','唐','御定全唐诗','yuding','','[]','西陵潮信滿，島嶼入中流。越客依風水，相思南渡頭。',48,'御定全唐詩/json/148.json','["西陵潮信滿，島嶼入中流。越客依風水，相思南渡頭。", "寒光生極浦，暮雪映滄洲。何事揚帆去，空驚海上鷗。"]'),
('yuding-52','雲門寺訪靈一上人','劉長卿','唐','御定全唐诗','yuding','','[]','所思勞日夕，惆悵去西東。禪客知何在，春山到處同。',48,'御定全唐詩/json/148.json','["所思勞日夕，惆悵去西東。禪客知何在，春山到處同。", "獨行殘雪裏，相見白雲中。請近東林寺，窮年事遠公。"]'),
('yuding-53','送陸羽之茅山，寄李延陵','劉長卿','唐','御定全唐诗','yuding','','[]','延陵衰草遍，有路問茅山。雞犬驅將去，煙霞擬不還。',48,'御定全唐詩/json/148.json','["延陵衰草遍，有路問茅山。雞犬驅將去，煙霞擬不還。", "新家彭澤縣，舊國穆陵關。處處逃名姓，無名亦是閑。"]'),
('yuding-54','寄靈一上人初還雲門','劉長卿','唐','御定全唐诗','yuding','','[]','寒霜白雲裏，法侶自相攜。竹徑通城下，松風隔水西。',48,'御定全唐詩/json/148.json','["寒霜白雲裏，法侶自相攜。竹徑通城下，松風隔水西。", "方同沃洲去，不作武陵迷。仿佛知心處，高峰是會稽。"]'),
('yuding-55','寄靈一上人','劉長卿','唐','御定全唐诗','yuding','','[]','高僧本姓竺，開士舊名林。一去春山裏，千峰不可尋。',48,'御定全唐詩/json/148.json','["高僧本姓竺，開士舊名林。一去春山裏，千峰不可尋。", "新年芳草遍，終日白雲深。欲徇微官去，懸知訝此心。"]'),
('yuding-56','送韓司直','劉長卿','唐','御定全唐诗','yuding','','[]','游吳還入越，來往任風波。複送王孫去，其如春草何。',48,'御定全唐詩/json/148.json','["游吳還入越，來往任風波。複送王孫去，其如春草何。", "岸明殘雪在，潮滿夕陽多。季子楊柳廟，停舟試一過。"]'),
('yuding-57','酬李郎中夜登蘇州城樓見寄','劉長卿','唐','御定全唐诗','yuding','','[]','辛勤萬里道，蕭索九秋殘。日照閩中夜，天凝海上寒。',48,'御定全唐詩/json/148.json','["辛勤萬里道，蕭索九秋殘。日照閩中夜，天凝海上寒。", "客程無地遠，主意在人安。遙寄登樓作，空知行路難。"]'),
('yuding-58','送人遊越','劉長卿','唐','御定全唐诗','yuding','','[]','未習風波事，初為吳越遊。露沾湖色曉，月照海門秋。',48,'御定全唐詩/json/148.json','["未習風波事，初為吳越遊。露沾湖色曉，月照海門秋。", "梅市門何在，蘭亭水尚流。西陵待潮處，落日滿扁舟。"]'),
('yuding-59','贈普門上人','劉長卿','唐','御定全唐诗','yuding','','[]','支公身欲老，長在沃洲多。惠力堪傳教，禪心久伏魔。',48,'御定全唐詩/json/148.json','["支公身欲老，長在沃洲多。惠力堪傳教，禪心久伏魔。", "山雲隨坐夏，江草伴頭陀。借問回心後，賢愚去幾何。"]'),
('yuding-60','送康判官往新安','劉長卿','唐','御定全唐诗','yuding','','[]','不向新安去，那知江路長。猿聲近廬霍，水色勝瀟湘。',48,'御定全唐詩/json/148.json','["不向新安去，那知江路長。猿聲近廬霍，水色勝瀟湘。", "驛路收殘雨，漁家帶夕陽。何須愁旅泊，使者有輝光。"]'),
('yuding-61','送顧長','劉長卿','唐','御定全唐诗','yuding','','[]','由來山水客，複道向新安。半是乘槎便，全非行路難。',48,'御定全唐詩/json/148.json','["由來山水客，複道向新安。半是乘槎便，全非行路難。", "晨裝林月在，野飯浦沙寒。嚴子千年後，何人釣舊灘。"]'),
('yuding-62','九日登李明府北樓','劉長卿','唐','御定全唐诗','yuding','','[]','九日登高望，蒼蒼遠樹低。人煙湖草裏，山翠縣樓西。',48,'御定全唐詩/json/148.json','["九日登高望，蒼蒼遠樹低。人煙湖草裏，山翠縣樓西。", "霜降鴻聲切，秋深客思迷。無勞白衣酒，陶令自相攜。"]'),
('yuding-63','同諸公登樓','劉長卿','唐','御定全唐诗','yuding','','[]','秋草行將暮，登樓客思驚。千家同霽色，一雁報寒聲。',48,'御定全唐詩/json/148.json','["秋草行將暮，登樓客思驚。千家同霽色，一雁報寒聲。", "北望無鄉信，東遊滯客行。今君佩銅墨，還有越鄉情。"]'),
('yuding-64','送友人南游','劉長卿','唐','御定全唐诗','yuding','','[]','不愁尋水遠，自愛逐連山。雖在春風裏，猶從芳草間。',48,'御定全唐詩/json/148.json','["不愁尋水遠，自愛逐連山。雖在春風裏，猶從芳草間。", "去程何用計，勝事且相關。旅逸同群鳥，悠悠往復還。"]'),
('yuding-65','送裴二十一','劉長卿','唐','御定全唐诗','yuding','','[]','多病長無事，開筵暫送君。正愁帆帶雨，莫望水連雲。',48,'御定全唐詩/json/148.json','["多病長無事，開筵暫送君。正愁帆帶雨，莫望水連雲。", "客思閑偏極，川程遠更分。不須論早晚，惆悵又離群。"]'),
('yuding-66','送張判官罷使東歸','劉長卿','唐','御定全唐诗','yuding','','[]','白首辭知己，滄洲憶舊居。落潮回野艇，積雪臥官廬。',48,'御定全唐詩/json/148.json','["白首辭知己，滄洲憶舊居。落潮回野艇，積雪臥官廬。", "范叔寒猶在，周王歲欲除。春山數畝地，歸去帶經鉏。"]'),
('yuding-67','早春','劉長卿','唐','御定全唐诗','yuding','','[]','微雨夜來歇，江南春色回。本驚時不住，還恐老相催。',48,'御定全唐詩/json/148.json','["微雨夜來歇，江南春色回。本驚時不住，還恐老相催。", "人好千場醉，花無百日開。豈堪滄海畔，為客十年來。"]'),
('yuding-68','送青苗鄭判官歸江西','劉長卿','唐','御定全唐诗','yuding','','[]','三苗餘古地，五稼滿秋田。來問周公稅，歸輸漢俸錢。',48,'御定全唐詩/json/148.json','["三苗餘古地，五稼滿秋田。來問周公稅，歸輸漢俸錢。", "江城寒背日，湓水暮連天。南楚凋殘後，疲民賴爾憐。"]'),
('yuding-69','過包尊師山院','劉長卿','唐','御定全唐诗','yuding','','[]','賣藥曾相識，吹簫此複聞。杏花誰是主，桂樹獨留君。',48,'御定全唐詩/json/148.json','["賣藥曾相識，吹簫此複聞。杏花誰是主，桂樹獨留君。", "漱玉臨丹井，圍棋訪白雲。道經今為寫，不慮惜鵝群。"]'),
('yuding-70','故女道士婉儀太原郭氏挽歌詞','劉長卿','唐','御定全唐诗','yuding','','[]','作范宮闈睦，歸真道藝超。馭風仙路遠，背日帝宮遙。',96,'御定全唐詩/json/148.json','["作范宮闈睦，歸真道藝超。馭風仙路遠，背日帝宮遙。", "鸞殿空留處，霓裳已罷朝。淮王哀不盡，松柏但蕭蕭。", "宮禁恩長隔，神仙道已分。人間驚早露，天上失朝雲。", "逝水年無限，佳城日易曛。簫聲將薤曲，哀斷不堪聞。"]'),
('yuding-71','少年行','劉長卿','唐','御定全唐诗','yuding','','[]','射飛誇侍獵，行樂愛聯鑣。薦枕青蛾豔，鳴鞭白馬驕。',48,'御定全唐詩/json/148.json','["射飛誇侍獵，行樂愛聯鑣。薦枕青蛾豔，鳴鞭白馬驕。", "曲房珠翠合，深巷管弦調。日晚春風裏，衣香滿路飄。"]'),
('yuding-72','歸弋陽山居，留別盧、邵二侍禦','劉長卿','唐','御定全唐诗','yuding','','[]','渺渺歸何處，沿流附客船。久依鄱水住，頻稅越人田。',48,'御定全唐詩/json/148.json','["渺渺歸何處，沿流附客船。久依鄱水住，頻稅越人田。", "偶俗機偏少，安閒性所便。只應君少慣，又欲寄林泉。"]'),
('yuding-73','赴江西，湖上贈皇甫曾之宣州','劉長卿','唐','御定全唐诗','yuding','','[]','莫恨扁舟去，川途我更遙。東西潮渺渺，離別雨蕭蕭。',48,'御定全唐詩/json/148.json','["莫恨扁舟去，川途我更遙。東西潮渺渺，離別雨蕭蕭。", "流水通春谷，青山過板橋。天涯有來客，遲爾訪漁樵。"]'),
('yuding-74','湘中紀行十首：湘妃廟','劉長卿','唐','御定全唐诗','yuding','','[]','荒祠古木暗，寂寂此江濆。未作湘南雨，知為何處雲。',48,'御定全唐詩/json/148.json','["荒祠古木暗，寂寂此江濆。未作湘南雨，知為何處雲。", "苔痕斷珠履，草色帶羅裙。莫唱迎仙曲，空山不可聞。"]'),
('yuding-75','湘中紀行十首：斑竹岩','劉長卿','唐','御定全唐诗','yuding','','[]','蒼梧在何處，斑竹自成林。點點留殘淚，枝枝寄此心。',48,'御定全唐詩/json/148.json','["蒼梧在何處，斑竹自成林。點點留殘淚，枝枝寄此心。", "寒山響易滿，秋水影偏深。欲覓樵人路，蒙籠不可尋。"]'),
('yuding-76','湘中紀行十首：洞山陽','劉長卿','唐','御定全唐诗','yuding','','[]','舊日仙成處，荒林客到稀。白雲將犬去，芳草任人歸。',48,'御定全唐詩/json/148.json','["舊日仙成處，荒林客到稀。白雲將犬去，芳草任人歸。", "空谷無行徑，深山少落暉。桃園幾家住，誰為掃荊扉。"]'),
('yuding-77','湘中紀行十首：雲母溪','劉長卿','唐','御定全唐诗','yuding','','[]','雲母映溪水，溪流知幾春。深藏武陵客，時過洞庭人。',48,'御定全唐詩/json/148.json','["雲母映溪水，溪流知幾春。深藏武陵客，時過洞庭人。", "白髮慚皎鏡，清光媚奫淪。寥寥古松下，歲晚掛頭巾。"]'),
('yuding-78','湘中紀行十首：赤沙湖','劉長卿','唐','御定全唐诗','yuding','','[]','茫茫葭菼外，一望一沾衣。秋水連天闊，涔陽何處歸。',48,'御定全唐詩/json/148.json','["茫茫葭菼外，一望一沾衣。秋水連天闊，涔陽何處歸。", "沙鷗積暮雪，川日動寒暉。楚客來相問，孤舟泊釣磯。"]'),
('yuding-79','湘中紀行十首：秋雲嶺','劉長卿','唐','御定全唐诗','yuding','','[]','山色無定姿，如煙複如黛。孤峰夕陽後，翠嶺秋天外。',48,'御定全唐詩/json/148.json','["山色無定姿，如煙複如黛。孤峰夕陽後，翠嶺秋天外。", "雲起遙蔽虧，江回頻向背。不知今遠近，到處猶相對。"]'),
('yuding-80','湘中紀行十首：花石潭','劉長卿','唐','御定全唐诗','yuding','','[]','江楓日搖落，轉愛寒潭靜。水色淡如空，山光復相映。',48,'御定全唐詩/json/148.json','["江楓日搖落，轉愛寒潭靜。水色淡如空，山光復相映。", "人閑流更慢，魚戲波難定。楚客往來多，偏知白鷗性。"]'),
('yuding-81','湘中紀行十首：石圍峰','劉長卿','唐','御定全唐诗','yuding','','[]','前山帶秋色，獨往秋江晚。疊嶂入雲多，孤峰去人遠。',48,'御定全唐詩/json/148.json','["前山帶秋色，獨往秋江晚。疊嶂入雲多，孤峰去人遠。", "夤緣不可到，蒼翠空在眼。渡口問漁家，桃源路深淺。"]'),
('yuding-82','湘中紀行十首：浮石瀨','劉長卿','唐','御定全唐诗','yuding','','[]','秋月照瀟湘，月明聞蕩槳。石橫晚瀨急，水落寒沙廣。',48,'御定全唐詩/json/148.json','["秋月照瀟湘，月明聞蕩槳。石橫晚瀨急，水落寒沙廣。", "眾嶺猿嘯重，空江人語響。清暉朝複暮，如待扁舟賞。"]'),
('yuding-83','湘中紀行十首：橫龍渡','劉長卿','唐','御定全唐诗','yuding','','[]','空傳古岸下，曾見蛟龍去。秋水晚沉沉，猶疑在深處。',48,'御定全唐詩/json/148.json','["空傳古岸下，曾見蛟龍去。秋水晚沉沉，猶疑在深處。", "亂聲沙上石，倒影雲中樹。獨見一扁舟，樵人往來渡。"]'),
('yuding-84','雜詠八首上禮部李侍郎：幽琴','劉長卿','唐','御定全唐诗','yuding','','[]','月色滿軒白，琴聲宜夜闌。飀飀青絲上，靜聽松風寒。',48,'御定全唐詩/json/148.json','["月色滿軒白，琴聲宜夜闌。飀飀青絲上，靜聽松風寒。", "古調雖自愛，今人多不彈。向君投此曲，所貴知音難。"]'),
('yuding-85','雜詠八首上禮部李侍郎：晚桃','劉長卿','唐','御定全唐诗','yuding','','[]','四月深澗底，桃花方欲然。寧知地勢下，遂使春風偏。',48,'御定全唐詩/json/148.json','["四月深澗底，桃花方欲然。寧知地勢下，遂使春風偏。", "此意頗堪惜，無言誰為傳。過時君未賞，空媚幽林前。"]'),
('yuding-86','雜詠八首上禮部李侍郎：疲馬','劉長卿','唐','御定全唐诗','yuding','','[]','玄黃一疲馬，筋力盡胡塵。驤首北風夕，徘徊鳴向人。',48,'御定全唐詩/json/148.json','["玄黃一疲馬，筋力盡胡塵。驤首北風夕，徘徊鳴向人。", "誰憐棄置久，卻與駑駘親。猶戀長城外，青青寒草春。"]'),
('yuding-87','雜詠八首上禮部李侍郎：春鏡','劉長卿','唐','御定全唐诗','yuding','','[]','寶鏡淩曙開，含虛淨如水。獨懸秦臺上，萬象清光裏。',48,'御定全唐詩/json/148.json','["寶鏡淩曙開，含虛淨如水。獨懸秦臺上，萬象清光裏。", "豈慮高鑒偏，但防流塵委。不知娉婷色，回照今何似。"]'),
('yuding-88','雜詠八首上禮部李侍郎：古劍','劉長卿','唐','御定全唐诗','yuding','','[]','龍泉閑古匣，苔蘚淪此地。何意久藏鋒，翻令世人棄。',48,'御定全唐詩/json/148.json','["龍泉閑古匣，苔蘚淪此地。何意久藏鋒，翻令世人棄。", "鐵衣今正澀，寶刃猶可試。倘遇拂拭恩，應知剸犀利。"]'),
('yuding-89','雜詠八首上禮部李侍郎：舊井','劉長卿','唐','御定全唐诗','yuding','','[]','舊井依舊城，寒水深洞徹。下看百餘尺，一鏡光不滅。',48,'御定全唐詩/json/148.json','["舊井依舊城，寒水深洞徹。下看百餘尺，一鏡光不滅。", "素綆久未垂，清涼尚含潔。豈能無汲引，長訝君恩絕。"]'),
('yuding-90','雜詠八首上禮部李侍郎：白鷺','劉長卿','唐','御定全唐诗','yuding','','[]','亭亭常獨立，川上時延頸。秋水寒白毛，夕陽吊孤影。',48,'御定全唐詩/json/148.json','["亭亭常獨立，川上時延頸。秋水寒白毛，夕陽吊孤影。", "幽姿閑自媚，逸翮思一騁。如有長風吹，青雲在俄頃。"]'),
('yuding-91','雜詠八首上禮部李侍郎：寒釭','劉長卿','唐','御定全唐诗','yuding','','[]','向夕燈稍進，空堂彌寂寞。光寒對愁人，時複一花落。',48,'御定全唐詩/json/148.json','["向夕燈稍進，空堂彌寂寞。光寒對愁人，時複一花落。", "但恐明見累，何愁暗難托。戀君秋夜永，無使蘭膏薄。"]'),
('yuding-92','寄李侍禦','劉長卿','唐','御定全唐诗','yuding','','[]','舊國人未歸，芳洲草還碧。年年湖上亭，悵望江南客。',48,'御定全唐詩/json/148.json','["舊國人未歸，芳洲草還碧。年年湖上亭，悵望江南客。", "驄馬入關西，白雲獨何適。相思煙水外，唯有心不隔。"]'),
('yuding-93','晚泊湘江懷故人','劉長卿','唐','御定全唐诗','yuding','','[]','天涯片雲去，遙指帝鄉憶。惆悵增暮情，瀟湘複秋色。',48,'御定全唐詩/json/148.json','["天涯片雲去，遙指帝鄉憶。惆悵增暮情，瀟湘複秋色。", "扁舟宿何處，落日羨歸翼。萬里無故人，江鷗不相識。"]'),
('yuding-94','過鄔三湖上書齋','劉長卿','唐','御定全唐诗','yuding','','[]','何事東南客，忘機一釣竿。酒香開甕老，湖色對門寒。',48,'御定全唐詩/json/148.json','["何事東南客，忘機一釣竿。酒香開甕老，湖色對門寒。", "向郭青山送，臨池白鳥看。見君能浪跡，予亦厭微官。"]'),
('yuding-95','從軍六首','劉長卿','唐','御定全唐诗','yuding','','[]','回看虜騎合，城下漢兵稀。白刃兩相向，黃雲愁不飛。',216,'御定全唐詩/json/148.json','["回看虜騎合，城下漢兵稀。白刃兩相向，黃雲愁不飛。", "手中無尺鐵，徒欲突重圍。", "目極雁門道，青青邊草春。一身事征戰，匹馬同苦辛。", "末路成白首，功歸天下人。", "倚劍白日暮，望鄉登戍樓。北風吹羌笛，此夜關山愁。", "回首不無意，滹河空自流。", "黃沙一萬里，白首無人憐。報國劍已折，歸鄉身幸全。", "單于古台下，邊色寒蒼然。", "落日更蕭條，北風動枯草。將軍追虜騎，夜失陰山道。", "戰敗仍樹勳，韓彭但空老。", "草枯秋塞上，望見漁陽郭。胡馬嘶一聲，漢兵淚雙落。", "誰為吮瘡者，此事今人薄。"]'),
('yuding-96','龍門八詠：闕口','劉長卿','唐','御定全唐诗','yuding','','[]','秋山日搖落，秋水急波瀾。獨見魚龍氣，長令煙雨寒。',36,'御定全唐詩/json/148.json','["秋山日搖落，秋水急波瀾。獨見魚龍氣，長令煙雨寒。", "誰窮造化力，空向兩崖看。"]'),
('yuding-97','龍門八詠：水東渡','劉長卿','唐','御定全唐诗','yuding','','[]','山葉傍崖赤，千峰秋色多。夜泉發清響，寒渚生微波。',36,'御定全唐詩/json/148.json','["山葉傍崖赤，千峰秋色多。夜泉發清響，寒渚生微波。", "稍見沙上月，歸人爭渡河。"]'),
('yuding-98','龍門八詠：福公塔','劉長卿','唐','御定全唐诗','yuding','','[]','寂寞對伊水，經行長未還。東流自朝暮，千載空雲山。',36,'御定全唐詩/json/148.json','["寂寞對伊水，經行長未還。東流自朝暮，千載空雲山。", "誰見白鷗鳥，無心洲渚間。"]'),
('yuding-99','龍門八詠：遠公龕','劉長卿','唐','御定全唐诗','yuding','','[]','松路向精舍，花龕歸老僧。閑雲隨錫杖，落日低金繩。',36,'御定全唐詩/json/148.json','["松路向精舍，花龕歸老僧。閑雲隨錫杖，落日低金繩。", "入夜翠微裏，千峰明一燈。"]'),
('yuding-100','龍門八詠：石樓','劉長卿','唐','御定全唐诗','yuding','','[]','隱隱見花閣，隔河映青林。水田秋雁下，山寺夜鐘深。',36,'御定全唐詩/json/148.json','["隱隱見花閣，隔河映青林。水田秋雁下，山寺夜鐘深。", "寂寞群動息，風泉清道心。"]'),
('yuding-101','龍門八詠：下山','劉長卿','唐','御定全唐诗','yuding','','[]','誰識往來意，孤雲長自閑。風寒未渡水，日暮更看山。',36,'御定全唐詩/json/148.json','["誰識往來意，孤雲長自閑。風寒未渡水，日暮更看山。", "木落眾峰出，龍宮蒼翠間。"]'),
('yuding-102','龍門八詠：水西渡','劉長卿','唐','御定全唐诗','yuding','','[]','伊水搖鏡光，纖鱗如不隔。千龕道傍古，一鳥沙上白。',36,'御定全唐詩/json/148.json','["伊水搖鏡光，纖鱗如不隔。千龕道傍古，一鳥沙上白。", "何事還山雲，能留向城客。"]'),
('yuding-103','龍門八詠：渡水','劉長卿','唐','御定全唐诗','yuding','','[]','日暮下山來，千山暮鐘發。不知波上棹，還弄山中月。',36,'御定全唐詩/json/148.json','["日暮下山來，千山暮鐘發。不知波上棹，還弄山中月。", "伊水連白雲，東南遠明滅。"]'),
('yuding-104','月下聽砧','劉長卿','唐','御定全唐诗','yuding','','[]','夜靜掩寒城，清砧發何處。聲聲搗秋月，腸斷盧龍戍。',36,'御定全唐詩/json/148.json','["夜靜掩寒城，清砧發何處。聲聲搗秋月，腸斷盧龍戍。", "未得寄征人，愁霜複愁露。"]'),
('yuding-105','送丘為赴上都','劉長卿','唐','御定全唐诗','yuding','','[]','帝鄉何處是，歧路空垂泣。楚思愁暮多，川程帶潮急。',36,'御定全唐詩/json/148.json','["帝鄉何處是，歧路空垂泣。楚思愁暮多，川程帶潮急。", "潮歸人不歸，獨向空塘立。"]'),
('yuding-106','題大理黃主簿湖上高齋','劉長卿','唐','御定全唐诗','yuding','','[]','閉門湖水畔，自與白鷗親。竟日窗中岫，終年林下人。',60,'御定全唐詩/json/148.json','["閉門湖水畔，自與白鷗親。竟日窗中岫，終年林下人。", "俗輕儒服弊，家厭法官貧。多雨茅簷夜，空洲草徑春。", "桃源君莫愛，且作漢朝臣。"]'),
('yuding-107','平蕃曲三首','劉長卿','唐','御定全唐诗','yuding','','[]','吹角報蕃營，回軍欲洗兵。已教青海外，自築漢家城。',72,'御定全唐詩/json/148.json','["吹角報蕃營，回軍欲洗兵。已教青海外，自築漢家城。", "渺渺戍煙孤，茫茫塞草枯。隴頭那用閉，萬里不防胡。", "絕漠大軍還，平沙獨戍閑。空留一片石，萬古在燕山。"]'),
('yuding-108','送鄭說之歙州謁薛侍郎','劉長卿','唐','御定全唐诗','yuding','','[]','漂泊來千里，謳謠滿百城。漢家尊太守，魯國重諸生。',72,'御定全唐詩/json/148.json','["漂泊來千里，謳謠滿百城。漢家尊太守，魯國重諸生。", "俗變人難理，江傳水至清。船經危石住，路入亂山行。", "老得滄州趣，春傷白首情。嘗聞馬南郡，門下有康成。"]'),
('yuding-109','題獨孤使君湖上林亭','劉長卿','唐','御定全唐诗','yuding','','[]','出樹倚朱闌，吹鐃引上官。老農持鍤拜，時稼捲簾看。',72,'御定全唐詩/json/148.json','["出樹倚朱闌，吹鐃引上官。老農持鍤拜，時稼捲簾看。", "水對登龍淨，山當建隼寒。夕陽湖草動，秋色渚田寬。", "渤海人無事，荊州客獨安。謝公何足比，來往石門難。"]'),
('yuding-110','酬滁州李十六使君見贈','劉長卿','唐','御定全唐诗','yuding','','[]','滿鏡悲華髮，空山寄此身。白雲家自有，黃卷業長貧。',72,'御定全唐詩/json/148.json','["滿鏡悲華髮，空山寄此身。白雲家自有，黃卷業長貧。", "懶任垂竿老，狂因釀黍春。桃花迷聖代，桂樹狎幽人。", "幢蓋方臨郡，柴荊忝作鄰。但愁千騎至，石路卻生塵。"]'),
('yuding-111','送嚴維赴河南充嚴中丞幕府','劉長卿','唐','御定全唐诗','yuding','','[]','久別耶溪客，來乘使者軒。用才榮入幕，扶病喜同樽。',72,'御定全唐詩/json/148.json','["久別耶溪客，來乘使者軒。用才榮入幕，扶病喜同樽。", "山屐留何處，江帆去獨翻。暮情辭鏡水，秋夢識雲門。", "蓮府開花萼，桃園寄子孫。何當舉嚴助，遍沐漢朝恩。"]'),
('yuding-112','酬包諫議佶見寄之什','劉長卿','唐','御定全唐诗','yuding','','[]','佐郡愧頑疏，殊方親裏閭。家貧寒未度，身老歲將除。',72,'御定全唐詩/json/148.json','["佐郡愧頑疏，殊方親裏閭。家貧寒未度，身老歲將除。", "過雪山僧至，依陽野客舒。藥陳隨遠宦，梅發對幽居。", "落日棲鴞鳥，行人遺鯉魚。高文不可和，空愧學相如。"]'),
('yuding-113','棲霞寺東峰尋南齊明征君故居','劉長卿','唐','御定全唐诗','yuding','','[]','山人今不見，山鳥自相從。長嘯辭明主，終身臥此峰。',72,'御定全唐詩/json/148.json','["山人今不見，山鳥自相從。長嘯辭明主，終身臥此峰。", "泉源通石徑，澗戶掩塵容。古墓依寒草，前朝寄老松。", "片雲生斷壁，萬壑遍疏鐘。惆悵空歸去，猶疑林下逢。"]'),
('yuding-114','奉和趙給事使君，留贈李婺州舍人兼謝舍人別駕之什','劉長卿','唐','御定全唐诗','yuding','','[]','便道訪情親，東方千騎塵。禁深分直夜，地遠獨行春。',72,'御定全唐詩/json/148.json','["便道訪情親，東方千騎塵。禁深分直夜，地遠獨行春。", "絳闕辭明主，滄洲識近臣。雲山隨候吏，雞犬逐歸人。", "庭顧婆娑老，邦傳蔽芾新。玄暉翻佐理，聞到郡齋頻。"]'),
('yuding-115','行營酬呂侍御時尚書問罪襄陽軍次漢東境上侍御以州鄰寇賊復有水火迫於征稅詩以見諭','劉長卿','唐','御定全唐诗','yuding','','[]','不敢淮南臥，來趨漢將營。受辭瞻左鉞，扶疾往前旌。',72,'御定全唐詩/json/148.json','["不敢淮南臥，來趨漢將營。受辭瞻左鉞，扶疾往前旌。", "井稅鶉衣樂，壺漿鶴發迎。水歸餘斷岸，烽至掩孤城。", "晚日歸千騎，秋風合五兵。孔璋才素健，早晚檄書成。"]'),
('yuding-116','登遷仁樓，酬子婿李穆','劉長卿','唐','御定全唐诗','yuding','','[]','臨風敞麗譙，落日聽吹鐃。歸路空回首，新章已在腰。',72,'御定全唐詩/json/148.json','["臨風敞麗譙，落日聽吹鐃。歸路空回首，新章已在腰。", "非才受官謗，無政作人謠。儉歲安三戶，餘年寄六條。", "春蕪生楚國，古樹過隋朝。賴有東床客，池塘免寂寥。"]'),
('yuding-117','別李氏女子','劉長卿','唐','御定全唐诗','yuding','','[]','念爾嫁猶近，稚年那別親。臨歧方教誨，所貴和六姻。',72,'御定全唐詩/json/148.json','["念爾嫁猶近，稚年那別親。臨歧方教誨，所貴和六姻。", "俯首戴荊釵，欲拜淒且嚬。本來儒家子，莫恥梁鴻貧。", "漢川若可涉，水清石磷磷。天涯遠鄉婦，月下孤舟人。"]'),
('yuding-118','長沙早春雪後臨湘水，呈同游諸子','劉長卿','唐','御定全唐诗','yuding','','[]','汀洲暖漸淥，煙景淡相和。舉目方如此，歸心豈奈何。',72,'御定全唐詩/json/148.json','["汀洲暖漸淥，煙景淡相和。舉目方如此，歸心豈奈何。", "日華浮野雪，春色染湘波。北渚生芳草，東風變舊柯。", "江山古思遠，猿鳥暮情多。君問漁人意，滄浪自有歌。"]'),
('yuding-119','自道林寺西入石路至麓山寺，過法崇禪師故居','劉長卿','唐','御定全唐诗','yuding','','[]','山僧候谷口，石路拂莓苔。深入泉源去，遙從樹杪回。',72,'御定全唐詩/json/148.json','["山僧候谷口，石路拂莓苔。深入泉源去，遙從樹杪回。", "香隨青靄散，鐘過白雲來。野雪空齋掩，山風古殿開。", "桂寒知自發，松老問誰栽。惆悵湘江水，何人更渡杯。"]'),
('yuding-120','和袁郎中破賊後軍行過剡中山水謹上太尉','劉長卿','唐','御定全唐诗','yuding','','[]','剡路除荊棘，王師罷鼓鼙。農歸滄海畔，圍解赤城西。',72,'御定全唐詩/json/148.json','["剡路除荊棘，王師罷鼓鼙。農歸滄海畔，圍解赤城西。", "赦罪春陽發，收兵太白低。遠峰來馬首，橫笛入猿啼。", "蘭渚催新幄，桃源識故蹊。已聞開閣待，誰許臥東溪。"]'),
('yuding-121','送鄭十二還廬山別業','劉長卿','唐','御定全唐诗','yuding','','[]','潯陽數畝宅，歸臥掩柴關。谷口何人待，門前秋草閑。',72,'御定全唐詩/json/148.json','["潯陽數畝宅，歸臥掩柴關。谷口何人待，門前秋草閑。", "忘機賣藥罷，無語杖藜還。舊筍成寒竹，空齋向暮山。", "水流經捨下，雲去到人間。桂樹花應發，因行寄一攀。"]'),
('yuding-122','至饒州尋陶十七不在寄贈','劉長卿','唐','御定全唐诗','yuding','','[]','謫宦投東道，逢君已北轅。孤蓬向何處，五柳不開門。',72,'御定全唐詩/json/148.json','["謫宦投東道，逢君已北轅。孤蓬向何處，五柳不開門。", "去國空回首，懷賢欲訴冤。梅枝橫嶺嶠，竹路過湘源。", "月下高秋雁，天南獨夜猿。離心與流水，萬里共朝昏。"]'),
('yuding-123','奉陪鄭中丞自宣州解印，與諸侄宴餘幹後溪','劉長卿','唐','御定全唐诗','yuding','','[]','跡遠親魚鳥，功成厭鼓鼙。林中阮生集，池上謝公題。',72,'御定全唐詩/json/148.json','["跡遠親魚鳥，功成厭鼓鼙。林中阮生集，池上謝公題。", "戶牖垂藤合，藩籬插槿齊。夕陽山向背，春草水東西。", "度雨諸峰出，看花幾路迷。何勞問秦漢，更入武陵溪。"]'),
('yuding-0','同諸公袁郎中宴筵喜加章服','劉長卿','唐','御定全唐诗','yuding','','[]','手詔來筵上，腰金向粉闈。勳名傳舊閣，蹈舞著新衣。',72,'御定全唐詩/json/149.json','["手詔來筵上，腰金向粉闈。勳名傳舊閣，蹈舞著新衣。", "白社同遊在，滄洲此會稀。寒笳發後殿，秋草送西歸。", "世難常摧敵，時閑已息機。魯連功可讓，千載一相揮。"]'),
('yuding-1','毗陵送鄒結先赴河南充判官','劉長卿','唐','御定全唐诗','yuding','','[]','王事相逢少，雲山奈別何。芳年臨水怨，瓜步上潮過。',72,'御定全唐詩/json/149.json','["王事相逢少，雲山奈別何。芳年臨水怨，瓜步上潮過。", "客路方經楚，鄉心共渡河。凋殘春草在，離亂故城多。", "罷戰逢時泰，輕徭佇俗和。東西此分手，惆悵恨煙波。"]'),
('yuding-2','送徐大夫赴廣州','劉長卿','唐','御定全唐诗','yuding','','[]','上將壇場拜，南荒羽檄招。遠人來百越，元老事三朝。',72,'御定全唐詩/json/149.json','["上將壇場拜，南荒羽檄招。遠人來百越，元老事三朝。", "霧繞龍山暗，山連象郡遙。路分江淼淼，軍動馬蕭蕭。", "畫角知秋氣，樓船逐暮潮。當令輸貢賦，不使外夷驕。"]'),
('yuding-3','九日題蔡國公主樓','劉長卿','唐','御定全唐诗','yuding','','[]','主第人何在，重陽客暫尋。水餘龍鏡色，雲罷鳳簫音。',72,'御定全唐詩/json/149.json','["主第人何在，重陽客暫尋。水餘龍鏡色，雲罷鳳簫音。", "暗牖藏昏曉，蒼苔換古今。晴山卷幔出，秋草閉門深。", "籬菊仍新吐，庭槐尚舊陰。年年畫梁燕，來去豈無心。"]'),
('yuding-4','送荀八過山陰舊縣，兼寄剡中諸官','劉長卿','唐','御定全唐诗','yuding','','[]','訪舊山陰縣，扁舟到海涯。故林嗟滿歲，春草憶佳期。',72,'御定全唐詩/json/149.json','["訪舊山陰縣，扁舟到海涯。故林嗟滿歲，春草憶佳期。", "晚景千峰亂，晴江一鳥遲。桂香留客處，楓暗泊舟時。", "舊石曹娥篆，空山夏禹祠。剡溪多隱吏，君去道相思。"]'),
('yuding-5','奉餞元侍郎加豫章採訪兼賜章服','劉長卿','唐','御定全唐诗','yuding','','[]','任重兼烏府，時平偃豹韜。澄清湘水變，分別楚山高。',72,'御定全唐詩/json/149.json','["任重兼烏府，時平偃豹韜。澄清湘水變，分別楚山高。", "花對彤襜發，霜和白雪操。黃金裝舊馬，青草換新袍。", "嶺暗猿啼月，江寒鷺映濤。豫章生宇下，無使翳蓬蒿。"]'),
('yuding-6','奉餞郎中四兄罷餘杭太守承恩加侍御史充行軍司馬赴汝南行營','劉長卿','唐','御定全唐诗','yuding','','[]','星使三江上，天波萬里通。權分金節重，恩借鐵冠雄。',72,'御定全唐詩/json/149.json','["星使三江上，天波萬里通。權分金節重，恩借鐵冠雄。", "梅吹前軍發，棠陰舊府空。殘春錦障外，初日羽旗東。", "岸柳遮浮鷁，江花隔避驄。離心在何處，芳草滿吳宮。"]'),
('yuding-7','送賈侍禦克復後入京','劉長卿','唐','御定全唐诗','yuding','','[]','對酒心不樂，見君動行舟。回看暮帆隱，獨向空江愁。',72,'御定全唐詩/json/149.json','["對酒心不樂，見君動行舟。回看暮帆隱，獨向空江愁。", "晴雲淡初夜，春塘深慢流。溫顏風霜霽，喜氣煙塵收。", "馳馹數千里，朝天十二樓。因之報親愛，白髮生滄洲。"]'),
('yuding-8','會稽王處士草堂壁畫衡霍諸山','劉長卿','唐','御定全唐诗','yuding','','[]','粉壁衡霍近，群峰如可攀。能令堂上客，見盡湖南山。',72,'御定全唐詩/json/149.json','["粉壁衡霍近，群峰如可攀。能令堂上客，見盡湖南山。", "青翠數千仞，飛來方丈間。歸雲無處滅，去鳥何時還。", "勝事日相對，主人常獨閑。稍看林壑晚，佳氣生重關。"]'),
('yuding-9','惠福寺與陳留諸官茶會','劉長卿','唐','御定全唐诗','yuding','','[]','到此機事遣，自嫌塵網迷。因知萬法幻，盡與浮雲齊。',72,'御定全唐詩/json/149.json','["到此機事遣，自嫌塵網迷。因知萬法幻，盡與浮雲齊。", "疏竹映高枕，空花隨杖藜。香飄諸天外，日隱雙林西。", "傲吏方見狎，真僧幸相攜。能令歸客意，不復還東溪。"]'),
('yuding-10','金陵西泊舟臨江樓','劉長卿','唐','御定全唐诗','yuding','','[]','蕭條金陵郭，舊是帝王州。日暮望鄉處，雲邊江樹秋。',72,'御定全唐詩/json/149.json','["蕭條金陵郭，舊是帝王州。日暮望鄉處，雲邊江樹秋。", "楚雲不可托，楚水只堪愁。行客千萬里，滄波朝暮流。", "迢迢洛陽夢，獨臥清川樓。異鄉共如此，孤帆難久遊。"]'),
('yuding-11','題靈佑上人法華院木蘭花','劉長卿','唐','御定全唐诗','yuding','','[]','庭種南中樹，年華幾度新。已依初地長，獨發舊園春。',72,'御定全唐詩/json/149.json','["庭種南中樹，年華幾度新。已依初地長，獨發舊園春。", "映日成華蓋，搖風散錦茵。色空榮落處，香醉往來人。", "菡萏千燈遍，芳菲一雨均。高柯倘為楫，渡海有良因。"]'),
('yuding-12','宿嚴維宅送包佶','劉長卿','唐','御定全唐诗','yuding','','[]','江湖同避地，分首自依依。盡室今為客，驚秋空念歸。',72,'御定全唐詩/json/149.json','["江湖同避地，分首自依依。盡室今為客，驚秋空念歸。", "歲儲無別墅，寒服羨鄰機。草色村橋晚，蟬聲江樹稀。", "夜深宜共醉，時難忍相違。何事隨陽雁，汀洲忽背飛。"]'),
('yuding-13','送從弟貶袁州','劉長卿','唐','御定全唐诗','yuding','','[]','何事成遷客，思歸不見鄉。游吳經萬里，吊屈向三湘。',72,'御定全唐詩/json/149.json','["何事成遷客，思歸不見鄉。游吳經萬里，吊屈向三湘。", "水與荊巫接，山通鄢郢長。名羞黃綬系，身是白眉郎。", "獨結南枝恨，應思北雁行。憂來沽楚酒，老鬢莫凝霜。"]'),
('yuding-14','無錫東郭送友人游越','劉長卿','唐','御定全唐诗','yuding','','[]','客路風霜曉，郊原春興餘。平蕪不可望，遊子去何如。',72,'御定全唐詩/json/149.json','["客路風霜曉，郊原春興餘。平蕪不可望，遊子去何如。", "煙水乘湖闊，雲山適越初。舊都懷作賦，古穴覓藏書。", "碑缺曹娥宅，林荒逸少居。江湖無限意，非獨為樵漁。"]'),
('yuding-15','送邵州判官往南','劉長卿','唐','御定全唐诗','yuding','','[]','看君發原隰，駟牡志皇皇。始罷滄江令，還隨粉署郎。',72,'御定全唐詩/json/149.json','["看君發原隰，駟牡志皇皇。始罷滄江令，還隨粉署郎。", "海沂軍未息，河兗歲仍荒。徵稅人全少，榛蕪虜近亡。", "新知行宋遠，相望隔淮長。早晚裁書寄，銀鉤佇八行。"]'),
('yuding-16','出豐縣界寄韓明府','劉長卿','唐','御定全唐诗','yuding','','[]','回首古原上，未能辭舊鄉。西風收暮雨，隱隱分芒碭。',72,'御定全唐詩/json/149.json','["回首古原上，未能辭舊鄉。西風收暮雨，隱隱分芒碭。", "賢友此為邑，令名滿徐方。音容想在眼，暫若升琴堂。", "疲馬顧春草，行人看夕陽。自非傳尺素，誰為論中腸。"]'),
('yuding-17','別陳留諸官','劉長卿','唐','御定全唐诗','yuding','','[]','戀此東道主，能令西上遲。徘徊暮郊別，惆悵秋風時。',72,'御定全唐詩/json/149.json','["戀此東道主，能令西上遲。徘徊暮郊別，惆悵秋風時。", "上國邈千里，夷門難再期。行人望落日，歸馬嘶空陂。", "不愧寶刀贈，維懷瓊樹枝。音塵倘未接，夢寐徒相思。"]'),
('yuding-18','觀李湊所畫美人障子','劉長卿','唐','御定全唐诗','yuding','','[]','愛爾含天姿，丹青有殊智。無間已得象，象外更生意。',96,'御定全唐詩/json/149.json','["愛爾含天姿，丹青有殊智。無間已得象，象外更生意。", "西子不可見，千載無重還。空令浣沙態，猶在含毫間。", "一笑豈易得，雙蛾如有情。窗風不舉袖，但覺羅衣輕。", "華堂翠幕春風來，內閣金屏曙色開。此中一見亂人目，"]'),
('yuding-19','送史判官奏事之靈武，兼寄巴西親故','劉長卿','唐','御定全唐诗','yuding','','[]','中州日紛梗，天地何時泰。獨有西歸心，遙懸夕陽外。',72,'御定全唐詩/json/149.json','["中州日紛梗，天地何時泰。獨有西歸心，遙懸夕陽外。", "故人奉章奏，此去論利害。陽雁南渡江，征驂去相背。", "因君欲寄遠，何處問親愛。空使滄洲人，相思減衣帶。"]'),
('yuding-20','自鄱陽還，道中寄褚征君','劉長卿','唐','御定全唐诗','yuding','','[]','南風日夜起，萬里孤帆漾。元氣連洞庭，夕陽落波上。',72,'御定全唐詩/json/149.json','["南風日夜起，萬里孤帆漾。元氣連洞庭，夕陽落波上。", "故人煙水隔，複此遙相望。江信久寂寥，楚雲獨惆悵。", "愛君清川口，弄月時棹唱。白首無子孫，一生自疏曠。"]'),
('yuding-21','石樑湖有寄','劉長卿','唐','御定全唐诗','yuding','','[]','故人千里道，滄波一年別。夜上明月樓，相思楚天闊。',72,'御定全唐詩/json/149.json','["故人千里道，滄波一年別。夜上明月樓，相思楚天闊。", "瀟瀟清秋暮，嫋嫋涼風發。湖色淡不流，沙鷗遠還滅。", "煙波日已遠，音問日已絕。歲晏空含情，江皋綠芳歇。"]'),
('yuding-22','送沈少府之任淮南','劉長卿','唐','御定全唐诗','yuding','','[]','惜君滯南楚，枳棘徒棲鳳。獨與千里帆，春風遠相送。',72,'御定全唐詩/json/149.json','["惜君滯南楚，枳棘徒棲鳳。獨與千里帆，春風遠相送。", "此行山水好，時物亦應眾。一鳥飛長淮，百花滿雲夢。", "相期丹霄路，遙聽清風頌。勿為州縣卑，時來自為用。"]'),
('yuding-23','嚴子瀨東送馬處直歸蘇','劉長卿','唐','御定全唐诗','yuding','','[]','望君舟已遠，落日潮未退。目送滄海帆，人行白雲外。',72,'御定全唐詩/json/149.json','["望君舟已遠，落日潮未退。目送滄海帆，人行白雲外。", "江中遠回首，波上生微靄。秋色姑蘇台，寒流子陵瀨。", "相送苦易散，動別知難會。從此日相思，空令減衣帶。"]'),
('yuding-24','宿懷仁縣南湖，寄東海荀處士','劉長卿','唐','御定全唐诗','yuding','','[]','向夕斂微雨，晴開湖上天。離人正惆悵，新月愁嬋娟。',84,'御定全唐詩/json/149.json','["向夕斂微雨，晴開湖上天。離人正惆悵，新月愁嬋娟。", "佇立白沙曲，相思滄海邊。浮雲自來去，此意誰能傳。", "一水不相見，千峰隨客船。寒塘起孤雁，夜色分鹽田。", "時複一延首，憶君如眼前。"]'),
('yuding-25','初至洞庭，懷灞陵別業','劉長卿','唐','御定全唐诗','yuding','','[]','長安邈千里，日夕懷雙闕。已是洞庭人，猶看灞陵月。',84,'御定全唐詩/json/149.json','["長安邈千里，日夕懷雙闕。已是洞庭人，猶看灞陵月。", "誰堪去鄉意，親戚想天末。昨夜夢中歸，煙波覺來闊。", "江皋見芳草，孤客心欲絕。豈訝青春來，但傷經時別。", "長天不可望，鳥與浮雲沒。"]'),
('yuding-26','題蕭郎中開元寺新構幽寂亭','劉長卿','唐','御定全唐诗','yuding','','[]','康樂愛山水，賞心千載同。結茅依翠微，伐木開蒙籠。',96,'御定全唐詩/json/149.json','["康樂愛山水，賞心千載同。結茅依翠微，伐木開蒙籠。", "孤峰倚青霄，一徑去不窮。候客石苔上，禮僧雲樹中。", "曠然見滄洲，自遠來清風。五馬留穀口，雙旌薄煙虹。", "沉沉眾香積，眇眇諸天空。獨往應未遂，蒼生思謝公。"]'),
('yuding-27','同姜浚題裴式微餘幹東齋','劉長卿','唐','御定全唐诗','yuding','','[]','世事終成夢，生涯欲半過。白雲心已矣，滄海意如何。',96,'御定全唐詩/json/149.json','["世事終成夢，生涯欲半過。白雲心已矣，滄海意如何。", "藜杖全吾道，榴花養太和。春風騎馬醉，江月釣魚歌。", "散帙看蟲蠹，開門見雀羅。遠山終日在，芳草傍人多。", "吏體莊生傲，方言楚俗訛。屈平君莫吊，腸斷洞庭波。"]'),
('yuding-28','贈元容州','劉長卿','唐','御定全唐诗','yuding','','[]','擁旌臨合浦，上印臥長沙。海徼長無戍，湘山獨種畬。',96,'御定全唐詩/json/149.json','["擁旌臨合浦，上印臥長沙。海徼長無戍，湘山獨種畬。", "政傳通歲貢，才惜過年華。萬里依孤劍，千峰寄一家。", "累征期旦暮，未起戀煙霞。避世歌芝草，休官醉菊花。", "舊遊如夢裏，此別是天涯。何事滄波上，漂漂逐海槎。"]'),
('yuding-29','夏口送長寧楊明府歸荊南，因寄幕府諸公','劉長卿','唐','御定全唐诗','yuding','','[]','關西楊太尉，千載德猶聞。白日俱終老，清風獨至君。',96,'御定全唐詩/json/149.json','["關西楊太尉，千載德猶聞。白日俱終老，清風獨至君。", "身承遠祖遺，才出眾人群。舉世貪荊玉，全家戀楚雲。", "向煙帆杳杳，臨水葉紛紛。草覆昭丘綠，江從夏口分。", "高名光盛府，異姓寵殊勳。百越今無事，南征欲罷軍。"]'),
('yuding-30','奉和杜相公新移長興宅，呈元相公','劉長卿','唐','御定全唐诗','yuding','','[]','間世生賢宰，同心奉至尊。功高開北第，機靜灌中園。',96,'御定全唐詩/json/149.json','["間世生賢宰，同心奉至尊。功高開北第，機靜灌中園。", "入並蟬冠影，歸分騎士喧。窗聞漢宮漏，家識杜陵源。", "獻替常焚槁，優閑獨對萱。花香逐荀令，草色對王孫。", "有地先開閣，何人不掃門。江湖難自退，明主托元元。"]'),
('yuding-31','湖南使還，留辭辛大夫','劉長卿','唐','御定全唐诗','yuding','','[]','王師勞近甸，兵食仰諸侯。天子無南顧，元勳在上游。',96,'御定全唐詩/json/149.json','["王師勞近甸，兵食仰諸侯。天子無南顧，元勳在上游。", "大才生間氣，盛業拯橫流。風景隨搖筆，山川入運籌。", "羽觴交餞席，旄節對歸舟。鶯識春深恨，猿知日去愁。", "別離花寂寂，南北水悠悠。唯有家兼國，終身共所憂。"]'),
('yuding-32','泛曲阿後湖，簡同游諸公','劉長卿','唐','御定全唐诗','yuding','','[]','元氣浮積水，沉沉深不流。春風萬頃綠，映帶至徐州。',96,'御定全唐詩/json/149.json','["元氣浮積水，沉沉深不流。春風萬頃綠，映帶至徐州。", "為客難適意，逢君方暫遊。夤緣白蘋際，日暮滄浪舟。", "渡口微月進，林西殘雨收。水雲去仍濕，沙鶴鳴相留。", "且習子陵隱，能忘生事憂。此中深有意，非為釣魚鉤。"]'),
('yuding-33','北游酬孟雲卿見寄','劉長卿','唐','御定全唐诗','yuding','','[]','忽忽忘前事，事願能相乖。衣馬日羸弊，誰辨行與才。',84,'御定全唐詩/json/149.json','["忽忽忘前事，事願能相乖。衣馬日羸弊，誰辨行與才。", "善道居貧賤，潔服蒙塵埃。行行無定止，懍坎難歸來。", "慈母憂疾疹，室家念棲萊。幸君夙姻親，深見中外懷。", "俟子惜時節，悵望臨高臺。"]'),
('yuding-34','冬夜宿揚州開元寺烈公房，送李侍禦之江東','劉長卿','唐','御定全唐诗','yuding','','[]','遷客投百越，窮陰淮海凝。中原馳困獸，萬里棲饑鷹。',96,'御定全唐詩/json/149.json','["遷客投百越，窮陰淮海凝。中原馳困獸，萬里棲饑鷹。", "寂寂連宇下，愛君心自弘。空堂來霜氣，永夜清明燈。", "發後望煙水，相思勞寢興。暮帆背楚郭，江色浮金陵。", "此去爾何恨，近名予未能。爐峰若便道，為訪東林僧。"]'),
('yuding-35','南楚懷古','劉長卿','唐','御定全唐诗','yuding','','[]','南國久蕪沒，我來空郁陶。君看章華宮，處處生蓬蒿。',96,'御定全唐詩/json/149.json','["南國久蕪沒，我來空郁陶。君看章華宮，處處生蓬蒿。", "但見陵與穀，豈知賢與豪。精魂托古木，寶劍捐江皋。", "倚棹下晴景，回舟隨晚濤。碧雲暮寥落，湖上秋天高。", "往事那堪問，此心徒自勞。獨餘湘水上，千載聞離騷。"]'),
('yuding-36','上湖田館南樓憶朱宴','劉長卿','唐','御定全唐诗','yuding','','[]','漂泊日複日，洞庭今更秋。白雲如有意，萬里望孤舟。',96,'御定全唐詩/json/149.json','["漂泊日複日，洞庭今更秋。白雲如有意，萬里望孤舟。", "何事愛成別，空令登此樓。天光映波動，月影隨江流。", "鶴唳靜寒渚，猿啼深夜洲。歸期誠已促，清景仍相留。", "頃者慕獨往，爾來悲遠遊。風波自此去，桂水空離憂。"]'),
('yuding-37','送姚八之句容舊任，便歸江南','劉長卿','唐','御定全唐诗','yuding','','[]','故人還水國，春色動離憂。碧草千萬里，滄江朝暮流。',96,'御定全唐詩/json/149.json','["故人還水國，春色動離憂。碧草千萬里，滄江朝暮流。", "桃花迷舊路，萍葉蕩歸舟。遠戍看京口，空城問石頭。", "折芳佳麗地，望月西南樓。猿鳥共孤嶼，煙波連數州。", "誰家過楚老，何處戀江鷗。尺素能相報，湖山若個憂。"]'),
('yuding-38','睢陽贈李司倉','劉長卿','唐','御定全唐诗','yuding','','[]','白露變時候，蛩聲暮啾啾。飄飄洛陽客，惆悵梁園秋。',96,'御定全唐詩/json/149.json','["白露變時候，蛩聲暮啾啾。飄飄洛陽客，惆悵梁園秋。", "只為乏生計，爾來成遠遊。一身不家食，萬事從人求。", "且喜接餘論，足堪資小留。寒城落日後，砧杵令人愁。", "歸路歲時盡，長河朝夕流。非君深意願，誰複能相憂。"]'),
('yuding-39','杪秋洞庭中，懷亡道士謝太虛','劉長卿','唐','御定全唐诗','yuding','','[]','漂泊日複日，洞庭今更秋。青楓亦何意，此夜催人愁。',96,'御定全唐詩/json/149.json','["漂泊日複日，洞庭今更秋。青楓亦何意，此夜催人愁。", "惆悵客中月，徘徊江上樓。心知楚天遠，目送滄波流。", "羽客久已歿，微言無處求。空餘白雲在，容與隨孤舟。", "千里杳難望，一身當獨遊。故園複何許，江海徒遲留。"]'),
('yuding-40','同郭參謀詠崔僕射淮南節度使廳前竹','劉長卿','唐','御定全唐诗','yuding','','[]','昔種梁王苑，今移漢將壇。蒙籠低冕過，青翠捲簾看。',96,'御定全唐詩/json/149.json','["昔種梁王苑，今移漢將壇。蒙籠低冕過，青翠捲簾看。", "得地移根遠，經霜抱節難。開花成鳳實，嫩筍長魚竿。", "藹藹軍容靜，蕭蕭郡宇寬。細音和角暮，疏影上門寒。", "湘浦何年變，山陽幾處殘。不知軒屏側，歲晚對袁安。"]'),
('yuding-41','硤石遇雨，宴前主簿從兄子英宅','劉長卿','唐','御定全唐诗','yuding','','[]','縣城蒼翠裏，客路兩崖開。硤石雲漠漠，東風吹雨來。',96,'御定全唐詩/json/149.json','["縣城蒼翠裏，客路兩崖開。硤石雲漠漠，東風吹雨來。", "吾兄此為吏，薄宦知無媒。方寸抱秦鏡，聲名傳楚材。", "折腰五鬥間，黽勉隨塵埃。秩滿少餘俸，家貧仍散財。", "誰言次東道，暫預傾金罍。雖欲少留此，其如歸限催。"]'),
('yuding-42','江中晚釣，寄荊南一二相識','劉長卿','唐','御定全唐诗','yuding','','[]','楚郭微雨收，荊門遙在目。漾舟水雲裏，日暮春江綠。',96,'御定全唐詩/json/149.json','["楚郭微雨收，荊門遙在目。漾舟水雲裏，日暮春江綠。", "霽華靜洲渚，暝色連松竹。月出波上時，人歸渡頭宿。", "一身已無累，萬事更何欲。漁父自夷猶，白鷗不羈束。", "既憐滄浪水，複愛滄浪曲。不見眼中人，相思心斷續。"]'),
('yuding-43','九日岳陽待黃遂、張渙','劉長卿','唐','御定全唐诗','yuding','','[]','別君頗已久，離念與時積。楚水空浮煙，江樓望歸客。',96,'御定全唐詩/json/149.json','["別君頗已久，離念與時積。楚水空浮煙，江樓望歸客。", "徘徊正佇想，仿佛如暫覿。心目徒自親，風波尚相隔。", "青林泊舟處，猿鳥愁孤驛。遙見郭外山，蒼然雨中夕。", "季鷹久疏曠，叔度早疇昔。反棹來何遲，黃花候君摘。"]'),
('yuding-44','題王少府堯山隱處，簡陸鄱陽','劉長卿','唐','御定全唐诗','yuding','','[]','故人滄洲吏，深與世情薄。解印二十年，委身在丘壑。',96,'御定全唐詩/json/149.json','["故人滄洲吏，深與世情薄。解印二十年，委身在丘壑。", "買田楚山下，妻子自耕鑿。群動心有營，孤雲本無著。", "因收溪上釣，遂接林中酌。對酒春日長，山村杏花落。", "陸生鄱陽令，獨步建溪作。早晚休此官，隨君永棲托。"]'),
('yuding-45','晚次湖口有懷','劉長卿','唐','御定全唐诗','yuding','','[]','靄然空水合，目極平江暮。南望天無涯，孤帆落何處。',96,'御定全唐詩/json/149.json','["靄然空水合，目極平江暮。南望天無涯，孤帆落何處。", "頃為衡湘客，頗見湖山趣。朝氣和楚雲，夕陽映江樹。", "帝鄉勞想望，萬里心來去。白髮生扁舟，滄波滿歸路。", "秋風今已至，日夜雁南度。木葉辭洞庭，紛紛落無數。"]'),
('yuding-46','陪元侍禦游支硎山寺','劉長卿','唐','御定全唐诗','yuding','','[]','支公去已久，寂寞龍華會。古木閉空山，蒼然暮相對。',96,'御定全唐詩/json/149.json','["支公去已久，寂寞龍華會。古木閉空山，蒼然暮相對。", "林巒非一狀，水石有餘態。密竹藏晦明，群峰爭向背。", "峰峰帶落日，步步入青靄。香氣空翠中，猿聲暮雲外。", "留連南台客，想像西方內。因逐溪水還，觀心兩無礙。"]'),
('yuding-47','桂陽西州晚泊古橋村住人','劉長卿','唐','御定全唐诗','yuding','','[]','洛陽別離久，江上心可得。惆悵增暮情，瀟湘複秋色。',96,'御定全唐詩/json/149.json','["洛陽別離久，江上心可得。惆悵增暮情，瀟湘複秋色。", "故山隔何處，落日羨歸翼。滄海空自流，白鷗不相識。", "悲蛩滿荊渚，輟棹徒沾臆。行客念寒衣，主人愁夜織。", "帝鄉片雲去，遙寄千里憶。南路隨天長，征帆杳無極。"]'),
('yuding-48','夕次簷石湖，夢洛陽親故','劉長卿','唐','御定全唐诗','yuding','','[]','天涯望不盡，日暮愁獨去。萬里雲海空，孤帆向何處。',96,'御定全唐詩/json/149.json','["天涯望不盡，日暮愁獨去。萬里雲海空，孤帆向何處。", "寄身煙波裏，頗得湖山趣。江氣和楚雲，秋聲亂楓樹。", "如何異鄉縣，日複懷親故。遙與洛陽人，相逢夢中路。", "不堪明月裏，更值清秋暮。倚棹對滄波，歸心共誰語。"]'),
('yuding-49','按覆後歸睦州，贈苗侍禦','劉長卿','唐','御定全唐诗','yuding','','[]','地遠心難達，天高謗易成。羊腸留覆轍，虎口脫餘生。',120,'御定全唐詩/json/149.json','["地遠心難達，天高謗易成。羊腸留覆轍，虎口脫餘生。", "直氏偷金枉，於家決獄明。一言知己重，片議殺身輕。", "日下人誰憶，天涯客獨行。年光銷蹇步，秋氣入衰情。", "建德知何在，長江問去程。孤舟百口渡，萬里一猿聲。", "落日開鄉路，空山向郡城。豈令冤氣積，千古在長平。"]'),
('yuding-50','奉寄婺州李使君舍人','劉長卿','唐','御定全唐诗','yuding','','[]','建隼罷鳴珂，初傳來暮歌。漁樵識太古，草樹得陽和。',120,'御定全唐詩/json/149.json','["建隼罷鳴珂，初傳來暮歌。漁樵識太古，草樹得陽和。", "東道諸生從，南依遠客過。天清婺女出，土厚絳人多。", "永日空相望，流年複幾何。崖開當夕照，葉去逐寒波。", "眼暗經難受，身閑劍懶磨。似鴞占賈誼，上馬試廉頗。", "窮分安藜藿，衰容勝薜蘿。只應隨越鳥，南翥托高柯。"]'),
('yuding-51','哭魏兼遂','劉長卿','唐','御定全唐诗','yuding','','[]','古今俱此去，修短竟誰分。樽酒空如在，弦琴肯重聞。',120,'御定全唐詩/json/149.json','["古今俱此去，修短竟誰分。樽酒空如在，弦琴肯重聞。", "一門同逝水，萬事共浮雲。舊館何人宅，空山遠客墳。", "艱危貧且共，少小秀而文。獨行依窮巷，全身出亂軍。", "歲時長寂寞，煙月自氛氳。壟樹隨人古，山門對日曛。", "泛舟悲向子，留劍贈徐君。來去雲陽路，傷心江水濆。"]'),
('yuding-52','負謫後登幹越亭作','劉長卿','唐','御定全唐诗','yuding','','[]','天南愁望絕，亭上柳條新。落日獨歸鳥，孤舟何處人。',120,'御定全唐詩/json/149.json','["天南愁望絕，亭上柳條新。落日獨歸鳥，孤舟何處人。", "生涯投越徼，世業陷胡塵。杳杳鐘陵暮，悠悠鄱水春。", "秦台悲白首，楚澤怨青蘋。草色迷征路，鶯聲傷逐臣。", "獨醒空取笑，直道不容身。得罪風霜苦，全生天地仁。", "青山數行淚，滄海一窮鱗。牢落機心盡，惟憐鷗鳥親。"]'),
('yuding-53','留題李明府霅溪水堂','劉長卿','唐','御定全唐诗','yuding','','[]','寥寥此堂上，幽意複誰論。落日無王事，青山在縣門。',120,'御定全唐詩/json/149.json','["寥寥此堂上，幽意複誰論。落日無王事，青山在縣門。", "雲峰向高枕，漁釣入前軒。晚竹疏簾影，春苔雙履痕。", "荷香隨坐臥，湖色映晨昏。虛牖閑生白，鳴琴靜對言。", "暮禽飛上下，春水帶清渾。遠岸誰家柳，孤煙何處村。", "謫居投瘴癘，離思過湘沅。從此扁舟去，誰堪江浦猿。"]'),
('yuding-54','入白沙渚，夤緣二十五裏至石窟山下，懷天臺陸山人','劉長卿','唐','御定全唐诗','yuding','','[]','遠嶼靄將夕，玩幽行自遲。歸人不計日，流水閑相隨。',120,'御定全唐詩/json/149.json','["遠嶼靄將夕，玩幽行自遲。歸人不計日，流水閑相隨。", "輟棹古崖口，捫蘿春景遲。偶因回舟次，寧與前山期。", "對此瑤草色，懷君瓊樹枝。浮雲去寂寞，白鳥相因依。", "何事愛高隱，但令勞遠思。窮年臥海嶠，永望愁天涯。", "吾亦從此去，扁舟何所之。迢迢江上帆，千里東風吹。"]'),
('yuding-55','禪智寺上方懷演和尚，寺即和尚所創','劉長卿','唐','御定全唐诗','yuding','','[]','絕巘東林寺，高僧惠遠公。買園隋苑下，持缽楚城中。',120,'御定全唐詩/json/149.json','["絕巘東林寺，高僧惠遠公。買園隋苑下，持缽楚城中。", "鬥極千燈近，煙波萬井通。遠山低月殿，寒木露花宮。", "紺宇焚香淨，滄洲擺霧空。雁來秋色裏，曙起早潮東。", "飛錫今何在，蒼生待發蒙。白雲翻送客，庭樹自辭風。", "舍筏追開士，回舟狎釣翁。平生江海意，惟共白鷗同。"]'),
('yuding-56','賈侍郎自會稽使迴篇什盈卷兼蒙見寄一首與余有挂冠之期因書數事率成十韻','劉長卿','唐','御定全唐诗','yuding','','[]','江上逢星使，南來自會稽。驚年一葉落，按俗五花嘶。',120,'御定全唐詩/json/149.json','["江上逢星使，南來自會稽。驚年一葉落，按俗五花嘶。", "上國悲蕪梗，中原動鼓鼙。報恩看鐵劍，銜命出金閨。", "風物催歸緒，雲峰發詠題。天長百越外，潮上小江西。", "鳥道通閩嶺，山光落剡溪。暮帆千里思，秋夜一猿啼。", "柏樹榮新壟，桃源憶故蹊。若能為休去，行複草萋萋。"]'),
('yuding-57','秋日夏口涉漢陽，獻李相公','劉長卿','唐','御定全唐诗','yuding','','[]','日望衡門處，心知漢水濆。偶乘青雀舫，還在白鷗群。',120,'御定全唐詩/json/149.json','["日望衡門處，心知漢水濆。偶乘青雀舫，還在白鷗群。", "間氣生靈秀，先朝翼戴勳。藏弓身已退，焚槁事難聞。", "舊業成青草，全家寄白雲。松蘿長稚子，風景逐新文。", "山帶寒城出，江依古岸分。楚歌悲遠客，羌笛怨孤軍。", "鼎罷調梅久，門看種藥勤。十年猶去國，黃葉又紛紛。"]'),
('yuding-58','歸沛縣道中晚泊留侯城','劉長卿','唐','御定全唐诗','yuding','','[]','訪古此城下，子房安在哉。白雲去不反，危堞空崔嵬。',120,'御定全唐詩/json/149.json','["訪古此城下，子房安在哉。白雲去不反，危堞空崔嵬。", "伊昔楚漢時，頗聞經濟才。運籌風塵下，能使天地開。", "蔓草日已積，長松日已摧。功名滿青史，祠廟唯蒼苔。", "百里暮程遠，孤舟川上回。進帆東風便，轉岸前山來。", "楚水澹相引，沙鷗閑不猜。扣舷從此去，延首仍裴回。"]'),
('yuding-59','關門望華山','劉長卿','唐','御定全唐诗','yuding','','[]','客路瞻太華，三峰高際天。夏雲亙百里，合遝遙相連。',120,'御定全唐詩/json/149.json','["客路瞻太華，三峰高際天。夏雲亙百里，合遝遙相連。", "雷雨飛半腹，太陽在其巔。翠微關上近，瀑布林梢懸。", "愛此眾容秀，能令西望偏。徘徊忘暝色，泱漭成陰煙。", "曾是朝百靈，亦聞會群仙。瓊漿豈易挹，毛女非空傳。", "仿佛仍佇想，幽期如眼前。金天有青廟，松柏隱蒼然。"]'),
('yuding-60','奉陪蕭使君入鮑達洞尋靈山寺','劉長卿','唐','御定全唐诗','yuding','','[]','山居秋更鮮，秋江相映碧。獨臨滄洲路，如待掛帆客。',120,'御定全唐詩/json/149.json','["山居秋更鮮，秋江相映碧。獨臨滄洲路，如待掛帆客。", "遂使康樂侯，披榛著雙屐。入雲開嶺道，永日尋泉脈。", "古寺隱青冥，空中寒磬夕。蒼苔絕行徑，飛鳥無去跡。", "樹杪下歸人，水聲過幽石。任情趣逾遠，移步奇屢易。", "蘿木靜濛濛，風煙深寂寂。徘徊未能去，畏共桃源隔。"]'),
('yuding-61','孫權故城下懷古，兼送友人歸建業','劉長卿','唐','御定全唐诗','yuding','','[]','雄圖爭割據，神器終不守。上下武昌城，長江竟何有。',120,'御定全唐詩/json/149.json','["雄圖爭割據，神器終不守。上下武昌城，長江竟何有。", "古來壯台榭，事往悲陵阜。寥落幾家人，猶依數株柳。", "威靈絕想像，蕪沒空林藪。野徑春草中，郊扉夕陽後。", "逢君從此去，背楚方東走。煙際指金陵，潮時過湓口。", "行人已何在，臨水徒揮手。惆悵不能歸，孤帆沒雲久。"]'),
('yuding-62','宿雙峰寺，寄盧七、李十六','劉長卿','唐','御定全唐诗','yuding','','[]','寥寥禪誦處，滿室蟲絲結。獨與山中人，無心生複滅。',120,'御定全唐詩/json/149.json','["寥寥禪誦處，滿室蟲絲結。獨與山中人，無心生複滅。", "徘徊雙峰下，惆悵雙峰月。杳杳暮猿深，蒼蒼古松列。", "玩奇不可盡，漸遠更幽絕。林暗僧獨歸，石寒泉且咽。", "竹房響輕吹，蘿徑陰餘雪。臥澗曉何遲，背岩春未發。", "此遊誠多趣，獨往共誰閱。得意空自歸，非君豈能說。"]'),
('yuding-63','京口懷洛陽舊居，兼寄廣陵二三知己','劉長卿','唐','御定全唐诗','yuding','','[]','川闊悲無梁，藹然滄波夕。天涯一飛鳥，日暮南徐客。',120,'御定全唐詩/json/149.json','["川闊悲無梁，藹然滄波夕。天涯一飛鳥，日暮南徐客。", "氣混京口雲，潮吞海門石。孤帆候風進，夜色帶江白。", "一水阻佳期，相望空脈脈。那堪歲芳盡，更使春夢積。", "故國胡塵飛，遠山楚雲隔。家人想何在，庭草為誰碧。", "惆悵空傷情，滄浪有餘跡。嚴陵七裏灘，攜手同所適。"]'),
('yuding-64','登揚州棲靈寺塔','劉長卿','唐','御定全唐诗','yuding','','[]','北塔淩空虛，雄觀壓川澤。亭亭楚雲外，千里看不隔。',120,'御定全唐詩/json/149.json','["北塔淩空虛，雄觀壓川澤。亭亭楚雲外，千里看不隔。", "遙對黃金台，浮輝亂相射。盤梯接元氣，半壁棲夜魄。", "稍登諸劫盡，若騁排霄翮。向是滄洲人，已為青雲客。", "雨飛千栱霽，日在萬家夕。鳥處高卻低，天涯遠如迫。", "江流入空翠，海嶠現微碧。向暮期下來，誰堪複行役。"]'),
('yuding-65','湖上遇鄭田','劉長卿','唐','御定全唐诗','yuding','','[]','故人青雲器，何意常窘迫。三十猶布衣，憐君頭已白。',120,'御定全唐詩/json/149.json','["故人青雲器，何意常窘迫。三十猶布衣，憐君頭已白。", "誰言此相見，暫得話疇昔。舊業今已蕪，還鄉返為客。", "扁舟伊獨往，鬥酒君自適。滄洲不可涯，孤帆去無跡。", "杯中忽複醉，湖上生月魄。湛湛江色寒，濛濛水雲夕。", "風波易迢遞，千里如咫尺。回首人已遙，南看楚天隔。"]'),
('yuding-66','雨中登沛縣樓，贈表兄郭少府','劉長卿','唐','御定全唐诗','yuding','','[]','楚澤秋更遠，雲雷有時作。晚陂帶殘雨，白水昏漠漠。',120,'御定全唐詩/json/149.json','["楚澤秋更遠，雲雷有時作。晚陂帶殘雨，白水昏漠漠。", "佇立收煙氛，洗然靜寥廓。捲簾高樓上，萬里看日落。", "為客頻改弦，辭家尚如昨。故山今不見，此鳥那可托。", "小邑務常閑，吾兄宦何薄。高標青雲器，獨立滄江鶴。", "惠愛原上情，殷勤丘中諾。何當遂良願，歸臥青山郭。"]'),
('yuding-67','灞東晚晴，簡同行薛棄、朱訓','劉長卿','唐','御定全唐诗','yuding','','[]','客心豁初霽，霽色暝玄灞。西向看夕陽，曈曈映桑柘。',120,'御定全唐詩/json/149.json','["客心豁初霽，霽色暝玄灞。西向看夕陽，曈曈映桑柘。", "二賢誠逸足，千里陪征駕。古樹枳道傍，人煙杜陵下。", "伊餘在羈束，且複隨造化。好道當有心，營生苦無暇。", "高賢幸茲偶，英達窮王霸。迢遞客王程，裴回主人夜。", "一熏知異質，片玉誰齊價。同結丘中緣，塵埃自茲謝。"]'),
('yuding-68','對雨贈濟陰馬少府考城蔣少府兼獻成武五兄南華二兄','劉長卿','唐','御定全唐诗','yuding','','[]','繁雲兼家思，彌望連濟北。日暮微雨中，州城帶秋色。',120,'御定全唐詩/json/149.json','["繁雲兼家思，彌望連濟北。日暮微雨中，州城帶秋色。", "蕭條主人靜，落葉飛不息。鄉夢寒更頻，蟲聲夜相逼。", "二賢縱橫器，久滯徒勞職。笑語和風騷，雍容事文墨。", "吾兄即時彥，前路良未測。秋水百丈清，寒松一枝直。", "此心欲引托，誰為生羽翼。且複頓歸鞍，杯中雪胸臆。"]'),
('yuding-69','李侍禦河北使回，至東京相訪','劉長卿','唐','御定全唐诗','yuding','','[]','故人南台秀，夙擅中朝美。擁傳從北來，飛霜日千里。',120,'御定全唐詩/json/149.json','["故人南台秀，夙擅中朝美。擁傳從北來，飛霜日千里。", "貧居幸相訪，顧我柴門裏。卻訝繡衣人，仍交布衣士。", "王程遽爾迫，別戀從此始。濁酒未暇斟，清文頗垂示。", "回瞻驄馬速，但見行塵起。日暮汀洲寒，春風渡流水。", "草色官道邊，桃花禦溝裏。天涯一鳥夕，惆悵知何已。"]'),
('yuding-70','吳中聞潼關失守，因奉寄淮南蕭判官','劉長卿','唐','御定全唐诗','yuding','','[]','一雁飛吳天，羈人傷暮律。松江風嫋嫋，波上片帆疾。',132,'御定全唐詩/json/149.json','["一雁飛吳天，羈人傷暮律。松江風嫋嫋，波上片帆疾。", "木落姑蘇台，霜收洞庭橘。蕭條長洲外，唯見寒山出。", "胡馬嘶秦雲，漢兵亂相失。關中因竊據，天下共憂栗。", "南楚有瓊枝，相思怨瑤瑟。一身寄滄洲，萬里看白日。", "赴敵甘負戈，論兵勇投筆。臨風但攘臂，擇木將委質。", "不如歸遠山，雲臥飯松栗。"]'),
('yuding-71','哭張員外繼','劉長卿','唐','御定全唐诗','yuding','','[]','慟哭鐘陵下，東流與別離。二星來不返，雙劍沒相隨。',144,'御定全唐詩/json/149.json','["慟哭鐘陵下，東流與別離。二星來不返，雙劍沒相隨。", "獨繼先賢傳，誰刊有道碑。故園荒峴曲，旅櫬寄天涯。", "白簡曾連拜，滄洲每共思。撫孤憐齒稚，歎逝顧身衰。", "泉壤成終古，雲山若在時。秋風鄰笛發，寒日寢門悲。", "世難愁歸路，家貧緩葬期。舊賓傷未散，夕臨咽常遲。", "自此辭張邵，何由見戴逵。獨聞山吏部，流涕訪孤兒。"]'),
('yuding-72','登東海龍興寺高頂望海，簡演公','劉長卿','唐','御定全唐诗','yuding','','[]','朐山壓海口，永望開禪宮。元氣遠相合，太陽生其中。',144,'御定全唐詩/json/149.json','["朐山壓海口，永望開禪宮。元氣遠相合，太陽生其中。", "豁然萬里餘，獨為百川雄。白波走雷電，黑霧藏魚龍。", "變化非一狀，晴明分眾容。煙開秦帝橋，隱隱橫殘虹。", "蓬島如在眼，羽人那可逢。偶聞真僧言，甚與靜者同。", "幽意頗相愜，賞心殊未窮。花間午時梵，雲外春山鐘。", "誰念遽成別，自憐歸所從。他時相憶處，惆悵西南峰。"]'),
('yuding-73','奉送從兄罷官之淮南','劉長卿','唐','御定全唐诗','yuding','','[]','何事浮溟渤，元戎棄莫邪。漁竿吾道在，鷗鳥世情賒。',144,'御定全唐詩/json/149.json','["何事浮溟渤，元戎棄莫邪。漁竿吾道在，鷗鳥世情賒。", "玄發他鄉換，滄洲此路遐。溯沿隨桂楫，醒醉任松華。", "離別誰堪道，艱危更可嗟。兵鋒搖海內，王命隔天涯。", "鐘漏移長樂，衣冠接永嘉。還當拂氛祲，那複臥雲霞。", "溪路漫岡轉，夕陽歸鳥斜。萬艘江縣郭，一樹海人家。", "揮袂看朱紱，揚帆指白沙。春風獨回首，愁思極如麻。"]'),
('yuding-74','落第，贈楊侍禦兼拜員外仍充安大夫判官赴范陽','劉長卿','唐','御定全唐诗','yuding','','[]','職副旌旄重，才兼識量通。使車遙肅物，邊策遠和戎。',144,'御定全唐詩/json/149.json','["職副旌旄重，才兼識量通。使車遙肅物，邊策遠和戎。", "擲地金聲著，從軍寶劍雄。官成稽古力，名達濟時功。", "肅穆烏臺上，雍容粉署中。含香初待漏，持簡舊生風。", "黠吏偏驚隼，貪夫輒避驄。且知榮已隔，誰謂道仍同。", "念舊追連茹，謀生任轉蓬。泣連三獻玉，瘡懼再傷弓。", "戀土函關外，瞻塵灞水東。他時書一劄，猶冀問途窮。"]'),
('yuding-75','初貶南巴至鄱陽，題李嘉佑江亭','劉長卿','唐','御定全唐诗','yuding','','[]','巴嶠南行遠，長江萬里隨。不才甘謫去，流水亦何之。',144,'御定全唐詩/json/149.json','["巴嶠南行遠，長江萬里隨。不才甘謫去，流水亦何之。", "地遠明君棄，天高酷吏欺。清山獨往路，芳草未歸時。", "流落還相見，悲歡話所思。猜嫌傷薏苡，愁暮向江籬。", "柳色迎高塢，荷衣照下帷。水雲初起重，暮鳥遠來遲。", "白首看長劍，滄洲寄釣絲。沙鷗驚小吏，湖月上高枝。", "稚子能吳語，新文怨楚辭。憐君不得意，川穀自逶迤。"]'),
('yuding-76','自紫陽觀至華陽洞，宿侯尊師草堂，簡同游李延年','劉長卿','唐','御定全唐诗','yuding','','[]','石門媚煙景，句曲盤江甸。南向佳氣濃，數峰遙隱見。',144,'御定全唐詩/json/149.json','["石門媚煙景，句曲盤江甸。南向佳氣濃，數峰遙隱見。", "漸臨華陽口，雲路入蔥蒨。七曜懸洞宮，五雲抱仙殿。", "銀函竟誰發，金液徒堪薦。千載空桃花，秦人深不見。", "東溪喜相遇，貞白如會面。青鳥來去閑，紅霞朝夕變。", "一從換仙骨，萬里乘飛電。蘿月延步虛，松花醉閑宴。", "幽人即長往，茂宰應交戰。明發歸琴堂，知君懶為縣。"]'),
('yuding-0','奉使新安自桐廬縣經嚴陵釣台宿七裏灘下寄使院諸公','劉長卿','唐','御定全唐诗','yuding','','[]','悠然釣台下，懷古時一望。江水自潺湲，行人獨惆悵。',144,'御定全唐詩/json/150.json','["悠然釣台下，懷古時一望。江水自潺湲，行人獨惆悵。", "新安從此始，桂楫方蕩漾。回轉百里間，青山千萬狀。", "連岸去不斷，對嶺遙相向。夾岸黛色愁，沉沉綠波上。", "夕陽留古木，水鳥拂寒浪。月下扣舷聲，煙中采菱唱。", "猶憐負羈束，未暇依清曠。牽役徒自勞，近名非所向。", "何時故山裏，卻醉松花釀。回首唯白雲，孤舟複誰訪。"]'),
('yuding-1','題虎丘寺','劉長卿','唐','御定全唐诗','yuding','','[]','青林虎丘寺，林際翠微路。仰見山僧來，遙從飛鳥處。',144,'御定全唐詩/json/150.json','["青林虎丘寺，林際翠微路。仰見山僧來，遙從飛鳥處。", "茲峰淪寶玉，千載唯丘墓。埋劍人空傳，鑿山龍已去。", "捫蘿披翳薈，路轉夕陽遽。虎嘯崖谷寒，猿鳴杉松暮。", "裴回北樓上，江海窮一顧。日映千里帆，鴉歸萬家樹。", "暫因愜所適，果得損外慮。庭暗棲閑雲，簷香滴甘露。", "久迷空寂理，多為繁華故。永欲投死生，餘生豈能誤。"]'),
('yuding-2','奉餞鄭中丞罷浙西節度還京','劉長卿','唐','御定全唐诗','yuding','','[]','天上移將星，元戎罷龍節。三軍含怨慕，橫吹聲斷絕。',144,'御定全唐詩/json/150.json','["天上移將星，元戎罷龍節。三軍含怨慕，橫吹聲斷絕。", "五馬嘶城隅，萬人臥車轍。滄洲浮雲暮，杳杳去帆發。", "回首不問家，歸心遙向闕。煙波限吳楚，日夕事淮越。", "吊影失所依，側身隨下列。孤蓬飛不定，長劍光未滅。", "綠綺為誰彈，綠芳堪自擷。悵然江南春，獨此湖上月。", "千里懷去思，百憂變華髮。頌聲滿江海，今古流不竭。"]'),
('yuding-3','送裴四判官赴河西軍試','劉長卿','唐','御定全唐诗','yuding','','[]','吏道豈易愜，如君誰與儔。逢時將騁驥，臨事無全牛。',144,'御定全唐詩/json/150.json','["吏道豈易愜，如君誰與儔。逢時將騁驥，臨事無全牛。", "鮑叔幸相知，田蘇頗同遊。英資挺孤秀，清論含古流。", "出塞佐持簡，辭家擁鳴騶。憲台貴公舉，幕府資良籌。", "武士佇明試，皇華難久留。陽關望天盡，洮水令人愁。", "萬里看一鳥，曠然煙霞收。晚花對古戍，春雪含邊州。", "道路難暫隔，音塵那可求。他時相望處，明月西南樓。"]'),
('yuding-4','旅次丹陽郡，遇康侍禦宣慰召募，兼別岑單父','劉長卿','唐','御定全唐诗','yuding','','[]','客心暮千里，回首煙花繁。楚水渡歸夢，春江連故園。',168,'御定全唐詩/json/150.json','["客心暮千里，回首煙花繁。楚水渡歸夢，春江連故園。", "羈人懷上國，驕虜窺中原。胡馬暫為害，漢臣多負恩。", "羽書晝夜飛，海內風塵昏。雙鬢日已白，孤舟心且論。", "繡衣從此來，汗馬宣王言。憂憤激忠勇，悲歡動黎元。", "南徐爭赴難，發卒如雲屯。倚劍看太白，洗兵臨海門。", "故人亦滄洲，少別堪傷魂。積翠下京口，歸潮落山根。", "如何天外帆，又此波上尊。空使憶君處，鶯聲催淚痕。"]'),
('yuding-5','客舍贈別韋九建赴任河南韋十七造赴任鄭縣就便覲省','劉長卿','唐','御定全唐诗','yuding','','[]','與子頗疇昔，常時仰英髦。弟兄盡公器，詩賦淩風騷。',168,'御定全唐詩/json/150.json','["與子頗疇昔，常時仰英髦。弟兄盡公器，詩賦淩風騷。", "頃者游上國，獨能光選曹。香名冠二陸，精鑒逢山濤。", "且副倚門望，莫辭趨府勞。桃花照彩服，草色連青袍。", "征馬臨素滻，離人傾濁醪。華山微雨霽，祠上殘雲高。", "而我倦棲屑，別君良郁陶。春風亦未已，旅思空滔滔。", "拙分甘棄置，窮居長蓬蒿。人生未鶤化，物議如鴻毛。", "迢遞兩鄉別，殷勤一寶刀。清琴有古調，更向何人操。"]'),
('yuding-6','送元八游汝南','劉長卿','唐','御定全唐诗','yuding','','[]','元生實奇邁，幸此論疇昔。刀筆素推高，鋒芒久無敵。',168,'御定全唐詩/json/150.json','["元生實奇邁，幸此論疇昔。刀筆素推高，鋒芒久無敵。", "縱橫濟時意，跌宕過人跡。破產供酒錢，盈門皆食客。", "田園頃失計，資用深相迫。生事誠可憂，嚴裝遠何適。", "世情薄恩義，俗態輕窮厄。四海金雖多，其如向人惜。", "迢遞朗陵道，悵望都門夕。向別伊水南，行看楚雲隔。", "繁蟬動高柳，匹馬嘶平澤。潢潦今正深，陂湖未澄碧。", "人生不得已，自可甘形役。勿複尊前酒，離居剩淒戚。"]'),
('yuding-7','奉和李大夫同呂評事太行苦熱行兼寄院中諸公仍呈王員外','劉長卿','唐','御定全唐诗','yuding','','[]','迢遞太行路，自古稱險惡。千騎儼欲前，群峰望如削。',192,'御定全唐詩/json/150.json','["迢遞太行路，自古稱險惡。千騎儼欲前，群峰望如削。", "火雲從中出，仰視飛鳥落。汗馬臥高原，危旌倚長薄。", "清風竟不至，赤日方煎鑠。石枯山木燋，鱗窮水泉涸。", "九重今旰食，萬里傳明略。諸將候軒車，元兇愁鼎鑊。", "何勞短兵接，自有長纓縛。通越事豈難，渡瀘功未博。", "朝辭羊腸阪，夕望貝丘郭。漳水斜繞營，常山遙入幕。", "永懷姑蘇下，遙寄建安作。白雪和難成，滄波意空托。", "陳琳書記好，王粲從軍樂。早晚歸漢廷，隨公上麟閣。"]'),
('yuding-8','洛陽主簿叔知和驛承恩赴選伏辭一首','劉長卿','唐','御定全唐诗','yuding','','[]','仲父王佐材，屈身仇香位。一從理京劇，萬事皆容易。',192,'御定全唐詩/json/150.json','["仲父王佐材，屈身仇香位。一從理京劇，萬事皆容易。", "則知無不可，通變有餘地。器宇溟渤寬，文鋒鏌鋣利。", "憧憧洛陽道，日夕皇華使。二載出江亭，一心奉王事。", "功成良可錄，道在知無愧。天府留香名，銓闈就明試。", "賦詩皆舊友，攀轍多新吏。彩服辭高堂，青袍擁征騎。", "此行季春月，時物正鮮媚。官柳陰相連，桃花色如醉。", "長安想在目，前路遙仿佛。落日看華山，關門逼青翠。", "行襜稍已隔，結戀無能慰。誰念尊酒間，裴回竹林意。"]'),
('yuding-9','題冤句宋少府廳留別','劉長卿','唐','御定全唐诗','yuding','','[]','宋侯人之秀，獨步南曹吏。世上無此才，天生一公器。',216,'御定全唐詩/json/150.json','["宋侯人之秀，獨步南曹吏。世上無此才，天生一公器。", "尚甘黃綬屈，未適青雲意。洞澈萬頃陂，昂藏千里驥。", "從宦聞苦節，應物推高誼。薄俸不自資，傾家共人費。", "顧予倦棲托，終日憂窮匱。開口即有求，私心豈無愧。", "幸逢東道主，因輟西征騎。對話堪息機，披文欲忘味。", "壺觴招過客，幾案無留事。綠樹映層城，蒼苔覆閑地。", "一言重然諾，累夕陪宴慰。何意秋風來，颯然動歸思。", "留歡殊自愜，去念能為累。草色愁別時，槐花落行次。", "臨期仍把手，此會良不易。他日瓊樹枝，相思勞夢寐。"]'),
('yuding-10','罷攝官後將還舊居，留辭李侍禦','劉長卿','唐','御定全唐诗','yuding','','[]','江海今為客，風波失所依。白雲心已負，黃綬計仍非。',264,'御定全唐詩/json/150.json','["江海今為客，風波失所依。白雲心已負，黃綬計仍非。", "累辱群公薦，頻沾一尉微。去緣焚玉石，來為采葑菲。", "州縣名何在，漁樵事亦違。故山桃李月，初服薜蘿衣。", "熊軾分朝寄，龍韜解賊圍。風謠傳吏體，雲物助兵威。", "白雪飄辭律，青春發禮闈。引軍橫吹動，援翰捷書揮。", "草映翻營綠，花臨檄羽飛。全吳爭轉戰，狂虜怯知機。", "憶昨趨金節，臨時廢玉徽。俗流應不厭，靜者或相譏。", "世難慵幹謁，時閑喜放歸。潘郎悲白髮，謝客愛清輝。", "樗散材因棄，交親跡已稀。獨愁看五柳，無事掩雙扉。", "世累多行路，生涯向釣磯。榜連溪水碧，家羨渚田肥。", "旅食傷飄梗，岩棲憶采薇。悠然獨歸去，回首望旌旗。"]'),
('yuding-11','贈別於群投筆赴安西','劉長卿','唐','御定全唐诗','yuding','','[]','風流一才子，經史仍滿腹。心鏡萬象生，文鋒眾人服。',264,'御定全唐詩/json/150.json','["風流一才子，經史仍滿腹。心鏡萬象生，文鋒眾人服。", "頃遊靈台下，頻棄荊山玉。蹭蹬空數年，裴回冀微祿。", "朅來投筆硯，長揖謝親族。且欲圖變通，安能守拘束。", "本持鄉曲譽，肯料泥塗辱。誰謂命迍邅，還令計反復。", "西戎今未弭，胡騎屯山谷。坐恃龍豹韜，全輕蜂蠆毒。", "拂衣從此去，擁傳一何速。元帥許提攜，他人佇瞻矚。", "出門寡儔侶，矧乃無僮僕。黠虜時相逢，黃沙暮愁宿。", "蕭條遠回首，萬里如在目。漢境天西窮，胡山海邊綠。", "想聞羌笛處，淚盡關山曲。地闊鳥飛遲，風寒馬毛縮。", "邊愁殊浩蕩，離思空斷續。塞上歸限賒，尊前別期促。", "知君志不小，一舉淩鴻鵠。且願樂從軍，功名在殊俗。"]'),
('yuding-12','送薛據宰涉縣','劉長卿','唐','御定全唐诗','yuding','','[]','故人河山秀，獨立風神異。人許白眉長，天資青雲器。',313,'御定全唐詩/json/150.json','["故人河山秀，獨立風神異。人許白眉長，天資青雲器。", "雄辭變文名，高價喧時議。下筆盈萬言，皆合古人意。", "一從負能名，數載猶卑位。寶劍誠可用，烹鮮是虛棄。", "昔聞在河上，高臥自無事。幾案終日閑，蒲鞭使人畏。", "頃因歲月滿，方謝風塵吏。頌德有輿人，薦賢逢八使。", "棲鸞往已屈，馴雀今可嗣。此道如不移，雲霄坐應致。", "縣前漳水綠，郭外晉山翠。日得謝客游，時堪陶令醉。", "前期今尚遠，握手空宴慰。驛路疏柳長，春城百花媚。", "裴回白日隱，暝色含天地。一鳥向灞陵，孤雲送行騎。", "夫君多述作，而我常諷味。賴有瓊瑤資，能寬別離思。", "槐陰覆堂殿，苔色上階砌。鳥倦自歸飛，雲閑獨容cV。", "既將慕幽絕，兼欲看定慧。遇物忘世緣，還家懶生計。", "無生妄已息，有妄心可制。心鏡常虛明，時人自淪翳。"]'),
('yuding-13','早春贈別趙居士還江左，時長卿下第歸嵩陽舊居','劉長卿','唐','御定全唐诗','yuding','','[]','見君風塵裏，意出風塵外。自有滄洲期，含情十餘載。',313,'御定全唐詩/json/150.json','["見君風塵裏，意出風塵外。自有滄洲期，含情十餘載。", "深居鳳城曲，日預龍華會。果得僧家緣，能遺俗人態。", "一身今已適，萬物知何愛。悟法電已空，看心水無礙。", "且將窮妙理，兼欲尋勝概。何獨謝客遊，當為遠公輩。", "放舟馳楚郭，負杖辭秦塞。目送南飛雲，令人想吳會。", "遙思舊遊處，仿佛疑相對。夜火金陵城，春煙石頭瀨。", "滄波極天末，萬里明如帶。一片孤客帆，飄然向青靄。", "楚天合江氣，雲色常霮zw。隱見湖中山，相連數州內。", "君行意可得，全與時人背。歸路隨楓林，還鄉念蓴菜。", "顧予尚羈束，何幸承眄睞。素願徒自勤，清機本難逮。", "累幸忝賓薦，末路逢沙汰。濩落名不成，裴回意空大。", "逢時雖貴達，守道甘易退。逆旅鄉夢頻，春風客心碎。", "別君日已遠，離念無明晦。予亦返柴荊，山田事耕耒。"]'),
('yuding-14','夜宴洛陽程九主簿宅送楊三山人往天臺尋智者禪師隱居','劉長卿','唐','御定全唐诗','yuding','','[]','東林問逋客，何處棲幽偏。滿腹萬餘卷，息機三十年。',360,'御定全唐詩/json/150.json','["東林問逋客，何處棲幽偏。滿腹萬餘卷，息機三十年。", "志圖良已久，鬢髮空蒼然。調嘯寄疏曠，形骸如棄捐。", "本家關西族，別業嵩陽田。雲臥能獨往，山棲幸周旋。", "垂竿不在魚，賣藥不為錢。藜杖閑倚壁，松花常醉眠。", "頃辭青溪隱，來訪赤縣仙。南畝自甘賤，中朝唯愛賢。", "仍空世諦法，遠結天臺緣。魏闕從此去，滄洲知所便。", "主人瓊枝秀，寵別瑤華篇。落日掃塵榻，春風吹客船。", "此行頗自適，物外誰能牽。弄棹白蘋裏，掛帆飛鳥邊。", "落潮見孤嶼，徹底觀澄漣。雁過湖上月，猿聲峰際天。", "群峰趨海嶠，千里黛相連。遙倚赤城上，曈曈初日圓。", "昔聞智公隱，此地常安禪。千載已如夢，一燈今尚傳。", "雲龕閉遺影，石窟無人煙。古寺暗喬木，春崖鳴細泉。", "流塵既寂寞，緬想增嬋娟。山鳥怨庭樹，門人思步蓮。", "夷猶懷永路，悵望臨清川。漁人來夢裏，沙鷗飛眼前。", "獨游豈易愜，群動多相纏。羨爾五湖夜，往來閑扣舷。"]'),
('yuding-15','瓜洲驛奉餞張侍御公拜膳部郎中却復憲臺充賀蘭大夫留後使之嶺南時侍御先在淮南幕府','劉長卿','唐','御定全唐诗','yuding','','[]','太華高標峻，青陽淑氣盤。屬辭傾渤澥，稱價掩琅玕。',480,'御定全唐詩/json/150.json','["太華高標峻，青陽淑氣盤。屬辭傾渤澥，稱價掩琅玕。", "楊葉頻推中，芸香早拜官。後來慚轍跡，先達仰門闌。", "佐劇勞黃綬，提綱疾素餐。風生趨府步，筆偃觸邪冠。", "骨鯁知難屈，鋒芒豈易幹。佇將調玉鉉，翻自落金丸。", "異議那容直，專權本畏彈。寸心寧有負，三黜竟無端。", "適喜鴻私降，旋驚羽檄攢。國憐朝市易，人怨虎狼殘。", "天地龍初見，風塵虜未殫。隨川歸少海，就日背長安。", "副相榮分寄，輸忠義不刊。擊胡馳汗馬，遷蜀扈鳴鑾。", "月罷名卿署，星懸上將壇。三軍搖旆出，百越畫圖觀。", "茅茹能相引，泥沙肯再蟠。兼榮知任重，交辟許才難。", "勁直隨台柏，芳香動省蘭。璧從全趙去，鵬自北溟摶。", "星象銜新寵，風霜帶舊寒。是非生倚伏，榮辱系悲歡。", "疇昔偏殊眄，屯蒙獨永歎。不才成擁腫，失計似邯鄲。", "江國傷移律，家山憶考盤。一為鷗鳥誤，三見露華團。", "回首青雲裏，應憐濁水瀾。愧將生事托，羞向鬢毛看。", "知己傷愆素，他人自好丹。鄉春連楚越，旅宿寄風湍。", "世路東流水，滄江一釣竿。松聲伯禹穴，草色子陵灘。", "度嶺情何遽，臨流興未闌。梅花分路遠，揚子上潮寬。", "夢想懷依倚，煙波限渺漫。且愁無去雁，甯冀少回鸞。", "極浦春帆迥，空郊晚騎單。獨憐南渡月，今夕送歸鞍。"]'),
('yuding-16','至德三年春正月時謬蒙差攝海鹽令聞王師收二京因書事寄上浙西節度李侍郎中丞行營五十韻','劉長卿','唐','御定全唐诗','yuding','','[]','天上胡星孛，人間反氣橫。風塵生汗馬，河洛縱長鯨。',576,'御定全唐詩/json/150.json','["天上胡星孛，人間反氣橫。風塵生汗馬，河洛縱長鯨。", "本謂才非據，誰知禍已萌。食參將可待，誅錯輒為名。", "萬里兵鋒接，三時羽檄驚。負恩殊鳥獸，流毒遍黎氓。", "朝市成蕪沒，干戈起戰爭。人心懸反復，天道暫虛盈。", "略地侵中土，傳烽到上京。王師陷魑魅，帝座逼欃槍。", "渭水嘶胡馬，秦山泣漢兵。關原馳萬騎，煙火亂千甍。", "鳳駕瞻西幸，龍樓議北征。自將行破竹，誰學去吹笙。", "白日重輪慶，玄穹再造榮。鬼神潛釋憤，夷狄遠輸誠。", "海內戎衣卷，關中賊壘平。山川隨轉戰，草木困橫行。", "區宇神功立，謳歌帝業成。天回萬象慶，龍見五雲迎。", "小苑春猶在，長安日更明。星辰歸正位，雷雨發殘生。", "文物登前古，簫韶下太清。未央新柳色，長樂舊鐘聲。", "八使推邦彥，中司案國程。蒼生屬伊呂，明主仗韓彭。", "凶醜將除蔓，奸豪已負荊。世危看柱石，時難識忠貞。", "薄伐征貔虎，長驅擁旆旌。吳山依重鎮，江月帶行營。", "金石懸詞律，煙雲動筆精。運籌初減灶，調鼎未和羹。", "北虜傳初解，東人望已傾。池塘催謝客，花木待春卿。", "昔忝登龍首，能傷困驥鳴。艱難悲伏劍，提握喜懸衡。", "巴曲誰堪聽，秦台自有情。遂令辭短褐，仍欲請長纓。", "久客田園廢，初官印綬輕。榛蕪上國路，苔蘚北山楹。", "懶慢羞趨府，驅馳憶退耕。榴花無暇醉，蓬發帶愁縈。", "地僻方言異，身微俗慮並。家憐雙鯉斷，才愧小鱗烹。", "滄海今猶滯，青陽歲又更。洲香生杜若，溪暖戲鵁鶄。", "煙水宜春候，褰關值晚晴。潮聲來萬井，山色映孤城。"]'),
('yuding-17','尋張逸人山居','劉長卿','唐','御定全唐诗','yuding','','[]','危石才通鳥道，空山更有人家。',28,'御定全唐詩/json/150.json','["危石才通鳥道，空山更有人家。", "桃源定在深處，澗水浮來落花。"]'),
('yuding-18','發越州赴潤州使院，留別鮑侍禦','劉長卿','唐','御定全唐诗','yuding','','[]','對水看山別離，孤舟日暮行遲。',28,'御定全唐詩/json/150.json','["對水看山別離，孤舟日暮行遲。", "江南江北春草，獨向金陵去時。"]'),
('yuding-19','送陸澧還吳中','劉長卿','唐','御定全唐诗','yuding','','[]','瓜步寒潮送客，楊柳暮雨沾衣。',28,'御定全唐詩/json/150.json','["瓜步寒潮送客，楊柳暮雨沾衣。", "故山南望何處，秋草連天獨歸。"]'),
('yuding-20','苕溪酬梁耿別後見寄','劉長卿','唐','御定全唐诗','yuding','','[]','清川永路何極，落日孤舟解攜。鳥向平蕪遠近，',35,'御定全唐詩/json/150.json','["清川永路何極，落日孤舟解攜。鳥向平蕪遠近，", "惆悵長沙謫去，江潭芳草萋萋。"]'),
('yuding-21','蛇浦橋下重送嚴維','劉長卿','唐','御定全唐诗','yuding','','[]','秋風颯颯鳴條，風月相和寂寥。黃葉一離一別，',35,'御定全唐詩/json/150.json','["秋風颯颯鳴條，風月相和寂寥。黃葉一離一別，", "明日行人已遠，空餘淚滴回潮。"]'),
('yuding-22','七裏灘重送','劉長卿','唐','御定全唐诗','yuding','','[]','秋江渺渺水空波，越客孤舟欲榜歌。',32,'御定全唐詩/json/150.json','["秋江渺渺水空波，越客孤舟欲榜歌。", "手折衰楊悲老大，故人零落已無多。"]'),
('yuding-23','家園瓜熟，是故蕭相公所遺瓜種，淒然感舊，因賦此詩','劉長卿','唐','御定全唐诗','yuding','','[]','事去人亡跡自留，黃花綠蒂不勝愁。',32,'御定全唐詩/json/150.json','["事去人亡跡自留，黃花綠蒂不勝愁。", "誰能更向青門外，秋草茫茫覓故侯。"]'),
('yuding-24','重送裴郎中貶吉州','劉長卿','唐','御定全唐诗','yuding','','[]','猿啼客散暮江頭，人自傷心水自流。',32,'御定全唐詩/json/150.json','["猿啼客散暮江頭，人自傷心水自流。", "同作逐臣君更遠，青山萬里一孤舟。"]'),
('yuding-25','尋盛禪師蘭若','劉長卿','唐','御定全唐诗','yuding','','[]','秋草黃花覆古阡，隔林何處起人煙。',32,'御定全唐詩/json/150.json','["秋草黃花覆古阡，隔林何處起人煙。", "山僧獨在山中老，唯有寒松見少年。"]'),
('yuding-26','寄許尊師','劉長卿','唐','御定全唐诗','yuding','','[]','獨上雲梯入翠微，濛濛煙雪映岩扉。',32,'御定全唐詩/json/150.json','["獨上雲梯入翠微，濛濛煙雪映岩扉。", "世人知在中峰裏，遙禮青山恨不歸。"]'),
('yuding-27','酬李穆見寄','劉長卿','唐','御定全唐诗','yuding','','[]','孤舟相訪至天涯，萬轉雲山路更賒。',32,'御定全唐詩/json/150.json','["孤舟相訪至天涯，萬轉雲山路更賒。", "欲掃柴門迎遠客，青苔黃葉滿貧家。"]'),
('yuding-28','送王司馬秩滿西歸','劉長卿','唐','御定全唐诗','yuding','','[]','漢主何時放逐臣，江邊幾度送歸人。',32,'御定全唐詩/json/150.json','["漢主何時放逐臣，江邊幾度送歸人。", "同官歲歲先辭滿，唯有青山伴老身。"]'),
('yuding-29','寄別朱拾遺','劉長卿','唐','御定全唐诗','yuding','','[]','天書遠召滄浪客，幾度臨歧病未能。',32,'御定全唐詩/json/150.json','["天書遠召滄浪客，幾度臨歧病未能。", "江海茫茫春欲遍，行人一騎發金陵。"]'),
('yuding-30','會赦後酬主簿所問','劉長卿','唐','御定全唐诗','yuding','','[]','江南海北長相憶，淺水深山獨掩扉。',32,'御定全唐詩/json/150.json','["江南海北長相憶，淺水深山獨掩扉。", "重見太平身已老，桃源久住不能歸。"]'),
('yuding-31','贈秦系','劉長卿','唐','御定全唐诗','yuding','','[]','向風長嘯戴紗巾，野鶴由來不可親。',32,'御定全唐詩/json/150.json','["向風長嘯戴紗巾，野鶴由來不可親。", "明日東歸變名姓，五湖煙水覓何人。"]'),
('yuding-32','酬靈徹公相招','劉長卿','唐','御定全唐诗','yuding','','[]','石澗泉聲久不聞，獨臨長路雪紛紛。',32,'御定全唐詩/json/150.json','["石澗泉聲久不聞，獨臨長路雪紛紛。", "如今漸欲生黃發，願脫頭冠與白雲。"]'),
('yuding-33','贈崔九載華','劉長卿','唐','御定全唐诗','yuding','','[]','憐君一見一悲歌，歲歲無如老去何。',32,'御定全唐詩/json/150.json','["憐君一見一悲歌，歲歲無如老去何。", "白屋漸看秋草沒，青雲莫道故人多。"]'),
('yuding-34','同崔載華贈日本聘使','劉長卿','唐','御定全唐诗','yuding','','[]','憐君異域朝周遠，積水連天何處通。',32,'御定全唐詩/json/150.json','["憐君異域朝周遠，積水連天何處通。", "遙指來從初日外，始知更有扶桑東。"]'),
('yuding-35','送建州陸使君','劉長卿','唐','御定全唐诗','yuding','','[]','漢庭初拜建安侯，天子臨軒寄所憂。',32,'御定全唐詩/json/150.json','["漢庭初拜建安侯，天子臨軒寄所憂。", "從此向南無限路，雙旌已去水悠悠。"]'),
('yuding-36','送秦侍禦外甥張篆之福州謁鮑大夫秦侍禦與大夫有舊','劉長卿','唐','御定全唐诗','yuding','','[]','萬里閩中去渺然，孤舟水上入寒煙。',32,'御定全唐詩/json/150.json','["萬里閩中去渺然，孤舟水上入寒煙。", "轅門拜首儒衣弊，貌似牢之豈不憐。"]'),
('yuding-37','聞奉迎皇太后使沈判官至，因有此作','劉長卿','唐','御定全唐诗','yuding','','[]','長樂宮人掃落花，君王正候五雲車。',32,'御定全唐詩/json/150.json','["長樂宮人掃落花，君王正候五雲車。", "萬方臣妾同瞻望，疑在曾城阿母家。"]'),
('yuding-38','送劉萱之道州謁崔大夫','劉長卿','唐','御定全唐诗','yuding','','[]','沅水悠悠湘水春，臨歧南望一沾巾。',32,'御定全唐詩/json/150.json','["沅水悠悠湘水春，臨歧南望一沾巾。", "信陵門下三千客，君到長沙見幾人。"]'),
('yuding-39','過鄭山人所居','劉長卿','唐','御定全唐诗','yuding','','[]','寂寂孤鶯啼杏園，寥寥一犬吠桃源。',32,'御定全唐詩/json/150.json','["寂寂孤鶯啼杏園，寥寥一犬吠桃源。", "落花芳草無尋處，萬壑千峰獨閉門。"]'),
('yuding-40','奉送賀若郎中賊退後之杭州','劉長卿','唐','御定全唐诗','yuding','','[]','江上初收戰馬塵，鶯聲柳色待行春。',32,'御定全唐詩/json/150.json','["江上初收戰馬塵，鶯聲柳色待行春。", "雙旌誰道來何暮，萬井如今有幾人。"]'),
('yuding-41','瓜洲驛重送梁郎中赴吉州','劉長卿','唐','御定全唐诗','yuding','','[]','渺渺雲山去幾重，依依獨聽廣陵鐘。',32,'御定全唐詩/json/150.json','["渺渺雲山去幾重，依依獨聽廣陵鐘。", "明朝借問南來客，五馬雙旌何處逢。"]'),
('yuding-42','奉使鄂渚至烏江道中作','劉長卿','唐','御定全唐诗','yuding','','[]','滄洲不復戀魚竿，白髮那堪戴鐵冠。',32,'御定全唐詩/json/150.json','["滄洲不復戀魚竿，白髮那堪戴鐵冠。", "客路向南何處是，蘆花千里雪漫漫。"]'),
('yuding-43','新息道中作','劉長卿','唐','御定全唐诗','yuding','','[]','蕭條獨向汝南行，客路多逢漢騎營。',32,'御定全唐詩/json/150.json','["蕭條獨向汝南行，客路多逢漢騎營。", "古木蒼蒼離亂後，幾家同住一孤城。"]'),
('yuding-44','春日宴魏萬成湘水亭','劉長卿','唐','御定全唐诗','yuding','','[]','何年家住此江濱，幾度門前北渚春。',32,'御定全唐詩/json/150.json','["何年家住此江濱，幾度門前北渚春。", "白髮亂生相顧老，黃鶯自語豈知人。"]'),
('yuding-45','重送道標上人','劉長卿','唐','御定全唐诗','yuding','','[]','衡陽千里去人稀，遙逐孤雲入翠微。',32,'御定全唐詩/json/150.json','["衡陽千里去人稀，遙逐孤雲入翠微。", "春草青青新覆地，深山無路若為歸。"]'),
('yuding-46','送李判官之潤州行營','劉長卿','唐','御定全唐诗','yuding','','[]','萬里辭家事鼓鼙，金陵驛路楚雲西。',32,'御定全唐詩/json/150.json','["萬里辭家事鼓鼙，金陵驛路楚雲西。", "江春不肯留歸客，草色青青送馬蹄。"]'),
('yuding-47','將赴南巴，至餘幹別李十二','劉長卿','唐','御定全唐诗','yuding','','[]','江上花催問禮人，鄱陽鶯報越鄉春。',32,'御定全唐詩/json/150.json','["江上花催問禮人，鄱陽鶯報越鄉春。", "誰憐此別悲歡異，萬里青山送逐臣。"]'),
('yuding-48','時平後春日思歸','劉長卿','唐','御定全唐诗','yuding','','[]','一尉何曾及布衣，時平卻憶臥柴扉。',32,'御定全唐詩/json/150.json','["一尉何曾及布衣，時平卻憶臥柴扉。", "故園柳色催南客，春水桃花待北歸。"]'),
('yuding-49','送陶十赴杭州攝掾','劉長卿','唐','御定全唐诗','yuding','','[]','莫歎江城一掾卑，滄洲未是阻心期。',32,'御定全唐詩/json/150.json','["莫歎江城一掾卑，滄洲未是阻心期。", "浙中山色千萬狀，門外潮聲朝暮時。"]'),
('yuding-50','使還七裏瀨上逢薛承規赴江西貶官','劉長卿','唐','御定全唐诗','yuding','','[]','遷客歸人醉晚寒，孤舟暫泊子陵灘。',32,'御定全唐詩/json/150.json','["遷客歸人醉晚寒，孤舟暫泊子陵灘。", "憐君更去三千里，落日青山江上看。"]'),
('yuding-51','使回赴蘇州道中作','劉長卿','唐','御定全唐诗','yuding','','[]','春風何事遠相催，路盡天涯始卻回。',32,'御定全唐詩/json/150.json','["春風何事遠相催，路盡天涯始卻回。", "萬里無人空楚水，孤帆送客到魚台。"]'),
('yuding-52','昭陽曲','劉長卿','唐','御定全唐诗','yuding','','[]','昨夜承恩宿未央，羅衣猶帶禦衣香。',32,'御定全唐詩/json/150.json','["昨夜承恩宿未央，羅衣猶帶禦衣香。", "芙蓉帳小雲屏暗，楊柳風多水殿涼。"]'),
('yuding-53','罪所留系，每夜聞長洲軍笛聲','劉長卿','唐','御定全唐诗','yuding','','[]','白日浮雲閉不開，黃沙誰問冶長猜。',32,'御定全唐詩/json/150.json','["白日浮雲閉不開，黃沙誰問冶長猜。", "只憐橫笛關山月，知處愁人夜夜來。"]'),
('yuding-54','贈微上人','劉長卿','唐','御定全唐诗','yuding','','[]','禪門來往翠微間，萬里千峰在剡山。',32,'御定全唐詩/json/150.json','["禪門來往翠微間，萬里千峰在剡山。", "何時共到天臺裏，身與浮雲處處閑。"]'),
('yuding-55','東湖送朱逸人歸','劉長卿','唐','御定全唐诗','yuding','','[]','山色湖光並在東，扁舟歸去有樵風。',32,'御定全唐詩/json/150.json','["山色湖光並在東，扁舟歸去有樵風。", "莫道野人無外事，開田鑿井白雲中。"]'),
('yuding-56','舟中送李十八','劉長卿','唐','御定全唐诗','yuding','','[]','釋子身心無有分，獨將衣缽去人群。',32,'御定全唐詩/json/150.json','["釋子身心無有分，獨將衣缽去人群。", "相思晚望西林寺，唯有鐘聲出白雲。"]'),
('yuding-57','送李穆歸淮南','劉長卿','唐','御定全唐诗','yuding','','[]','揚州春草新年綠，未去先愁去不歸。',32,'御定全唐詩/json/150.json','["揚州春草新年綠，未去先愁去不歸。", "淮水問君來早晚，老人偏畏過芳菲。"]'),
('yuding-58','晚春歸山居題窗前竹','劉長卿','唐','御定全唐诗','yuding','','[]','溪上殘春黃鳥稀，辛夷花盡杏花飛。',32,'御定全唐詩/json/150.json','["溪上殘春黃鳥稀，辛夷花盡杏花飛。", "始憐幽竹山窗下，不改清陰待我歸。"]'),
('yuding-0','送盧侍禦赴河北','劉長卿','唐','御定全唐诗','yuding','','[]','謫居為別倍傷情，何事從戎獨遠行。千里按圖收故地，',40,'御定全唐詩/json/151.json','["謫居為別倍傷情，何事從戎獨遠行。千里按圖收故地，", "莫學仲連逃海上，田單空愧取聊城。"]'),
('yuding-1','送子婿崔真父歸長城','劉長卿','唐','御定全唐诗','yuding','','[]','送君卮酒不成歡，幼女辭家事伯鸞。桃葉宜人誠可詠，',40,'御定全唐詩/json/151.json','["送君卮酒不成歡，幼女辭家事伯鸞。桃葉宜人誠可詠，", "惆悵暮帆何處落，青山無限水漫漫。"]'),
('yuding-2','送陸澧倉曹西上','劉長卿','唐','御定全唐诗','yuding','','[]','長安此去欲何依，先達誰當薦陸機。日下鳳翔雙闕迥，',40,'御定全唐詩/json/151.json','["長安此去欲何依，先達誰當薦陸機。日下鳳翔雙闕迥，", "臨水自傷流落久，贈君空有淚沾衣。"]'),
('yuding-3','送柳使君赴袁州','劉長卿','唐','御定全唐诗','yuding','','[]','宜陽出守新恩至，京口因家始願違。五柳閉門高士去，',40,'御定全唐詩/json/151.json','["宜陽出守新恩至，京口因家始願違。五柳閉門高士去，", "惟有郡齋窗裏岫，朝朝空對謝玄暉。"]'),
('yuding-4','戲題贈二小男','劉長卿','唐','御定全唐诗','yuding','','[]','異鄉流落頻生子，幾許悲歡並在身。欲並老容羞白髮，',40,'御定全唐詩/json/151.json','["異鄉流落頻生子，幾許悲歡並在身。欲並老容羞白髮，", "何幸暮年方有後，舉家相對卻沾巾。"]'),
('yuding-5','謫官後臥病官舍，簡賀蘭侍郎','劉長卿','唐','御定全唐诗','yuding','','[]','青春衣繡共稱宜，白首垂絲恨不遺。江上幾回今夜月，',40,'御定全唐詩/json/151.json','["青春衣繡共稱宜，白首垂絲恨不遺。江上幾回今夜月，", "歲歲任他芳草綠，長沙未有定歸期。"]'),
('yuding-6','歲日見新曆，因寄都官裴郎中','劉長卿','唐','御定全唐诗','yuding','','[]','青陽振蟄初頒曆，白首銜冤欲問天。絳老更能經幾歲，',40,'御定全唐詩/json/151.json','["青陽振蟄初頒曆，白首銜冤欲問天。絳老更能經幾歲，", "若道平分四時氣，南枝為底發春偏。"]'),
('yuding-7','江州重別薛六、柳八二員外','劉長卿','唐','御定全唐诗','yuding','','[]','生涯豈料承優詔，世事空知學醉歌。江上月明胡雁過，',40,'御定全唐詩/json/151.json','["生涯豈料承優詔，世事空知學醉歌。江上月明胡雁過，", "今日龍鍾人共棄，愧君猶遣慎風波。"]'),
('yuding-8','青溪口送人歸岳州','劉長卿','唐','御定全唐诗','yuding','','[]','洞庭何處雁南飛，江菼蒼蒼客去稀。帆帶夕陽千里沒，',40,'御定全唐詩/json/151.json','["洞庭何處雁南飛，江菼蒼蒼客去稀。帆帶夕陽千里沒，", "歧路相逢無可贈，老年空有淚沾衣。"]'),
('yuding-9','送靈澈上人還越中','劉長卿','唐','御定全唐诗','yuding','','[]','禪客無心杖錫還，沃洲深處草堂閑。身隨敝屨經殘雪，',40,'御定全唐詩/json/151.json','["禪客無心杖錫還，沃洲深處草堂閑。身隨敝屨經殘雪，", "那堪別後長相憶，雲木蒼蒼但閉關。"]'),
('yuding-10','送耿拾遺歸上都','劉長卿','唐','御定全唐诗','yuding','','[]','若為天畔獨歸秦，對水看山欲暮春。窮海別離無限路，',40,'御定全唐詩/json/151.json','["若為天畔獨歸秦，對水看山欲暮春。窮海別離無限路，", "想到郵亭愁駐馬，不堪西望見風塵。"]'),
('yuding-11','和樊使君登潤州城樓','劉長卿','唐','御定全唐诗','yuding','','[]','山城迢遞敞高樓，露冕吹鐃居上頭。春草連天隨北望，',40,'御定全唐詩/json/151.json','["山城迢遞敞高樓，露冕吹鐃居上頭。春草連天隨北望，", "王粲尚為南郡客，別來何處更銷憂。"]'),
('yuding-12','餞王相公出牧括州','劉長卿','唐','御定全唐诗','yuding','','[]','縉雲詎比長沙遠，出牧猶承明主恩。城對寒山開畫戟，',40,'御定全唐詩/json/151.json','["縉雲詎比長沙遠，出牧猶承明主恩。城對寒山開畫戟，", "蕭索庭槐空閉合，舊人誰到翟公門。"]'),
('yuding-13','題靈佑和尚故居','劉長卿','唐','御定全唐诗','yuding','','[]','歎逝翻悲有此身，禪房寂寞見流塵。多時行徑空秋草，',40,'御定全唐詩/json/151.json','["歎逝翻悲有此身，禪房寂寞見流塵。多時行徑空秋草，", "殘經窗下依然在，憶得山中問許詢。"]'),
('yuding-14','尋龍井楊老','劉長卿','唐','御定全唐诗','yuding','','[]','柴門草舍絕風塵，空谷耕田學子真。泉咽恐勞經隴底，',40,'御定全唐詩/json/151.json','["柴門草舍絕風塵，空谷耕田學子真。泉咽恐勞經隴底，", "唯有胡麻當雞黍，白雲來往未嫌貧。"]'),
('yuding-15','見故人李均所借古鏡恨其未獲歸府斯人已亡愴然有作','劉長卿','唐','御定全唐诗','yuding','','[]','故人留鏡無歸處，今日懷君試暫窺。歲久豈堪塵自入，',40,'御定全唐詩/json/151.json','["故人留鏡無歸處，今日懷君試暫窺。歲久豈堪塵自入，", "所恨平生還不早，如今始掛隴頭枝。"]'),
('yuding-16','聞虞沔州有替，將歸上都，登漢東城寄贈','劉長卿','唐','御定全唐诗','yuding','','[]','淮南搖落客心悲，溳水悠悠怨別離。早雁初辭舊關塞，',40,'御定全唐詩/json/151.json','["淮南搖落客心悲，溳水悠悠怨別離。早雁初辭舊關塞，", "惆悵恨君先我去，漢陽耆老憶旌麾。"]'),
('yuding-17','獻淮甯軍節度使李相公','劉長卿','唐','御定全唐诗','yuding','','[]','建牙吹角不聞喧，三十登壇眾所尊。家散萬金酬士死，',40,'御定全唐詩/json/151.json','["建牙吹角不聞喧，三十登壇眾所尊。家散萬金酬士死，", "白馬翩翩春草細，郊原西去獵平原。"]'),
('yuding-18','觀校獵，上淮西相公','劉長卿','唐','御定全唐诗','yuding','','[]','龍驤校獵邵陵東，野火初燒楚澤空。師事黃公千戰後，',40,'御定全唐詩/json/151.json','["龍驤校獵邵陵東，野火初燒楚澤空。師事黃公千戰後，", "三十擁旄誰不羨，周郎少小立奇功。"]'),
('yuding-19','送皇甫曾赴上都','劉長卿','唐','御定全唐诗','yuding','','[]','東游久與故人違，西去荒涼舊路微。秋草不生三徑處，',40,'御定全唐詩/json/151.json','["東游久與故人違，西去荒涼舊路微。秋草不生三徑處，", "楚客豈勞傷此別，滄江欲暮自沾衣。"]'),
('yuding-20','送李錄事兄歸襄鄧','劉長卿','唐','御定全唐诗','yuding','','[]','十年多難與君同，幾處移家逐轉蓬。白首相逢征戰後，',40,'御定全唐詩/json/151.json','["十年多難與君同，幾處移家逐轉蓬。白首相逢征戰後，", "漢水楚雲千萬里，天涯此別恨無窮。"]'),
('yuding-21','漢陽獻李相公','劉長卿','唐','御定全唐诗','yuding','','[]','退身高臥楚城幽，獨掩閑門漢水頭。春草雨中行徑沒，',40,'御定全唐詩/json/151.json','["退身高臥楚城幽，獨掩閑門漢水頭。春草雨中行徑沒，", "早晚卻還丞相印，十年空被白雲留。"]'),
('yuding-22','長沙過賈誼宅','劉長卿','唐','御定全唐诗','yuding','','[]','三年謫宦此棲遲，萬古惟留楚客悲。秋草獨尋人去後，',40,'御定全唐詩/json/151.json','["三年謫宦此棲遲，萬古惟留楚客悲。秋草獨尋人去後，", "寂寂江山搖落處，憐君何事到天涯。"]'),
('yuding-23','奉酬辛大夫喜湖南臘月連日降雪見示之作','劉長卿','唐','御定全唐诗','yuding','','[]','長沙耆舊拜旌麾，喜見江潭積雪時。柳絮三冬先北地，',40,'御定全唐詩/json/151.json','["長沙耆舊拜旌麾，喜見江潭積雪時。柳絮三冬先北地，", "閭裏何人不相慶，萬家同唱郢中詞。"]'),
('yuding-24','登餘幹古縣城','劉長卿','唐','御定全唐诗','yuding','','[]','孤城上與白雲齊，萬古荒涼楚水西。官舍已空秋草綠，',40,'御定全唐詩/json/151.json','["孤城上與白雲齊，萬古荒涼楚水西。官舍已空秋草綠，", "沙鳥不知陵穀變，朝飛暮去弋陽溪。"]'),
('yuding-25','將赴嶺外，留題蕭寺遠公院','劉長卿','唐','御定全唐诗','yuding','','[]','竹房遙閉上方幽，苔徑蒼蒼訪昔遊。內史舊山空日暮，',40,'御定全唐詩/json/151.json','["竹房遙閉上方幽，苔徑蒼蒼訪昔遊。內史舊山空日暮，", "此去播遷明主意，白雲何事欲相留。"]'),
('yuding-26','初聞貶謫，續喜量移，登幹越亭贈鄭校書','劉長卿','唐','御定全唐诗','yuding','','[]','青青草色滿江洲，萬里傷心水自流。越鳥豈知南國遠，',40,'御定全唐詩/json/151.json','["青青草色滿江洲，萬里傷心水自流。越鳥豈知南國遠，", "何事還邀遷客醉，春風日夜待歸舟。"]'),
('yuding-27','北歸入至德州界，偶逢洛陽鄰家李光宰','劉長卿','唐','御定全唐诗','yuding','','[]','生涯心事已蹉跎，舊路依然此重過。近北始知黃葉落，',40,'御定全唐詩/json/151.json','["生涯心事已蹉跎，舊路依然此重過。近北始知黃葉落，", "華髮相逢俱若是，故園秋草複如何。"]'),
('yuding-28','自江西歸至舊任官舍，贈袁贊府','劉長卿','唐','御定全唐诗','yuding','','[]','卻見同官喜複悲，此生何幸有歸期。空庭客至逢搖落，',40,'御定全唐詩/json/151.json','["卻見同官喜複悲，此生何幸有歸期。空庭客至逢搖落，", "南方風土勞君問，賈誼長沙豈不知。"]'),
('yuding-29','赴南中題褚少府湖上亭子','劉長卿','唐','御定全唐诗','yuding','','[]','種田東郭傍春陂，萬事無情把釣絲。綠竹放侵行徑裏，',40,'御定全唐詩/json/151.json','["種田東郭傍春陂，萬事無情把釣絲。綠竹放侵行徑裏，", "從此別君千萬里，白雲流水憶佳期。"]'),
('yuding-30','上巳日越中與鮑侍郎泛舟耶溪','劉長卿','唐','御定全唐诗','yuding','','[]','蘭橈縵轉傍汀沙，應接雲峰到若耶。舊浦滿來移渡口，',40,'御定全唐詩/json/151.json','["蘭橈縵轉傍汀沙，應接雲峰到若耶。舊浦滿來移渡口，", "君見漁船時借問，前洲幾路入煙花。"]'),
('yuding-31','雙峰下哭故人李宥','劉長卿','唐','御定全唐诗','yuding','','[]','憐君孤壟寄雙峰，埋骨窮泉複幾重。白露空沾九原草，',40,'御定全唐詩/json/151.json','["憐君孤壟寄雙峰，埋骨窮泉複幾重。白露空沾九原草，", "惆悵東皋卻歸去，人間無處更相逢。"]'),
('yuding-32','使次安陸寄友人','劉長卿','唐','御定全唐诗','yuding','','[]','新年草色遠萋萋，久客將歸失路蹊。暮雨不知溳口處，',40,'御定全唐詩/json/151.json','["新年草色遠萋萋，久客將歸失路蹊。暮雨不知溳口處，", "君在江南相憶否，門前五柳幾枝低。"]'),
('yuding-33','哭陳歙州','劉長卿','唐','御定全唐诗','yuding','','[]','千秋萬古葬平原，素業清風及子孫。旅櫬歸程傷道路，',40,'御定全唐詩/json/151.json','["千秋萬古葬平原，素業清風及子孫。旅櫬歸程傷道路，", "儒行公才竟何在，獨憐棠樹一枝存。"]'),
('yuding-34','酬屈突陝','劉長卿','唐','御定全唐诗','yuding','','[]','落葉紛紛滿四鄰，蕭條環堵絕風塵。鄉看秋草歸無路，',40,'御定全唐詩/json/151.json','["落葉紛紛滿四鄰，蕭條環堵絕風塵。鄉看秋草歸無路，", "憐君計畫誰知者，但見蓬蒿空沒身。"]'),
('yuding-35','送惠法師游天臺，因懷智大師故居','劉長卿','唐','御定全唐诗','yuding','','[]','翠屏瀑水知何在，鳥道猿啼過幾重。落日獨搖金策去，',40,'御定全唐詩/json/151.json','["翠屏瀑水知何在，鳥道猿啼過幾重。落日獨搖金策去，", "憶想東林禪誦處，寂寥惟聽舊時鐘。"]'),
('yuding-36','自夏口至鸚鵡洲，夕望岳陽，寄源中丞','劉長卿','唐','御定全唐诗','yuding','','[]','汀洲無浪複無煙，楚客相思益渺然。漢口夕陽斜渡鳥，',40,'御定全唐詩/json/151.json','["汀洲無浪複無煙，楚客相思益渺然。漢口夕陽斜渡鳥，", "賈誼上書憂漢室，長沙謫去古今憐。"]'),
('yuding-37','送侯中丞流康州','劉長卿','唐','御定全唐诗','yuding','','[]','長江極目帶楓林，匹馬孤雲不可尋。遷播共知臣道枉，',40,'御定全唐詩/json/151.json','["長江極目帶楓林，匹馬孤雲不可尋。遷播共知臣道枉，", "北闕九重誰許屈，獨看湘水淚沾襟。"]'),
('yuding-38','別嚴士元','劉長卿','唐','御定全唐诗','yuding','','[]','春風倚棹闔閭城，水國春寒陰複晴。細雨濕衣看不見，',40,'御定全唐詩/json/151.json','["春風倚棹闔閭城，水國春寒陰複晴。細雨濕衣看不見，", "東道若逢相識問，青袍今日誤儒生。"]'),
('yuding-39','避地江東，留別淮南使院諸公','劉長卿','唐','御定全唐诗','yuding','','[]','長安路絕鳥飛通，萬里孤雲西複東。舊業已應成茂草，',40,'御定全唐詩/json/151.json','["長安路絕鳥飛通，萬里孤雲西複東。舊業已應成茂草，", "此去行持一竿竹，等閒將狎釣漁翁。"]'),
('yuding-40','罪所上禦史惟則','劉長卿','唐','御定全唐诗','yuding','','[]','誤因微祿滯南昌，幽系圜扉晝夜長。黃鶴翅垂同燕雀，',40,'御定全唐詩/json/151.json','["誤因微祿滯南昌，幽系圜扉晝夜長。黃鶴翅垂同燕雀，", "賢達不能同感激，更於何處問蒼蒼。"]'),
('yuding-41','送台州李使君，兼寄題國清寺','劉長卿','唐','御定全唐诗','yuding','','[]','露冕新承明主恩，山城別是武陵源。花間五馬時行縣，',40,'御定全唐詩/json/151.json','["露冕新承明主恩，山城別是武陵源。花間五馬時行縣，", "知到應真飛錫處，因君一想已忘言。"]'),
('yuding-42','獄中聞收東京有赦','劉長卿','唐','御定全唐诗','yuding','','[]','傳聞闕下降絲綸，為報關東滅虜塵。壯志已憐成白首，',40,'御定全唐詩/json/151.json','["傳聞闕下降絲綸，為報關東滅虜塵。壯志已憐成白首，", "持法不須張密網，恩波自解惜枯鱗。"]'),
('yuding-43','溫湯客舍','劉長卿','唐','御定全唐诗','yuding','','[]','冬狩溫泉歲欲闌，宮城佳氣晚宜看。湯熏仗裏千旗暖，',40,'御定全唐詩/json/151.json','["冬狩溫泉歲欲闌，宮城佳氣晚宜看。湯熏仗裏千旗暖，", "且喜禮闈秦鏡在，還將妍醜付春官。"]'),
('yuding-44','送孫逸歸廬山','劉長卿','唐','御定全唐诗','yuding','','[]','爐峰絕頂楚雲銜，楚客東歸棲此岩。彭蠡湖邊香橘柚，',40,'御定全唐詩/json/151.json','["爐峰絕頂楚雲銜，楚客東歸棲此岩。彭蠡湖邊香橘柚，", "常愛此中多勝事，新詩他日佇開緘。"]'),
('yuding-45','送馬秀才落第歸江南','劉長卿','唐','御定全唐诗','yuding','','[]','南客懷歸鄉夢頻，東門悵別柳條新。殷勤鬥酒城陰暮，',40,'御定全唐詩/json/151.json','["南客懷歸鄉夢頻，東門悵別柳條新。殷勤鬥酒城陰暮，", "憐君此去未得意，陌上愁看淚滿巾。"]'),
('yuding-46','送常十九歸嵩少故林','劉長卿','唐','御定全唐诗','yuding','','[]','迢迢此恨杳無涯，楚澤嵩丘千里賒。歧路別時驚一葉，',40,'御定全唐詩/json/151.json','["迢迢此恨杳無涯，楚澤嵩丘千里賒。歧路別時驚一葉，", "他日山中逢勝事，桃源洞裏幾人家。"]'),
('yuding-47','送宇文遷明府赴洪州張觀察追攝豐城令','劉長卿','唐','御定全唐诗','yuding','','[]','送君不復遠為心，餘亦扁舟湘水陰。路逐山光何處盡，',40,'御定全唐詩/json/151.json','["送君不復遠為心，餘亦扁舟湘水陰。路逐山光何處盡，", "倘見主人論謫宦，爾來空有白頭吟。"]'),
('yuding-48','送李將軍','劉長卿','唐','御定全唐诗','yuding','','[]','征西諸將一如君，報德誰能不顧勳。身逐塞鴻來萬里，',40,'御定全唐詩/json/151.json','["征西諸將一如君，報德誰能不顧勳。身逐塞鴻來萬里，", "歸去蕭條灞陵上，幾人看葬李將軍。"]'),
('yuding-49','西陵寄一上人','劉長卿','唐','御定全唐诗','yuding','','[]','東山訪道成開士，南渡隋陽作本師。了義惠心能善誘，',40,'御定全唐詩/json/151.json','["東山訪道成開士，南渡隋陽作本師。了義惠心能善誘，", "多謝清言異玄度，懸河高論有誰持。"]'),
('yuding-50','賦得','劉長卿','唐','御定全唐诗','yuding','','[]','鶯啼燕語報新年，馬邑龍堆路幾千。家住層城臨漢苑，',40,'御定全唐詩/json/151.json','["鶯啼燕語報新年，馬邑龍堆路幾千。家住層城臨漢苑，", "為問元戎竇車騎，何時返旆勒燕然。"]'),
('yuding-51','三月李明府後亭泛舟','劉長卿','唐','御定全唐诗','yuding','','[]','江南風景複如何，聞道新亭更欲過。處處紉蘭春浦淥，',40,'御定全唐詩/json/151.json','["江南風景複如何，聞道新亭更欲過。處處紉蘭春浦淥，", "更待持橈徐轉去，微風落日水增波。"]'),
('yuding-52','喜朱拾遺承恩拜命赴任上都','劉長卿','唐','御定全唐诗','yuding','','[]','詔書征拜脫荷裳，身去東山閉草堂。閶闔九天通奏籍，',40,'御定全唐詩/json/151.json','["詔書征拜脫荷裳，身去東山閉草堂。閶闔九天通奏籍，", "今日卻回垂釣處，海鷗相見已高翔。"]'),
('yuding-53','鄖上送韋司士歸上都舊業','劉長卿','唐','御定全唐诗','yuding','','[]','前朝舊業想遺塵，今日他鄉獨爾身。鄖地國除為過客，',40,'御定全唐詩/json/151.json','["前朝舊業想遺塵，今日他鄉獨爾身。鄖地國除為過客，", "西去茫茫問歸路，關河漸近淚盈巾。"]'),
('yuding-54','感懷','劉長卿','唐','御定全唐诗','yuding','','[]','秋風落葉正堪悲，黃菊殘花欲待誰。水近偏逢寒氣早，',40,'御定全唐詩/json/151.json','["秋風落葉正堪悲，黃菊殘花欲待誰。水近偏逢寒氣早，", "自笑不如湘浦雁，飛來即是北歸時。"]'),
('yuding-55','送楊于陵歸宋汴州別業','劉長卿','唐','御定全唐诗','yuding','','[]','半山溪雨帶斜暉，向水殘花映客衣。旅食嗟餘當歲晚，',40,'御定全唐詩/json/151.json','["半山溪雨帶斜暉，向水殘花映客衣。旅食嗟餘當歲晚，", "離亂要知君到處，寄書須及雁南飛。"]'),
('yuding-56','送崔使君赴壽州','劉長卿','唐','御定全唐诗','yuding','','[]','列郡專城分國憂，彤幨皂蓋古諸侯。仲華遇主年猶少，',40,'御定全唐詩/json/151.json','["列郡專城分國憂，彤幨皂蓋古諸侯。仲華遇主年猶少，", "千里相思如可見，淮南木葉正驚秋。"]'),
('yuding-57','上陽宮望幸','劉長卿','唐','御定全唐诗','yuding','','[]','玉輦西巡久未還，春光猶入上陽間。萬木長承新雨露，',40,'御定全唐詩/json/151.json','["玉輦西巡久未還，春光猶入上陽間。萬木長承新雨露，", "獨見彩雲飛不盡，只應來去候龍顏。"]'),
('yuding-58','過裴舍人故居','劉長卿','唐','御定全唐诗','yuding','','[]','慘慘天寒獨掩扃，紛紛黃葉滿空庭。孤墳何處依山木，',40,'御定全唐詩/json/151.json','["慘慘天寒獨掩扃，紛紛黃葉滿空庭。孤墳何處依山木，", "書幌無人長不卷，秋來芳草自為螢。"]'),
('yuding-59','登松江驛樓北望故園','劉長卿','唐','御定全唐诗','yuding','','[]','淚盡江樓北望歸，田園已陷百重圍。平蕪萬里無人去，',40,'御定全唐詩/json/151.json','["淚盡江樓北望歸，田園已陷百重圍。平蕪萬里無人去，", "白鷗漁父徒相待，未掃欃槍懶息機。"]'),
('yuding-60','秋夜有懷高三十五適，兼呈空上人','劉長卿','唐','御定全唐诗','yuding','','[]','晚節逢君趣道深，結茅栽樹近東林。吾師幾度曾摩頂，',40,'御定全唐詩/json/151.json','["晚節逢君趣道深，結茅栽樹近東林。吾師幾度曾摩頂，", "不見支公與玄度，相思擁膝坐長吟。"]'),
('yuding-61','送孔巢父赴河南軍','劉長卿','唐','御定全唐诗','yuding','','[]','江南相送隔煙波，況複新秋一雁過。聞道全軍征北虜，',40,'御定全唐詩/json/151.json','["江南相送隔煙波，況複新秋一雁過。聞道全軍征北虜，", "共許陳琳工奏記，知君名行未蹉跎。"]'),
('yuding-62','登潤州萬歲樓','劉長卿','唐','御定全唐诗','yuding','','[]','高樓獨上思依依，極浦遙山合翠微。江客不堪頻北望，',40,'御定全唐詩/json/151.json','["高樓獨上思依依，極浦遙山合翠微。江客不堪頻北望，", "聞道王師猶轉戰，更能談笑解重圍。"]'),
('yuding-63','江樓送太康郭主簿赴嶺南','劉長卿','唐','御定全唐诗','yuding','','[]','對酒憐君安可論，當官愛士如平原。料錢用盡卻為謗，',48,'御定全唐詩/json/151.json','["對酒憐君安可論，當官愛士如平原。料錢用盡卻為謗，", "樹色應無江北秋，天涯尚見淮陽月。驛路南隨桂水流，"]'),
('yuding-64','客舍喜鄭三見寄','劉長卿','唐','御定全唐诗','yuding','','[]','客舍逢君未換衣，閉門愁見桃花飛。遙想故園今已爾，',48,'御定全唐詩/json/151.json','["客舍逢君未換衣，閉門愁見桃花飛。遙想故園今已爾，", "窮巷無人鳥雀閑，空庭新雨莓苔綠。北中分與故交疏，"]'),
('yuding-65','送賈三北游','劉長卿','唐','御定全唐诗','yuding','','[]','賈生未達猶窘迫，身馳匹馬邯鄲陌。片雲郊外遙送人，',48,'御定全唐詩/json/151.json','["賈生未達猶窘迫，身馳匹馬邯鄲陌。片雲郊外遙送人，", "雨色新添漳水綠，夕陽遠照蘇門高。把袂相看衣共緇，"]'),
('yuding-66','齊一和尚影堂','劉長卿','唐','御定全唐诗','yuding','','[]','一公住世忘世紛，暫來複去誰能分。身寄虛空如過客，',72,'御定全唐詩/json/151.json','["一公住世忘世紛，暫來複去誰能分。身寄虛空如過客，", "舊地愁看雙樹在，空堂只是一燈懸。一燈長照恒河沙，", "昔餘精念訪禪扉，常接微言清道機。今來寂寞無所得，"]'),
('yuding-67','潁川留別司倉李萬','劉長卿','唐','御定全唐诗','yuding','','[]','故人早負幹將器，誰言未展平生意。想君疇昔高步時，',72,'御定全唐詩/json/151.json','["故人早負幹將器，誰言未展平生意。想君疇昔高步時，", "槐暗公庭趨小吏，荷香陂水膾鱸魚。客裏相逢款話深，", "落日征驂隨去塵，含情揮手背城闉。已恨良時空此別，"]'),
('yuding-68','聽笛歌留別鄭協律','劉長卿','唐','御定全唐诗','yuding','','[]','舊游憐我長沙謫，載酒沙頭送遷客。天涯望月自沾衣，',72,'御定全唐詩/json/151.json','["舊游憐我長沙謫，載酒沙頭送遷客。天涯望月自沾衣，", "商聲寥亮羽聲苦，江天寂曆江楓秋。靜聽關山聞一叫，", "隨風飄向何處落，唯見曲盡平湖深。明發與君離別後，"]'),
('yuding-69','時平後送范倫歸安州','劉長卿','唐','御定全唐诗','yuding','','[]','昨聞戰罷圖麟閣，破虜收兵卷戎幕。滄海初看漢月明，',96,'御定全唐詩/json/151.json','["昨聞戰罷圖麟閣，破虜收兵卷戎幕。滄海初看漢月明，", "與君攜手姑蘇台，望鄉一日登幾回。白雲飛鳥去寂寞，", "洛陽舉目今誰在，潁水無情應自流。吳苑西人去欲稀，", "萬里遙懸帝鄉憶，五年空帶風塵色。卻到長安逢故人，"]'),
('yuding-70','小鳥篇，上裴尹','劉長卿','唐','御定全唐诗','yuding','','[]','藩籬小鳥何甚微，翩翩日夕空此飛。只緣六翮不自致，',96,'御定全唐詩/json/151.json','["藩籬小鳥何甚微，翩翩日夕空此飛。只緣六翮不自致，", "獨立雖輕燕雀群，孤飛還懼鷹鸇搏。自憐天上青雲路，", "歲月蹉跎飛不進，羽毛憔悴何人問。繞樹空隨烏鵲驚，", "少年挾彈遙相猜，遂使驚飛往復回。不辭奮翼向君去，"]'),
('yuding-71','登吳古城歌','劉長卿','唐','御定全唐诗','yuding','','[]','登古城兮思古人，感賢達兮同埃塵。望平原兮寄遠目，',96,'御定全唐詩/json/151.json','["登古城兮思古人，感賢達兮同埃塵。望平原兮寄遠目，", "伍員殺身誰不冤，竟看墓樹如所言。越王嘗膽安可敵，", "黍離離兮城坡坨，牛羊踐兮牧豎歌。野無人兮秋草綠，", "荒阡斷兮誰重過，孤舟逝兮愁若何。天寒日暮江楓落，"]'),
('yuding-72','疲兵篇','劉長卿','唐','御定全唐诗','yuding','','[]','驕虜乘秋下薊門，陰山日夕煙塵昏。三軍疲馬力已盡，',120,'御定全唐詩/json/151.json','["驕虜乘秋下薊門，陰山日夕煙塵昏。三軍疲馬力已盡，", "孤城望處增斷腸，折劍看時可沾臆。元戎日夕且歌舞，", "萬里飄颻空此身，十年征戰老胡塵。赤心報國無片賞，", "漢月何曾照客心，胡笳只解催人老。軍前仍欲破重圍，", "飲馬滹河晚更清，行吹羌笛遠歸營。只恨漢家多苦戰，"]'),
('yuding-73','新安送陸澧歸江陰','劉長卿','唐','御定全唐诗','yuding','','[]','新安路，人來去。早潮複晚潮，明日知何處。',36,'御定全唐詩/json/151.json','["新安路，人來去。早潮複晚潮，明日知何處。", "潮水無情亦解歸，自憐長在新安住。"]'),
('yuding-74','弄白鷗歌','劉長卿','唐','御定全唐诗','yuding','','[]','泛泛江上鷗，毛衣皓如雪。朝飛瀟湘水，夜宿洞庭月。',38,'御定全唐詩/json/151.json','["泛泛江上鷗，毛衣皓如雪。朝飛瀟湘水，夜宿洞庭月。", "歸客正夷猶，愛此滄江閑白鷗。"]'),
('yuding-75','長沙贈衡岳祝融峰般若禪師','劉長卿','唐','御定全唐诗','yuding','','[]','般若公，般若公，負缽何時下祝融。歸路卻看飛鳥外，',24,'御定全唐詩/json/151.json','["般若公，般若公，負缽何時下祝融。歸路卻看飛鳥外，"]'),
('yuding-76','贈湘南漁父','劉長卿','唐','御定全唐诗','yuding','','[]','問君何所適，暮暮逢煙水。獨與不系舟，往來楚雲裏。',44,'御定全唐詩/json/151.json','["問君何所適，暮暮逢煙水。獨與不系舟，往來楚雲裏。", "釣魚非一歲，終日只如此。日落江清桂楫遲，"]'),
('yuding-77','明月灣尋賀九不遇','劉長卿','唐','御定全唐诗','yuding','','[]','楚水日夜綠，傍江春草滋。青青遙滿目，萬里傷心歸。',48,'御定全唐詩/json/151.json','["楚水日夜綠，傍江春草滋。青青遙滿目，萬里傷心歸。", "故人川上複何之，明月灣南空所思。故人不在明月在，"]'),
('yuding-78','題曲阿三昧王佛殿前孤石','劉長卿','唐','御定全唐诗','yuding','','[]','孤石自何處，對之疑舊遊。氛氳峴首夕，蒼翠剡中秋。',48,'御定全唐詩/json/151.json','["孤石自何處，對之疑舊遊。氛氳峴首夕，蒼翠剡中秋。", "迥出群峰當殿前，雪山靈鷲慚貞堅。一片孤雲長不去，"]'),
('yuding-79','送友人東歸','劉長卿','唐','御定全唐诗','yuding','','[]','對酒灞亭暮，相看愁自深。河邊草已綠，此別難為心。',48,'御定全唐詩/json/151.json','["對酒灞亭暮，相看愁自深。河邊草已綠，此別難為心。", "關路迢迢匹馬歸，垂楊寂寂數鶯飛。憐君獻策十餘載，"]'),
('yuding-80','入桂渚次砂牛石穴','劉長卿','唐','御定全唐诗','yuding','','[]','扁舟傍歸路，日暮瀟湘深。湘水清見底，楚雲淡無心。',44,'御定全唐詩/json/151.json','["扁舟傍歸路，日暮瀟湘深。湘水清見底，楚雲淡無心。", "片帆落桂渚，獨夜依楓林。楓林月出猿聲苦，"]'),
('yuding-81','嚴陵釣台，送李康成赴江東使','劉長卿','唐','御定全唐诗','yuding','','[]','潺湲子陵瀨，仿佛如在目。七裏人已非，千年水空綠。',64,'御定全唐詩/json/151.json','["潺湲子陵瀨，仿佛如在目。七裏人已非，千年水空綠。", "新安江上孤帆遠，應逐楓林萬餘轉。古台落日共蕭條，", "灘聲山翠至今在，遲爾行舟晚泊時。"]'),
('yuding-82','送姨子弟往南郊','劉長卿','唐','御定全唐诗','yuding','','[]','一展慰久闊，寸心仍未伸。別時兩童稚，及此俱成人。',72,'御定全唐詩/json/151.json','["一展慰久闊，寸心仍未伸。別時兩童稚，及此俱成人。", "那堪適會面，遽已悲分首。客路向楚雲，河橋對衰柳。", "送君匹馬別河橋，汝南山郭寒蕭條。今我單車複西上，"]'),
('yuding-83','銅雀台','劉長卿','唐','御定全唐诗','yuding','','[]','嬌愛更何日，高臺空數層。含啼映雙袖，不忍看西陵。',64,'御定全唐詩/json/151.json','["嬌愛更何日，高臺空數層。含啼映雙袖，不忍看西陵。", "漳河東流無複來，百花輦路為蒼苔。青樓月夜長寂寞，", "宮中歌舞已浮雲，空指行人往來處。"]'),
('yuding-84','王昭君歌','劉長卿','唐','御定全唐诗','yuding','','[]','自矜嬌豔色，不顧丹青人。那知粉繪能相負，',60,'御定全唐詩/json/151.json','["自矜嬌豔色，不顧丹青人。那知粉繪能相負，", "北風雁急浮雲秋，萬里獨見黃河流。纖腰不復漢宮寵，", "誰憐一曲傳樂府，能使千秋傷綺羅。"]'),
('yuding-85','送杜越江佐覲省往新安江','劉長卿','唐','御定全唐诗','yuding','','[]','去帆楚天外，望遠愁複積。想見新安江，扁舟一行客。',96,'御定全唐詩/json/151.json','["去帆楚天外，望遠愁複積。想見新安江，扁舟一行客。", "清流數千丈，底下看白石。色混元氣深，波連洞庭碧。", "鳴桹去未已，前路行可覿。猿鳥悲啾啾，杉松雨聲夕。", "送君東赴歸寧期，新安江水遠相隨。見說江中孤嶼在，"]'),
('yuding-86','湘中憶歸','劉長卿','唐','御定全唐诗','yuding','','[]','終日空理棹，經年猶別家。頃來行已遠，彌覺天無涯。',96,'御定全唐詩/json/151.json','["終日空理棹，經年猶別家。頃來行已遠，彌覺天無涯。", "白雲意自深，滄海夢難隔。迢遞萬里帆，飄颻一行客。", "獨憐西江外，遠寄風波裏。平湖流楚天，孤雁渡湘水。", "湘流澹澹空愁予，猿啼啾啾滿南楚。扁舟泊處聞此聲，"]'),
('yuding-87','送郭六侍從之武陵郡','劉長卿','唐','御定全唐诗','yuding','','[]','常愛武陵郡，羨君將遠尋。空憐世界迫，孤負桃源心。',72,'御定全唐詩/json/151.json','["常愛武陵郡，羨君將遠尋。空憐世界迫，孤負桃源心。", "洛陽遙想桃源隔，野水閑流春自碧。花下常迷楚客船，", "河梁馬首隨春草，江路猿聲愁暮天。丈人別乘佐分憂，"]'),
('yuding-88','山鴝鵒歌','劉長卿','唐','御定全唐诗','yuding','','[]','山鴝鵒，長在此山吟古木。嘲哳相呼響空穀，',60,'御定全唐詩/json/151.json','["山鴝鵒，長在此山吟古木。嘲哳相呼響空穀，", "巴人峽裏自聞猿，燕客水頭空擊築。山鴝鵒，", "鳴相逐，啄殘粟，食不足。青雲杳杳無力飛，"]'),
('yuding-89','望龍山懷道士許法棱','劉長卿','唐','御定全唐诗','yuding','','[]','心惆悵，望龍山。雲之際，鳥獨還。懸崖絕壁幾千丈，',72,'御定全唐詩/json/151.json','["心惆悵，望龍山。雲之際，鳥獨還。懸崖絕壁幾千丈，", "嵐煙瀑水如向人，終日迢迢空在眼。中有一人披霓裳，", "朝入青霄禮玉堂，夜掃白雲眠石床。桃花洞裏居人滿，"]'),
('yuding-90','戲贈幹越尼子歌','劉長卿','唐','御定全唐诗','yuding','','[]','鄱陽女子年十五，家本秦人今在楚。厭向春江空浣沙，',96,'御定全唐詩/json/151.json','["鄱陽女子年十五，家本秦人今在楚。厭向春江空浣沙，", "亭亭獨立青蓮下，忍草禪枝繞精舍。自用黃金買地居，", "一花一竹如有意，不語不笑能留人。黃鸝欲棲白日暮，", "雲房寂寂夜鐘後，吳音清切令人聽。人聽吳音歌一曲，"]'),
('yuding-91','遊四窗','劉長卿','唐','御定全唐诗','yuding','','[]','四明山絕奇，自古說登陸。蒼崖倚天立，覆石如覆屋。',108,'御定全唐詩/json/151.json','["四明山絕奇，自古說登陸。蒼崖倚天立，覆石如覆屋。", "玲瓏開戶牖，落落明四目。箕星分南野，有鬥掛簷北。", "日月居東西，朝昏互出沒。我來遊其間，寄傲巾半幅。", "白雲本無心，悠然伴幽獨。對此脫塵鞅，頓忘榮與辱。", "長笑天地寬，仙風吹佩玉。"]'),
('yuding-92','和中丞出使恩命過終南別業','劉長卿','唐','御定全唐诗','yuding','','[]','不過林園久，多因寵遇偏。故山長寂寂，春草過年年。',72,'御定全唐詩/json/151.json','["不過林園久，多因寵遇偏。故山長寂寂，春草過年年。", "花待朝衣間，雲迎驛騎連。松蘿深舊合，樵木散閒田。", "拜闕貪搖佩，看琴懶更弦。君恩催早入，已夢傅岩邊。"]'),
('yuding-93','岳陽樓','劉長卿','唐','御定全唐诗','yuding','','[]','行盡清溪日已蹉，雲容山影兩嵯峨。樓前歸客怨秋夢，',40,'御定全唐詩/json/151.json','["行盡清溪日已蹉，雲容山影兩嵯峨。樓前歸客怨秋夢，", "終期一艇載樵去，來往片帆愁白波。"]'),
('yuding-94','春望寄王涔陽','劉長卿','唐','御定全唐诗','yuding','','[]','清明別後雨晴時，極浦空顰一望眉。湖畔春山煙點點，',40,'御定全唐詩/json/151.json','["清明別後雨晴時，極浦空顰一望眉。湖畔春山煙點點，", "風暖草長愁自醉，行吟無處寄相思。"]'),
('yuding-95','留辭','劉長卿','唐','御定全唐诗','yuding','','[]','南楚迢迢通漢口，西江淼淼去揚州。',32,'御定全唐詩/json/151.json','["南楚迢迢通漢口，西江淼淼去揚州。", "春風已遣歸心促，縱複芳菲不可留。"]'),
('yuding-0','題杼山癸亭得暮字','顏真卿','唐','御定全唐诗','yuding','','[]','杼山多幽絕，勝事盈跬步。前者雖登攀，淹留恨晨暮。',132,'御定全唐詩/json/152.json','["杼山多幽絕，勝事盈跬步。前者雖登攀，淹留恨晨暮。", "及茲紆勝引，曾是美無度。欻構三癸亭，實為陸生故。", "高賢能創物，疏鑿皆有趣。不越方丈間，居然雲霄遇。", "巍峨倚修岫，曠望臨古渡。左右苔石攢，低昂桂枝蠹。", "山僧狎猿狖，巢鳥來枳椇。俯視何楷台，傍瞻戴顒路。", "遲回未能下，夕照明村樹。"]'),
('yuding-1','謝陸處士杼山折青桂花見寄之什','顏真卿','唐','御定全唐诗','yuding','','[]','群子遊杼山，山寒桂花白。綠荑含素萼，采折自逋客。',60,'御定全唐詩/json/152.json','["群子遊杼山，山寒桂花白。綠荑含素萼，采折自逋客。", "忽枉岩中詩，芳香潤金石。全高南越蠹，豈謝東堂策。", "會愜名山期，從君恣幽覿。"]'),
('yuding-2','贈裴將軍','顏真卿','唐','御定全唐诗','yuding','','[]','大君制六合，猛將清九垓。戰馬若龍虎，騰淩何壯哉。',108,'御定全唐詩/json/152.json','["大君制六合，猛將清九垓。戰馬若龍虎，騰淩何壯哉。", "將軍臨八荒，烜赫耀英材。劍舞若遊電，隨風縈且回。", "登高望天山，白雲正崔巍。入陣破驕虜，威名雄震雷。", "一射百馬倒，再射萬夫開。匈奴不敢敵，相呼歸去來。", "功成報天子，可以畫麟台。"]'),
('yuding-3','贈僧皎然','顏真卿','唐','御定全唐诗','yuding','','[]','秋意西山多，別岑縈左次。繕亭曆三癸，趾趾鄰什寺。',132,'御定全唐詩/json/152.json','["秋意西山多，別岑縈左次。繕亭曆三癸，趾趾鄰什寺。", "元化隱靈蹤，始君啟高致。誅榛養翹楚，鞭草理芳穗。", "俯砌披水容，逼天掃峰翠。境新耳目換，物遠風塵異。", "倚石忘世情，援雲得真意。嘉林幸勿剪，禪侶欣可庇。", "衛法大臣過，佐游群英萃。龍池護清激，虎節到深邃。", "徒想嵊頂期，於今沒遺記。"]'),
('yuding-4','詠陶淵明','顏真卿','唐','御定全唐诗','yuding','','[]','張良思報韓，龔勝恥事新。狙擊不肯就，舍生悲縉紳。',84,'御定全唐詩/json/152.json','["張良思報韓，龔勝恥事新。狙擊不肯就，舍生悲縉紳。", "嗚呼陶淵明，奕葉為晉臣。自以公相後，每懷宗國屯。", "題詩庚子歲，自謂羲皇人。手持山海經，頭戴漉酒巾。", "興逐孤雲外，心隨還鳥泯。"]'),
('yuding-5','三言擬五雜組二首','顏真卿','唐','御定全唐诗','yuding','','[]','五雜組，繡與錦。往復還，興又寢。不得已，病伏枕。',48,'御定全唐詩/json/152.json','["五雜組，繡與錦。往復還，興又寢。不得已，病伏枕。", "五雜組，甘鹹醋。往復還，烏與兔。不得已，韶光度。"]'),
('yuding-6','使過瑤台寺，有懷圓寂上人','顏真卿','唐','御定全唐诗','yuding','','[]','上人居此寺，不出三十年。萬法元無著，一心唯趣禪。',48,'御定全唐詩/json/152.json','["上人居此寺，不出三十年。萬法元無著，一心唯趣禪。", "忽紆塵外軫，遠訪區中緣。及爾不復見，支提猶岌然。"]'),
('yuding-7','登平望橋下作','顏真卿','唐','御定全唐诗','yuding','','[]','登橋試長望，望極與天平。際海蒹葭色，終朝鳧雁聲。',48,'御定全唐詩/json/152.json','["登橋試長望，望極與天平。際海蒹葭色，終朝鳧雁聲。", "近山猶仿佛，遠水忽微明。更覽諸公作，知高題柱名。"]'),
('yuding-8','刻清遠道士詩，因而繼作','顏真卿','唐','御定全唐诗','yuding','','[]','不到東西寺，於今五十春。朅來從舊賞，林壑宛相親。',144,'御定全唐詩/json/152.json','["不到東西寺，於今五十春。朅來從舊賞，林壑宛相親。", "吳子多藏日，秦王厭勝辰。劍池穿萬仞，磐石坐千人。", "金氣騰為虎，琴台化若神。登壇仰生一，舍宅歎珣瑉。", "中嶺分雙樹，回巒絕四鄰。窺臨江海接，崇飾四時新。", "客有神仙者，于茲雅麗陳。名高清遠峽，文聚鬥牛津。", "跡異心寧間，聲同質豈均。悠然千載後，知我揖光塵。"]'),
('yuding-0','雜詩六首','李華','唐','御定全唐诗','yuding','','[]','黃鐘叩母音，律呂更迴圈。邪氣悖正聲，鄭衛生其間。',420,'御定全唐詩/json/153.json','["黃鐘叩母音，律呂更迴圈。邪氣悖正聲，鄭衛生其間。", "典樂忽涓微，波浪與天渾。嘈嘈鴟梟動，好鳥徒綿蠻。", "王吉歸鄉里，甘心長閉關。", "玄黃與丹青，五氣之正色。聖人端其源，上下皆有則。", "齊侯好紫衣，魏帝婦人飾。女奴厭金翠，傾海未滿臆。", "何忍嚴子陵，羊裘死荊棘。", "甘酸不私人，元和運五行。生人受其用，味正心亦平。", "爪牙相踐傷，日與性命爭。聖人不能絕，鑽燧與炮烹。", "嗜欲乘此熾，百金資一傾。正銷神耗衰，邪勝體充盈。", "顏子有餘樂，瓢中寒水清。", "陰魄淪宇宙，太陽假其明。臣道不敢專，由此見虧盈。", "未聞東菑稼，一氣嘉谷成。上天降寒暑，地利乃可生。", "葛藟附柔木，繁陰蔽曾原。風霜摧枝幹，不復庇本根。", "女蘿依松柏，然後得長存。", "孔光尊董賢，胡廣慚李固。儒風冠天下，而乃敗王度。", "絳侯與博陸，忠朴受遺顧。求名不考實，文弊反成蠹。", "結交得書生，書生鈍且直。爭權複爭利，終不得其力。", "我逢縱橫者，是我牙與翼。相旋如疾風，並命趨紫極。", "奔車得停軌，風火何相逼。仁義豈有常，肝膽反為賊。", "勿嫌書生直，鈍直深可憶。"]'),
('yuding-1','詠史十一首','李華','唐','御定全唐诗','yuding','','[]','昂藏獬豸獸，出自太平年。亂代乃潛伏，縱人為禍愆。',516,'御定全唐詩/json/153.json','["昂藏獬豸獸，出自太平年。亂代乃潛伏，縱人為禍愆。", "嘗聞斷馬劍，每壯朱雲賢。身死名不滅，寒風吹墓田。", "精靈如有在，幽憤滿松煙。", "漢皇修雅樂，乘輿臨太學。三老與五更，天王親割牲。", "一人調風俗，萬國和且平。單于驟款塞，武庫欲銷兵。", "文物此朝盛，君臣何穆清。至今壝壇下，如有簫韶聲。", "巢許在嵩潁，陶唐不得臣。九州尚洗耳，一命安能親。", "綿邈數千祀，丘中誰隱淪。朝遊公卿府，夕是山林人。", "蒲帛揚側陋，薜蘿為縉紳。九重念入夢，三事思降神。", "且設庭中燎，寧窺泉下鱗。", "漢時征百粵，楊僕將樓船。幕府功未立，江湖已騷然。", "島夷非敢亂，政暴地仍偏。得罪因懷璧，防身輒控弦。", "三軍求裂土，萬里詎聞天。魏闕心猶在，旗門首已懸。", "如何得良吏，一為制方圓。", "秦滅漢帝興，南山有遺老。危冠揖萬乘，幸得厭征討。", "當君逐鹿時，臣等已枯槁。寧知市朝變，但覺林泉好。", "高臥三十年，相看成四皓。帝言翁甚善，見顧何不早。", "咸稱太子仁，重義亦尊道。側聞驪姬事，申生不自保。", "暫出商山雲，朅來趨灑掃。東宮成羽翼，楚舞傷懷抱。", "後代無其人，戾園滿秋草。", "日照昆侖上，羽人披羽衣。乘龍駕雲霧，欲往心無違。", "此山在西北，乃是神仙國。靈氣皆自然，求之不可得。", "何為漢武帝，精思遍群山。糜費巨萬計，宮車終不還。", "蒼蒼茂陵樹，足以戒人間。"]'),
('yuding-2','雲母泉詩','李華','唐','御定全唐诗','yuding','','[]','晨登玄石嶺，嶺上寒松聲。朗日風雨霽，高秋天地清。',228,'御定全唐詩/json/153.json','["晨登玄石嶺，嶺上寒松聲。朗日風雨霽，高秋天地清。", "山門開古寺，石竇含純精。洞徹淨金界，夤緣流玉英。", "澤藥滋畦茂，氣染茶甌馨。飲液盡眉壽，餐和皆體平。", "瓊漿駐容發，甘露瑩心靈。岱谷謝巧妙，匡山徒有名。", "願言構蓬蓽，荷鍤引泠泠。訪道出人世，招賢依福庭。", "此心不能已，寤寐見吾兄。曾結潁陽契，窮年無所成。", "東西同放逐，蛇豕尚縱橫。江漢阻攜手，天涯萬里情。", "恩光起憔悴，西上謁承明。秋色變江樹，相思紛以盈。", "猿啼巴丘戍，月上武陵城。共恨川路永，無由會友生。", "雲泉不可忘，何日遂躬耕。"]'),
('yuding-3','寄趙七侍禦','李華','唐','御定全唐诗','yuding','','[]','搖槳曙江流，江清山複重。心愜賞未足，川迥失前峰。',372,'御定全唐詩/json/153.json','["搖槳曙江流，江清山複重。心愜賞未足，川迥失前峰。", "淩灘出極浦，曠若天池通。君陽青嵯峨，開拆混元中。", "九潭魚龍窟，仙成羽人宮。陰奧潛鬼物，精光動煙空。", "玄猿啼深蘢，白鳥戲蔥蒙。飛湍鳴金石，激溜鼓雷風。", "雨濯萬木鮮，霞照千山濃。草閑長餘綠，花靜落幽紅。", "渚煙見晨釣，山月聞夜舂。覆溪窈窕波，涵石淘溶溶。", "丹丘忽聚散，素壁相奔沖。白日破昏靄，靈山出其東。", "勢排昊蒼上，氣壓吳越雄。回頭望雲卿，此恨發吾衷。", "昔日蕭邵游，四人才成童。屬詞慕孔門，入仕希上公。", "緯卿陷非罪，折我昆吾鋒。茂挺獨先覺，拔身渡京虹。", "斯人謝明代，百代墜鵷鴻。世故墜橫流，與君哀路窮。", "相顧無死節，蒙恩逐殊封。天波洗其瑕，朱衣備朝容。", "一別凡十年，豈期複相從。餘生得攜手，遺此兩孱翁。", "群遷失鶯羽，後凋惜長松。衰旅難重別，淒淒滿心胸。", "遇勝悲獨遊，貪奇悵孤逢。禽尚彼何人，胡為束樊籠。", "吾師度門教，投弁躡遐蹤。"]'),
('yuding-4','仙遊寺','李華','唐','御定全唐诗','yuding','','[]','舍事入樵徑，雲木深谷口。萬壑移晦明，千峰轉前後。',144,'御定全唐詩/json/153.json','["舍事入樵徑，雲木深谷口。萬壑移晦明，千峰轉前後。", "嶷然龍潭上，石勢若奔走。開拆秋天光，崩騰夏雷吼。", "靈溪自茲去，紆直互紛糾。聽聲靜複喧，望色無更有。", "冥冥翠微下，高殿映杉柳。滴滴洞穴中，懸泉響相扣。", "昔時秦王女，羽化年代久。日暮松風來，簫聲生左右。", "早窺神仙籙，願結芝朮友。安得羨門方，青囊系吾肘。"]'),
('yuding-5','春遊吟','李華','唐','御定全唐诗','yuding','','[]','初春遍芳甸，千里藹盈矚。美人摘新英，步步玩春綠。',52,'御定全唐詩/json/153.json','["初春遍芳甸，千里藹盈矚。美人摘新英，步步玩春綠。", "所思杳何處，宛在吳江曲。", "可憐不得共芳菲，日暮歸來淚滿衣。"]'),
('yuding-6','長門怨','李華','唐','御定全唐诗','yuding','','[]','弱體鴛鴦薦，啼妝翡翠衾。鴉鳴秋殿曉，人靜禁門深。',48,'御定全唐詩/json/153.json','["弱體鴛鴦薦，啼妝翡翠衾。鴉鳴秋殿曉，人靜禁門深。", "每憶椒房寵，那堪永巷陰。自驚羅帶緩，非復舊來心。"]'),
('yuding-7','奉使朔方，贈郭都護','李華','唐','御定全唐诗','yuding','','[]','絕塞臨光祿，孤營佐貳師。鐵衣山月冷，金鼓朔風悲。',48,'御定全唐詩/json/153.json','["絕塞臨光祿，孤營佐貳師。鐵衣山月冷，金鼓朔風悲。", "都護徵兵日，將軍破虜時。揚鞭玉關道，回首望旌旗。"]'),
('yuding-8','尚書都堂瓦松','李華','唐','御定全唐诗','yuding','','[]','華省秘仙蹤，高堂露瓦松。葉因春後長，花為雨來濃。',72,'御定全唐詩/json/153.json','["華省秘仙蹤，高堂露瓦松。葉因春後長，花為雨來濃。", "影混鴛鴦色，光含翡翠容。天然斯所寄，地勢太無從。", "接棟臨雙闕，連甍近九重。寧知深澗底，霜雪歲兼封。"]'),
('yuding-9','海上生明月','李華','唐','御定全唐诗','yuding','','[]','皎皎秋中月，團團海上生。影開金鏡滿，輪抱玉壺清。',72,'御定全唐詩/json/153.json','["皎皎秋中月，團團海上生。影開金鏡滿，輪抱玉壺清。", "漸出三山岊，將淩一漢橫。素娥嘗藥去，烏鵲繞枝驚。", "照水光偏白，浮雲色最明。此時堯砌下，蓂莢自將榮。"]'),
('yuding-10','晚日湖上寄所思','李華','唐','御定全唐诗','yuding','','[]','與君為近別，不啻遠相思。落日平湖上，看山對此時。',24,'御定全唐詩/json/153.json','["與君為近別，不啻遠相思。落日平湖上，看山對此時。"]'),
('yuding-11','寄從弟','李華','唐','御定全唐诗','yuding','','[]','眼病身亦病，浮生已半空。迢迢千里月，應與惠連同。',24,'御定全唐詩/json/153.json','["眼病身亦病，浮生已半空。迢迢千里月，應與惠連同。"]'),
('yuding-12','奉寄彭城公','李華','唐','御定全唐诗','yuding','','[]','公子三千客，人人願報恩。應憐抱關者，貧病老夷門。',24,'御定全唐詩/json/153.json','["公子三千客，人人願報恩。應憐抱關者，貧病老夷門。"]'),
('yuding-13','春行寄興','李華','唐','御定全唐诗','yuding','','[]','宜陽城下草萋萋，澗水東流複向西。',32,'御定全唐詩/json/153.json','["宜陽城下草萋萋，澗水東流複向西。", "芳樹無人花自落，春山一路鳥空啼。"]'),
('yuding-0','江有楓一篇十章','蕭穎士','唐','御定全唐诗','yuding','','[]','江有楓，其葉濛濛。我友自東，于以遊從。',243,'御定全唐詩/json/154.json','["江有楓，其葉濛濛。我友自東，于以遊從。", "山有槭，其葉漠漠。我友徂北，於以休息。", "想彼槭矣，亦類其楓。矧伊懷人，而忘其東。", "東可遊矣，會之丘矣。于山于水，于廟於寺，", "粵東可居，彼吳之墟。有田有庭，有朋有書，", "我朋在矣，彼陸之子。如松如杞，淑問不已。", "我友于征，彼鄭之子。如琇如英，德音孔明。", "我思震澤，菱芡幕幕。寤寐如覿，我思剡溪。", "杉筱萋萋，寤寐無迷。", "有鳥有鳥，粵鷗與鷺。浮湍戲渚，皓然潔素，", "此懼惟何，懼寘于羅。彼驕者子，讒言孔多。", "我聞先師，體命委和。公伯之愬，則如予何。", "悵然山河，惟以嘯歌，其憂也哉。"]'),
('yuding-1','菊榮一篇五章','蕭穎士','唐','御定全唐诗','yuding','','[]','采采者菊，芬其榮斯。紫英黃萼，照灼丹墀。愷悌君子，',125,'御定全唐詩/json/154.json','["采采者菊，芬其榮斯。紫英黃萼，照灼丹墀。愷悌君子，", "采采者菊，於邑之城。舊根新莖，布葉垂英。彼美淑人，", "采采者菊，於邦之府。陰槐翳柳，邇楹近宇。彼勞者子，", "采采者菊，於賓之館。既低其枝，又弱其幹。有斐君子，", "歲方晏矣，霜露殘促。誰其榮斯，有英者菊。豈微春華，"]'),
('yuding-2','涼雨一章','蕭穎士','唐','御定全唐诗','yuding','','[]','習習涼風，泠泠浮飆。君子樂胥，於其賓僚。有女斯夭，',25,'御定全唐詩/json/154.json','["習習涼風，泠泠浮飆。君子樂胥，於其賓僚。有女斯夭，"]'),
('yuding-3','有竹一篇七章','蕭穎士','唐','御定全唐诗','yuding','','[]','有竹斯竿，於閣之前。君子秉心，惟其貞堅兮。',162,'御定全唐詩/json/154.json','["有竹斯竿，於閣之前。君子秉心，惟其貞堅兮。", "有竿斯竹，於閣之側。君子秉操，惟其正直兮。", "彼蔚者竹，蕭其森矣。有開者合，宛其深矣。", "回簷幽砌，如翼如齒。", "冬之宵，霰雪斯瀌。我有金爐，熹其以歊。", "夏之日，炎景斯鬱。我有珍簟，淒其以栗。", "彼紛者務，體其豫矣。有旨者酒，歡其且矣。", "友僚萃止，跗萼載韡。", "彼美公之姓兮，那歟應積慶兮，期子惟去之柄兮。"]'),
('yuding-4','江有歸舟三章','蕭穎士','唐','御定全唐诗','yuding','','[]','江有歸舟，亦亂其流。之子言旋，嘉名孔修。',90,'御定全唐詩/json/154.json','["江有歸舟，亦亂其流。之子言旋，嘉名孔修。", "揚于王庭，允焯其休。", "舟既歸止，人亦榮止。兄矣弟矣，孝斯踐矣。", "稱觴燕喜，于岵於屺。", "彼遊惟帆，匪風不揚。有彬伊父，匪學不彰。", "予其懷而，勉爾無忘。"]'),
('yuding-5','過河濱，和文學張志尹','蕭穎士','唐','御定全唐诗','yuding','','[]','隆古日以遠，舉世喪其淳。慷慨懷黃虞，化理何由臻。',120,'御定全唐詩/json/154.json','["隆古日以遠，舉世喪其淳。慷慨懷黃虞，化理何由臻。", "步出城西門，裴回見河濱。當其側陋時，河水清且潾。", "滄桑一以變，莽然翳荊榛。至化無苦窳，宇宙將陶甄。", "太息感悲泉，人往跡未湮。瑟瑟寒原暮，冷風吹衣巾。", "顧我譾劣質，希聖杳無因。且盡登臨意，鬥酒歡相親。"]'),
('yuding-6','舟中遇陸棣兄西歸數日得廣陵二三子書知遲晚次沙墊西岸作','蕭穎士','唐','御定全唐诗','yuding','','[]','林烏遙岸鳴，早知東方曙。波上風雨歇，舟人叫將去。',168,'御定全唐詩/json/154.json','["林烏遙岸鳴，早知東方曙。波上風雨歇，舟人叫將去。", "蒼蒼前洲日，的的回沙鷺。水氣清曉陰，灘聲隱川霧。", "舊山勞魂想，憶人阻洄溯。信宿千里餘，佳期曷由遇。", "前程入楚鄉，弭棹問維揚。但見土音異，始知程路長。", "寥寥晚空靜，漫漫風淮涼。雲景信可美，風潮殊未央。", "故人江皋上，永日念容光。中路枉尺書，謂餘瓊樹芳。", "深期結晤語，竟夕恨相望。冀願崇朝霽，吾其一葦航。"]'),
('yuding-7','重陽日陪元魯山德秀登北城，矚對新霽，因以贈別','蕭穎士','唐','御定全唐诗','yuding','','[]','山縣繞古堞，悠悠快登望。雨餘秋天高，目盡無隱狀。',168,'御定全唐詩/json/154.json','["山縣繞古堞，悠悠快登望。雨餘秋天高，目盡無隱狀。", "綿連滍川回，杳渺鴉路深。彭澤興不淺，臨風動歸心。", "賴茲琴堂暇，傲睨傾菊酒。人和歲已登，從政複何有。", "遠山十裏碧，一道銜長雲。青霞半落日，混合疑晴曛。", "漸聞驚棲羽，坐歎清夜月。中歡愴有違，行子念明發。", "僅能泯寵辱，未免傷別離。江湖不可忘，風雨勞相思。", "明時當盛才，短伎安所設。何日謝百里，從君漢之澨。"]'),
('yuding-8','留別二三子，得韻字','蕭穎士','唐','御定全唐诗','yuding','','[]','二紀尚雌伏，徒然忝先進。英英爾眾賢，名實鬱雙振。',48,'御定全唐詩/json/154.json','["二紀尚雌伏，徒然忝先進。英英爾眾賢，名實鬱雙振。", "殘春惜將別，清洛行不近。相與愛後時，無令孤逸韻。"]'),
('yuding-9','仰答韋司業垂訪五首','蕭穎士','唐','御定全唐诗','yuding','','[]','呦呦食蘋鹿，常飲清泠川。但悅豐草美，寧知牢饌鮮。',396,'御定全唐詩/json/154.json','["呦呦食蘋鹿，常飲清泠川。但悅豐草美，寧知牢饌鮮。", "主人有幽意，將以充林泉。羅網倖免傷，蒙君複羈牽。", "高堂列眾賓，廣座鳴清弦。俯仰轉驚惕，裴回獨憂煎。", "緬懷雲岩路，欲往無由緣。物各有所好，違之傷自然。", "神龜在南國，緬邈湘川陰。游止蓮葉上，歲時嘉樹林。", "毒蟲且不近，斤斧何由尋。錯落負奇文，熒煌耀丹金。", "江山萬里餘，淮海阻且深。獨保貞素質，不為寒暑侵。", "一逢盛明代，應見通靈心。", "晉代有儒臣，當年富詞藻。立言寄青史，將以贊王道。", "遼落緬歲時，辛勤曆江島。且言風波倦，探涉豈為寶。", "不遇庾征西，雲誰展懷抱。士貧乏知己，安得成所好。", "彭陽昔遊說，願謁南郢都。王果尚未達，況從夷節謨。", "豈知晉叔向，無罪嬰囚拘。臨難俟解紛，獨知祁大夫。", "舉讎且不棄，何必論親疏。夫子覺者也，其能遺我乎。", "關西一公子，年貌獨青春。被褐來上京，翳然聲未振。", "中郎何為者，倒屣驚座賓。詞賦豈不佳，盛名亦相因。", "為君奏此曲，此曲多苦辛。千載不可誣，孰言今無人。"]'),
('yuding-10','答鄒象先','蕭穎士','唐','御定全唐诗','yuding','','[]','桂枝常共擢，茅茨冀同薦。一命何阻修，載馳各川縣。',48,'御定全唐詩/json/154.json','["桂枝常共擢，茅茨冀同薦。一命何阻修，載馳各川縣。", "壯圖悲歲月，明代恥貧賤。回首無津梁，只令二毛變。"]'),
('yuding-11','蒙山作','蕭穎士','唐','御定全唐诗','yuding','','[]','東蒙鎮海沂，合遝餘百里。清秋淨氛靄，崖崿隱天起。',180,'御定全唐詩/json/154.json','["東蒙鎮海沂，合遝餘百里。清秋淨氛靄，崖崿隱天起。", "于役勞往還，息徒暫攀躋。將窮絕跡處，偶得冥心理。", "雲氣雜虹霓，松聲亂風水。微明綠林際，杳窱丹洞裏。", "仙鳥時可聞，羽人邈難視。此焉多深邃，賢達昔所止。", "子尚捐俗紛，季隨躡遐軌。蘊真道彌曠，懷古情未已。", "白鹿凡幾游，黃精複奚似。顧予尚牽纏，家業重書史。", "少學務從師，壯年貴趨仕。方馳桂林譽，未暇桃源美。", "歲暮期再尋，幽哉羨門子。"]'),
('yuding-12','早春過七嶺，寄題硤石裴丞廳壁','蕭穎士','唐','御定全唐诗','yuding','','[]','出硤寄趣少，晚行偏憶君。依然向來處，官路溪邊雲。',72,'御定全唐詩/json/154.json','["出硤寄趣少，晚行偏憶君。依然向來處，官路溪邊雲。", "茲路豈不劇，能無俗累紛。槐陰永未合，泉聲細猶聞。", "彌歎春罷酒，牽卑從此分。登高望城入，斜影半風熏。"]'),
('yuding-13','送張翬下第歸江東','蕭穎士','唐','御定全唐诗','yuding','','[]','俱飛仍失路，彩服邇清波。地積東南美，朝遺甲乙科。',48,'御定全唐詩/json/154.json','["俱飛仍失路，彩服邇清波。地積東南美，朝遺甲乙科。", "客愁千里別，春色五湖多。明日舊山去，其如相望何。"]'),
('yuding-14','越江秋曙','蕭穎士','唐','御定全唐诗','yuding','','[]','扁舟東路遠，曉月下江濆。瀲灩信潮上，蒼茫孤嶼分。',72,'御定全唐詩/json/154.json','["扁舟東路遠，曉月下江濆。瀲灩信潮上，蒼茫孤嶼分。", "林聲寒動葉，水氣曙連雲。暾日浪中出，榜歌天際聞。", "伯鸞常去國，安道惜離群。延首剡溪近，詠言懷數君。"]'),
('yuding-15','山莊月夜作','蕭穎士','唐','御定全唐诗','yuding','','[]','獻書嗟棄置，疲拙歸田園。且事計然策，將符公冶言。',96,'御定全唐詩/json/154.json','["獻書嗟棄置，疲拙歸田園。且事計然策，將符公冶言。", "桑榆清暮景，雞犬應遙村。蠶罷裏閭晏，麥秋田野喧。", "澗聲連枕簟，峰勢入階軒。未奏東山妓，先傾北海尊。", "隴瓜香早熟，庭果落初繁。更愜野人意，農談朝竟昏。"]'),
('yuding-0','古意','崔曙','唐','御定全唐诗','yuding','','[]','綠筍總成竹，紅花亦成子。能當此時好，獨自幽閨裏。',36,'御定全唐詩/json/155.json','["綠筍總成竹，紅花亦成子。能當此時好，獨自幽閨裏。", "夜夜苦更長，愁來不如死。"]'),
('yuding-1','宿大通和尚塔，敬贈如上人，兼呈常、孫二山人','崔曙','唐','御定全唐诗','yuding','','[]','支公已寂滅，影塔山上古。更有真僧來，道場救諸苦。',108,'御定全唐詩/json/155.json','["支公已寂滅，影塔山上古。更有真僧來，道場救諸苦。", "一承微妙法，寓宿清淨土。身心能自觀，色相了無取。", "森森松映月，漠漠雲近戶。嶺外飛電明，夜來前山雨。", "然燈見棲鴿，作禮聞信鼓。曉霽南軒開，秋華淨天宇。", "願言出世塵，謝爾申及甫。"]'),
('yuding-2','送薛據之宋州','崔曙','唐','御定全唐诗','yuding','','[]','無媒嗟失路，有道亦乘流。客處不堪別，異鄉應共愁。',72,'御定全唐詩/json/155.json','["無媒嗟失路，有道亦乘流。客處不堪別，異鄉應共愁。", "我生早孤賤，淪落居此州。風土至今憶，山河皆昔遊。", "一從文章事，兩京春複秋。君去問相識，幾人今白頭。"]'),
('yuding-3','山下晚晴','崔曙','唐','御定全唐诗','yuding','','[]','寥寥遠天淨，溪路何空蒙。斜光照疏雨，秋氣生白虹。',48,'御定全唐詩/json/155.json','["寥寥遠天淨，溪路何空蒙。斜光照疏雨，秋氣生白虹。", "雲盡山色暝，蕭條西北風。故林歸宿處，一葉下梧桐。"]'),
('yuding-4','潁陽東溪懷古','崔曙','唐','御定全唐诗','yuding','','[]','靈溪氛霧歇，皎鏡清心顏。空色不映水，秋聲多在山。',72,'御定全唐詩/json/155.json','["靈溪氛霧歇，皎鏡清心顏。空色不映水，秋聲多在山。", "世人久疏曠，萬物皆自閑。白鷺寒更浴，孤雲晴未還。", "昔時讓王者，此地閉玄關。無以躡高步，淒涼岑壑間。"]'),
('yuding-5','早發交崖山還太室作','崔曙','唐','御定全唐诗','yuding','','[]','東林氣微白，寒鳥急高翔。吾亦自茲去，北山歸草堂。',84,'御定全唐詩/json/155.json','["東林氣微白，寒鳥急高翔。吾亦自茲去，北山歸草堂。", "仲冬正三五，日月遙相望。蕭蕭過潁上，曨曨辨少陽。", "川冰生積雪，野火出枯桑。獨往路難盡，窮陰人易傷。", "傷此無衣客，如何蒙雪霜。"]'),
('yuding-6','奉試明堂火珠','崔曙','唐','御定全唐诗','yuding','','[]','正位開重屋，淩空出火珠。夜來雙月滿，曙後一星孤。',48,'御定全唐詩/json/155.json','["正位開重屋，淩空出火珠。夜來雙月滿，曙後一星孤。", "天淨光難滅，雲生望欲無。遙知太平代，國寶在名都。"]'),
('yuding-7','途中曉發','崔曙','唐','御定全唐诗','yuding','','[]','曉霽長風裏，勞歌赴遠期。雲輕歸海疾，月滿下山遲。',48,'御定全唐詩/json/155.json','["曉霽長風裏，勞歌赴遠期。雲輕歸海疾，月滿下山遲。", "旅望因高盡，鄉心遇物悲。故林遙不見，況在落花時。"]'),
('yuding-8','緱山廟','崔曙','唐','御定全唐诗','yuding','','[]','遺廟宿陰陰，孤峰映綠林。步隨仙路遠，意入道門深。',48,'御定全唐詩/json/155.json','["遺廟宿陰陰，孤峰映綠林。步隨仙路遠，意入道門深。", "澗水流年月，山雲變古今。只聞風竹裏，猶有鳳笙音。"]'),
('yuding-9','同諸公謁啟母祠','崔曙','唐','御定全唐诗','yuding','','[]','閟宮淩紫微，芳草閉閑扉。帝子複何在，王孫游不歸。',48,'御定全唐詩/json/155.json','["閟宮淩紫微，芳草閉閑扉。帝子複何在，王孫游不歸。", "春風鳴玉佩，暮雨拂靈衣。豈但湘江口，能令懷二妃。"]'),
('yuding-10','九日登望仙台，呈劉明府容','崔曙','唐','御定全唐诗','yuding','','[]','漢文皇帝有高臺，此日登臨曙色開。三晉雲山皆北向，',40,'御定全唐詩/json/155.json','["漢文皇帝有高臺，此日登臨曙色開。三晉雲山皆北向，", "且欲近尋彭澤宰，陶然共醉菊花杯。"]'),
('yuding-11','奉酬中書相公至日圓丘攝事合於中書後閣宿齋移止于集賢院敘懷見寄之作','崔曙','唐','御定全唐诗','yuding','','[]','典籍開書府，恩榮避鼎司。郊丘資有事，齋戒守無為。',72,'御定全唐詩/json/155.json','["典籍開書府，恩榮避鼎司。郊丘資有事，齋戒守無為。", "宿霧蒙瓊樹，餘香覆玉墀。進經逢乙夜，展禮值明時。", "勳共山河列，名同竹帛垂。年年佐堯舜，相與致雍熙。"]'),
('yuding-12','登水門樓，見亡友張貞期題望黃河詩，因以感興','崔曙','唐','御定全唐诗','yuding','','[]','吾友東南美，昔聞登此樓。人隨川上逝，書向壁中留。',96,'御定全唐詩/json/155.json','["吾友東南美，昔聞登此樓。人隨川上逝，書向壁中留。", "嚴子好真隱，謝公耽遠遊。清風初作頌，暇日複銷憂。", "時與文字古，跡將山水幽。已孤蒼生望，空見黃河流。", "流落年將晚，悲涼物已秋。天高不可問，掩泣赴行舟。"]'),
('yuding-13','對雨送鄭陵','崔曙','唐','御定全唐诗','yuding','','[]','別愁複經雨，別淚還如霰。寄心海上雲，千里常相見。',24,'御定全唐詩/json/155.json','["別愁複經雨，別淚還如霰。寄心海上雲，千里常相見。"]'),
('yuding-14','嵩山尋馮煉師不遇','崔曙','唐','御定全唐诗','yuding','','[]','青溪訪道淩煙曙，王子仙成已飛去。',32,'御定全唐詩/json/155.json','["青溪訪道淩煙曙，王子仙成已飛去。", "更值空山雷雨時，雲林薄暮歸何處。"]'),
('yuding-0','贈唐祖二子','王翰','唐','御定全唐诗','yuding','','[]','鴻飛遵枉渚，鹿鳴思故群。物情尚勞愛，況乃予別君。',72,'御定全唐詩/json/156.json','["鴻飛遵枉渚，鹿鳴思故群。物情尚勞愛，況乃予別君。", "別時花始發，別後蘭再熏。瑤觴滋白露，寶瑟凝涼氛。", "裴徊北林月，悵望南山雲。雲月渺千里，音徽不可聞。"]'),
('yuding-1','飛燕篇','王翰','唐','御定全唐诗','yuding','','[]','孝成皇帝本嬌奢，行幸平陽公主家。可憐女兒三五許，',120,'御定全唐詩/json/156.json','["孝成皇帝本嬌奢，行幸平陽公主家。可憐女兒三五許，", "君心見賞不見忘，姊妹雙飛入紫房。紫房彩女不得見，", "日夕風傳歌舞聲，只擾長信憂人情。長信憂人氣欲絕，", "明月薄蝕陽精昏，嬌妒傾城惑至尊。已見白虹橫紫極，", "明明天子咸戒之，赫赫宗周褒姒滅。古來賢聖歎狐裘，"]'),
('yuding-2','飲馬長城窟行','王翰','唐','御定全唐诗','yuding','','[]','長安少年無遠圖，一生惟羨執金吾。麒麟前殿拜天子，',120,'御定全唐詩/json/156.json','["長安少年無遠圖，一生惟羨執金吾。麒麟前殿拜天子，", "遙聞鼙鼓動地來，傳道單于夜猶戰。此時顧恩甯顧身，", "歸來飲馬長城窟，長城道傍多白骨。問之耆老何代人，", "無罪見誅功不賞，孤魂流落此城邊。當昔秦王按劍起，", "秦王築城何太愚，天實亡秦非北胡。一朝禍起蕭牆內，"]'),
('yuding-3','賦得明星玉女壇，送廉察尉華陰','王翰','唐','御定全唐诗','yuding','','[]','洪河之南曰秦鎮，發地削成五千仞。三峰離地皆倚天，',112,'御定全唐詩/json/156.json','["洪河之南曰秦鎮，發地削成五千仞。三峰離地皆倚天，", "三十六梯入河漢，樵人往往見蛾眉。蛾眉嬋娟又宜笑，", "含情遲佇惜韶年，願侍君邊複中旋。江妃玉佩留為念，", "遙見明星是妾家，風飄雪散不知處。故人家在西長安，", "欲求玉女長生法，日夜燒香應自還。"]'),
('yuding-4','春女行','王翰','唐','御定全唐诗','yuding','','[]','紫台穹跨連綠波，紅軒鉿匝垂纖羅。中有一人金作面，',48,'御定全唐詩/json/156.json','["紫台穹跨連綠波，紅軒鉿匝垂纖羅。中有一人金作面，", "羅袖嬋娟似無力，行拾落花比容色。落花一度無再春，"]'),
('yuding-5','古蛾眉怨','王翰','唐','御定全唐诗','yuding','','[]','君不見宜春苑中九華殿，飛閣連連直如發。',179,'御定全唐詩/json/156.json','["君不見宜春苑中九華殿，飛閣連連直如發。", "白日全含朱鳥窗，流雲半入蒼龍闕。宮中彩女夜無事，", "忽聞天子憶蛾眉，寶鳳銜花揲兩螭。傳聲走馬開金屋，", "燈前含笑更羅衣，帳裏承恩薦瑤枕。不意君心半路回，", "欲向人間種桃實，先從海底覓蓬萊。蓬萊可求不可上，", "王母嫣然感君意，雲車羽旆欲相迎。飛廉觀前空怨慕，", "宮車晚出向南山，仙衛逶迤去不還。朝晡泣對麒麟樹，", "情知白日不可私，一死一生何足算。"]'),
('yuding-6','子夜春歌','王翰','唐','御定全唐诗','yuding','','[]','春氣滿林香，春遊不可忘。落花吹欲盡，垂柳折還長。',48,'御定全唐詩/json/156.json','["春氣滿林香，春遊不可忘。落花吹欲盡，垂柳折還長。", "桑女淮南曲，金鞍塞北裝。行行小垂手，日暮渭川陽。"]'),
('yuding-7','奉和聖制同二相已下群官樂遊園宴','王翰','唐','御定全唐诗','yuding','','[]','未極人心暢，如何帝道明。仍嫌酺宴促，複寵樂遊行。',72,'御定全唐詩/json/156.json','["未極人心暢，如何帝道明。仍嫌酺宴促，複寵樂遊行。", "陸海披珍藏，天河直鬥城。四關青靄合，數處白雲生。", "飪餗調元氣，歌鐘溢雅聲。空慚堯舜日，至德杳難名。"]'),
('yuding-8','奉和聖制送張說上集賢學士賜宴，得筵字','王翰','唐','御定全唐诗','yuding','','[]','東堂起集賢，貴得從神仙。首命臺階老，將崇禦府員。',72,'御定全唐詩/json/156.json','["東堂起集賢，貴得從神仙。首命臺階老，將崇禦府員。", "送人鏘玉佩，中使拂瓊筵。和樂熏風解，湛恩時雨連。", "長材成磊落，短翮強翩翾。徒仰蓬萊地，何階不讓緣。"]'),
('yuding-9','奉和聖制送張尚書巡邊','王翰','唐','御定全唐诗','yuding','','[]','紫綬尚書印，朱輧丞相車。登朝身許國，出閫將辭家。',120,'御定全唐詩/json/156.json','["紫綬尚書印，朱輧丞相車。登朝身許國，出閫將辭家。", "不憚炎蒸苦，親嘗走集賒。選徒軍有政，誓卒爾無嘩。", "帝樂風初起，王城日半斜。寵行流聖作，寅餞照台華。", "騎曆河南樹，旌搖塞北沙。榮懷應盡服，嚴殺已先加。", "業峻靈祇保，功成道路嗟。寧如鑿空使，遠致石榴花。"]'),
('yuding-10','涼州詞二首','王翰','唐','御定全唐诗','yuding','','[]','蒲萄美酒夜光杯，欲飲琵琶馬上催。',64,'御定全唐詩/json/156.json','["蒲萄美酒夜光杯，欲飲琵琶馬上催。", "醉臥沙場君莫笑，古來征戰幾人回。", "秦中花鳥已應闌，塞外風沙猶自寒。", "夜聽胡笳折楊柳，教人意氣憶長安。"]'),
('yuding-11','春日歸思','王翰','唐','御定全唐诗','yuding','','[]','楊柳青青杏發花，年光誤客轉思家。',32,'御定全唐詩/json/156.json','["楊柳青青杏發花，年光誤客轉思家。", "不知湖上菱歌女，幾個春舟在若耶。"]'),
('yuding-12','觀蠻童為伎之作','王翰','唐','御定全唐诗','yuding','','[]','長裙錦帶還留客，廣額青娥亦效顰。',32,'御定全唐詩/json/156.json','["長裙錦帶還留客，廣額青娥亦效顰。", "共惜不成金穀妓，虛令看殺玉車人。"]'),
('yuding-0','古別離','孟雲卿','唐','御定全唐诗','yuding','','[]','朝日上高臺，離人怨秋草。但見萬里天，不見萬里道。',108,'御定全唐詩/json/157.json','["朝日上高臺，離人怨秋草。但見萬里天，不見萬里道。", "君行本迢遠，苦樂良難保。宿昔夢同衾，憂心常傾倒。", "含酸欲誰訴，輾轉傷懷抱。結髮年已遲，征行去何早。", "寒暄有時謝，憔悴難再好。人皆算年壽，死者何曾老。", "少壯無見期，水深風浩浩。"]'),
('yuding-1','今別離','孟雲卿','唐','御定全唐诗','yuding','','[]','結髮生別離，相思複相保。如何日已久，五變庭中草。',96,'御定全唐詩/json/157.json','["結髮生別離，相思複相保。如何日已久，五變庭中草。", "渺渺大海途，悠悠吳江島。但恐不出門，出門無遠道。", "遠道行既難，家貧衣複單。嚴風吹積雪，晨起鼻何酸。", "人生各有志，豈不懷所安。分明天上日，生死願同歡。"]'),
('yuding-2','悲哉行','孟雲卿','唐','御定全唐诗','yuding','','[]','孤兒去慈親，遠客喪主人。莫吟苦辛曲，此曲誰忍聞。',84,'御定全唐詩/json/157.json','["孤兒去慈親，遠客喪主人。莫吟苦辛曲，此曲誰忍聞。", "可聞不可說，去去無期別。行人念前程，不待參辰沒。", "朝亦常苦饑，暮亦常苦饑。飄飄萬餘裏，貧賤多是非。", "少年莫遠遊，遠遊多不歸。"]'),
('yuding-3','行行且遊獵篇','孟雲卿','唐','御定全唐诗','yuding','','[]','少年多武力，勇氣冠幽州。何以縱心賞，馬啼春草頭。',96,'御定全唐詩/json/157.json','["少年多武力，勇氣冠幽州。何以縱心賞，馬啼春草頭。", "遲遲平原上，狐兔奔林丘。猛虎忽前逝，俊鷹連下鞲。", "俯身逐南北，輕捷固難儔。所發無不中，失之如我讎。", "豈唯務馳騁，猗爾暴田疇。殘殺非不痛，古來良有由。"]'),
('yuding-4','古挽歌','孟雲卿','唐','御定全唐诗','yuding','','[]','草草閭巷喧，塗車儼成位。冥冥何所須，盡我生人意。',96,'御定全唐詩/json/157.json','["草草閭巷喧，塗車儼成位。冥冥何所須，盡我生人意。", "北邙路非遠，此別終天地。臨穴頻撫棺，至哀反無淚。", "爾形未衰老，爾息才童稚。骨肉安可離，皇天若容易。", "房帷即靈帳，庭宇為哀次。薤露歌若斯，人生盡如寄。"]'),
('yuding-5','放歌行','孟雲卿','唐','御定全唐诗','yuding','','[]','吾觀天地圖，世界亦可小。落落大海中，飄浮數洲島。',96,'御定全唐詩/json/157.json','["吾觀天地圖，世界亦可小。落落大海中，飄浮數洲島。", "賢愚與蟻虱，一種同草草。地脈日夜流，天衣有時掃。", "東山謁居士，了我生死道。目見難噬臍，心通可親腦。", "軒皇竟磨滅，周孔亦衰老。永謝當時人，吾將寶非寶。"]'),
('yuding-6','傷懷贈故人','孟雲卿','唐','御定全唐诗','yuding','','[]','稍稍晨鳥翔，淅淅草上霜。人生早罹苦，壽命恐不長。',108,'御定全唐詩/json/157.json','["稍稍晨鳥翔，淅淅草上霜。人生早罹苦，壽命恐不長。", "二十學已成，三十名不彰。豈無同門友，貴賤易中腸。", "驅馬行萬里，悠悠過帝鄉。幸因弦歌末，得上君子堂。", "眾樂互喧奏，獨子備笙簧。坐中無知音，安得神揚揚。", "願因高風起，上感白日光。"]'),
('yuding-7','鄴城懷古','孟雲卿','唐','御定全唐诗','yuding','','[]','朝發淇水南，將尋北燕路。魏家舊城闕，寥落無人住。',144,'御定全唐詩/json/157.json','["朝發淇水南，將尋北燕路。魏家舊城闕，寥落無人住。", "伊昔天地屯，曹公獨中據。群臣將北面，白日忽西暮。", "三台竟寂寞，萬事良難固。雄圖安在哉，衰草沾霜露。", "崔嵬長河北，尚見應劉墓。古樹藏龍蛇，荒茅伏狐兔。", "永懷故池館，數子連章句。逸興驅山河，雄詞變雲霧。", "我行睹遺跡，精爽如可遇。鬥酒將酹君，悲風白楊樹。"]'),
('yuding-8','傷情','孟雲卿','唐','御定全唐诗','yuding','','[]','為長心易憂，早孤意常傷。出門先躊躇，入戶亦彷徨。',108,'御定全唐詩/json/157.json','["為長心易憂，早孤意常傷。出門先躊躇，入戶亦彷徨。", "此生一何苦，前事安可忘。兄弟先我沒，孤幼盈我傍。", "舊居近東南，河水新為梁。松柏今在茲，安忍思故鄉。", "四時與日月，萬物各有常。秋風已一起，草木無不霜。", "行行當自勉，不忍再思量。"]'),
('yuding-9','傷時二首','孟雲卿','唐','御定全唐诗','yuding','','[]','徘回宋郊上，不睹平生親。獨立正傷心，悲風來孟津。',108,'御定全唐詩/json/157.json','["徘回宋郊上，不睹平生親。獨立正傷心，悲風來孟津。", "大方載群物，先死有常倫。虎豹不相食，哀哉人食人。", "豈伊逢世運，天道亮云云。", "太空流素月，三五何明明。光耀侵白日，賢愚迷至精。", "四時更變化，天道有虧盈。常恐今夜沒，須臾還複生。"]'),
('yuding-10','田園觀雨兼晴後作','孟雲卿','唐','御定全唐诗','yuding','','[]','貧賤少情欲，借荒種南陂。我非老農圃，安得良土宜。',96,'御定全唐詩/json/157.json','["貧賤少情欲，借荒種南陂。我非老農圃，安得良土宜。", "秋成不廉儉，歲餘多餒饑。顧視倉廩間，有糧不成炊。", "晨登南園上，暮歇清蟬悲。早苗既芃芃，晚田尚離離。", "五行孰堪廢，萬物當及時。賢哉數夫子，開翅慎勿遲。"]'),
('yuding-11','汴河阻風','孟雲卿','唐','御定全唐诗','yuding','','[]','清晨自梁宋，掛席之楚荊。出浦風漸惡，傍灘舟欲橫。',96,'御定全唐詩/json/157.json','["清晨自梁宋，掛席之楚荊。出浦風漸惡，傍灘舟欲橫。", "大河噴東注，群動皆窅冥。白霧魚龍氣，黑雲牛馬形。", "蒼茫迷所適，危安懼暫寧。信此天地內，孰為身命輕。", "丈夫苟未達，所向須存誠。前路舍舟去，東南仍曉晴。"]'),
('yuding-12','行路難','孟雲卿','唐','御定全唐诗','yuding','','[]','君不見高山萬仞連蒼旻，天長地久成埃塵。',72,'御定全唐詩/json/157.json','["君不見高山萬仞連蒼旻，天長地久成埃塵。", "君不見長松百尺多勁節，狂風暴雨終摧折。", "古今何世無聖賢，吾愛伯陽真乃天。金堂玉闕朝群仙，", "行路難，艱險莫踟躕。"]'),
('yuding-13','途中寄友人','孟雲卿','唐','御定全唐诗','yuding','','[]','昔時聞遠路，謂是等閒行。及到求人地，始知為客情。',48,'御定全唐詩/json/157.json','["昔時聞遠路，謂是等閒行。及到求人地，始知為客情。", "事將公道背，塵繞馬蹄生。倘使長如此，便堪休去程。"]'),
('yuding-14','寒食','孟雲卿','唐','御定全唐诗','yuding','','[]','二月江南花滿枝，他鄉寒食遠堪悲。',32,'御定全唐詩/json/157.json','["二月江南花滿枝，他鄉寒食遠堪悲。", "貧居往往無煙火，不獨明朝為子推。"]'),
('yuding-15','新安江上寄處士','孟雲卿','唐','御定全唐诗','yuding','','[]','深潭與淺灘，萬轉出新安。人遠禽魚靜，山空水木寒。',48,'御定全唐詩/json/157.json','["深潭與淺灘，萬轉出新安。人遠禽魚靜，山空水木寒。", "嘯起青蘋末，吟矚白雲端。即事遂幽賞，何必掛儒冠。"]'),
('yuding-16','句','孟雲卿','唐','御定全唐诗','yuding','','[]','群物歸大化，六龍頹西荒。',24,'御定全唐詩/json/157.json','["群物歸大化，六龍頹西荒。", "安知浮雲外，日月不運行。"]');
